-- Poems batch 325
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('79e1ac6a-e430-4548-900f-030d6f20a530','老兒挈幼小將及鄧因寄君時弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','莫言法法與塵塵，祇論而今見在身。',64,'全唐诗/poet.song.51000.json','["莫言法法與塵塵，祇論而今見在身。", "婆子臺山能護物，廝兒臨濟最疑人。", "阿那含果多生葉，優鉢羅花別樣春。", "須認鐵牛樓上語，一回幾看一回新。"]'),
('1d04198c-ad1a-4f62-bcb3-61a96c6ed029','老兒挈幼小將及鄧因寄君時弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','長年騎馬走風塵，擾擾猶知夢幻身。',64,'全唐诗/poet.song.51000.json','["長年騎馬走風塵，擾擾猶知夢幻身。", "野柳最憐青綬客，山桃莫笑白髭人。", "照溪七里亭邊晚，近郭百花洲上春。", "捉麈即從君道舊，浮蛆更許我嘗新。"]'),
('35d20868-36d6-4cce-85e9-3c5b286d4b5b','和范學士  其一','彭汝礪','宋','宋诗','song-poetry','','[]','紅塵投老倦征鞍，夢寐清規祇厚顔。',64,'全唐诗/poet.song.51000.json','["紅塵投老倦征鞍，夢寐清規祇厚顔。", "論德每疑觀大水，言詩曾賦仰高山。", "退之自處軻雄後，甫也當居揚馬間。", "知止舊風衰久矣，只今須合爲公還。"]'),
('ea7dd01b-5d75-4bc7-b6e5-402bfc0ff4fa','和范學士  其二','彭汝礪','宋','宋诗','song-poetry','','[]','酒榼棋枰足燕閑，市朝愁復抗塵顔。',64,'全唐诗/poet.song.51000.json','["酒榼棋枰足燕閑，市朝愁復抗塵顔。", "曾非學道隨東魯，可怕移文累北山。", "花燭園林春半際，烟波亭榭水中間。", "籃輿想見公游處，潁水何時聽我還。"]'),
('df59eba5-fb63-47ab-a404-3174990270ed','寄致政侍郎','彭汝礪','宋','宋诗','song-poetry','','[]','孔門弟子數三千，用舍行藏獨與顔。',64,'全唐诗/poet.song.51000.json','["孔門弟子數三千，用舍行藏獨與顔。", "委曲百川終至海，辛勤一簣欲爲山。", "是非擾擾俱身外，生死悠悠亦夢間。", "漫愛隠居多氣味，扁舟今欲與公還。"]'),
('0b8c6b18-37a6-406d-98dc-55ba5b6aba02','又書懷','彭汝礪','宋','宋诗','song-poetry','','[]','錦江蟠泊落雲端，秀氣全分在爾顔。',64,'全唐诗/poet.song.51000.json','["錦江蟠泊落雲端，秀氣全分在爾顔。", "少日大鵬飛北海，清時片玉出崑山。", "心存魏闕安危際，名在丹臺伯仲間。", "昨夜瀘渝初奏捷，巔崖誰爲勒銘還。"]'),
('3d5999a0-018e-4416-a030-4d0145f03dda','中丞溫伯雜端持正與其僚出祖正孺端伯于劉元忠宅某即席賦詩','彭汝礪','宋','宋诗','song-poetry','','[]','蜀山想見去程兼，滿眼春風別興添。',64,'全唐诗/poet.song.51000.json','["蜀山想見去程兼，滿眼春風別興添。", "光動酒船浮玉雪，味調羹鼎足梅鹽。", "竹枝墮影低垂砌，花葉吹香細入簾。", "更欲稍留山簡醉，應須少霽弱翁嚴。"]'),
('57fb29ff-af62-43c8-85f0-fd7e714181ce','翌日景繁察院公初叔明推直謙父主簿復會某晚至即席用前韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','鼎食參差海陸兼，爐烟浮動麝蘭添。',64,'全唐诗/poet.song.51000.json','["鼎食參差海陸兼，爐烟浮動麝蘭添。", "紛紛不及同朝飲，草草猶能共暮鹽。", "最愛梅香頻倚檻，欲留槐影更褰簾。", "驛途即折垂楊別，酒令毋嫌細柳嚴。"]'),
('33d624d4-aa52-40c7-a4a8-71c5039b0a8d','翌日景繁察院公初叔明推直謙父主簿復會某晚至即席用前韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','銀魚朱紱綵衣兼，稍覺公行氣象添。',64,'全唐诗/poet.song.51000.json','["銀魚朱紱綵衣兼，稍覺公行氣象添。", "白水長時雲似霧，青泥三月雪如鹽。", "詩成曷日傳郵置，書就他時奏陛簾。", "更爲朝廷問幽仄，人材豈遂乏楊嚴。"]'),
('724e4b47-a38d-4a9c-aa37-79415fc38a5d','送桂陽令臧祖道','彭汝礪','宋','宋诗','song-poetry','','[]','莫笑長官權勢輕，所懷端可及生靈。',64,'全唐诗/poet.song.51000.json','["莫笑長官權勢輕，所懷端可及生靈。", "勤憂每見朝嘗膽，勸恤遙知夜戴星。", "禮節但能堅玉石，清名亦合上丹青。", "餞行欲以言箴贈，留作君家座右銘。"]'),
('279fe5d0-0ea7-462b-93db-430d7e2b3ed1','中丞溫伯雜端持正約同餞夷仲不克某獨出城重陽後一日','彭汝礪','宋','宋诗','song-poetry','','[]','宛轉平林十里開，天晴更喜少風埃。',64,'全唐诗/poet.song.51000.json','["宛轉平林十里開，天晴更喜少風埃。", "桃花笑摘籬邊菊，竹葉慚無馬上盃。", "更欲看君橫奮迅，不應如我久低徊。", "閭閻蟄蟄憂昏墊，側耳乘驄御史來。"]'),
('895dfc94-19be-4b71-b8d8-bec9569c02cd','和提點少卿詩韵','彭汝礪','宋','宋诗','song-poetry','','[]','文場俱是出羣雄，曾頌鴻毛遇順風。',64,'全唐诗/poet.song.51000.json','["文場俱是出羣雄，曾頌鴻毛遇順風。", "稍記螭頭初賜第，漸驚鶴髮欲成翁。", "老年翰墨才仍敵，故國溪山路更同。", "存歿感懷渾夢寐，會須推付酒樽中。"]'),
('459ea98f-3e9e-4ea3-a0e9-1124b205bc7f','和提點少卿喜雪詩韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','曲岸滄洲一水涯，輕舟欲訪戴逵家。',64,'全唐诗/poet.song.51000.json','["曲岸滄洲一水涯，輕舟欲訪戴逵家。", "城隅寂淡梧桐月，溪岸蕭騷蘆葦花。", "潤澤便知年事足，清明更愛曉晴佳。", "園林已有春來信，笑看浮生鬢欲華。"]'),
('adf8bb75-5b8b-4901-a8a7-45ceb60080b9','和提點少卿喜雪詩韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','同雲漫不見津涯，雪霧參差似一家。',64,'全唐诗/poet.song.51000.json','["同雲漫不見津涯，雪霧參差似一家。", "辛苦宋人成楮葉，殷勤驛使寄梅花。", "潤沾南畝從橫闊，寒助西山曉夕佳。", "三白更同千乘喜，屢豐吾亦有光華。"]'),
('7430c987-2983-4bc9-94c3-c726d1b5a3bc','久雨和張季友寄程德林時季友得環倅程受婺源未赴','彭汝礪','宋','宋诗','song-poetry','','[]','寂寂不聞車馬聲，泥途無亦畏逢迎。',64,'全唐诗/poet.song.51000.json','["寂寂不聞車馬聲，泥途無亦畏逢迎。", "引觴自放連朝醉，揮麈遙思一座傾。", "傅野好爲三日雨，杜陵莫醉百憂行。", "西南俱說催征轡，却願雙輪四角生。"]'),
('3004d69b-a049-4730-8150-5711de92c803','和張季友正夫歸因爲詩寄','彭汝礪','宋','宋诗','song-poetry','','[]','曲曲幽林遠遠山，歸與誰得似公安。',64,'全唐诗/poet.song.51000.json','["曲曲幽林遠遠山，歸與誰得似公安。", "定爲五柳先生傳，應笑三年博士官。", "上國塵沙隨馬箠，長溪風浪屬漁竿。", "秋風喜得音聲到，起對青燈子細看。"]'),
('80bf74a9-bd58-48c2-b2a4-c0c6c09fc488','寄妻兄甯文淵時廣西方用兵而文淵謫官在廣東','彭汝礪','宋','宋诗','song-poetry','','[]','有客遲留瘴海邊，白頭想見欲潸然。',64,'全唐诗/poet.song.51000.json','["有客遲留瘴海邊，白頭想見欲潸然。", "淹留每笑猶千里，芘藾遙知有二天。", "行聽伏波平嶺嶠，已聞下瀨濟樓船。", "幾時幽谷靈芝路，水石相看穩晝眠。"]'),
('627903a2-33e9-4492-84b7-c94a50c63ddc','送郭知章宰浮梁  其一','彭汝礪','宋','宋诗','song-poetry','','[]','萬室喁喁望已深，臨流不敢重分襟。',64,'全唐诗/poet.song.51000.json','["萬室喁喁望已深，臨流不敢重分襟。", "閭閻早覺春風到，岩谷遙思晝日臨。", "制御古非無至策，愛調人自有良心。", "笑言已得公才敏，側耳風前聽好音。"]'),
('8ac94c7e-be24-4f0d-a528-99aba51135f0','送郭知章宰浮梁  其二','彭汝礪','宋','宋诗','song-poetry','','[]','仕宦悠悠今幾年，初分一邑走江邊。',64,'全唐诗/poet.song.51000.json','["仕宦悠悠今幾年，初分一邑走江邊。", "鳳飛遠水顛崖地，鶴唳清霜皓月天。", "瀟灑淵明多種秫，從容子賤數鳴弦。", "秋風坐看車轅速，一夢歸爭鳥翼先。"]'),
('1d4d903b-ada9-4f0a-bbe1-ef530771e688','和李潜夫同年并簡甯文淵時二君在鄱陽','彭汝礪','宋','宋诗','song-poetry','','[]','我賤無庸如子何，白頭相望欲悲歌。',64,'全唐诗/poet.song.51000.json','["我賤無庸如子何，白頭相望欲悲歌。", "少年策在英豪腹，清世名專守相科。", "薄宦從容憂自少，故人邂逅樂應多。", "秋風不見北歸信，東顧蒼茫臨大河。"]'),
('a64a5875-ef64-47da-bc86-a18eb7fdcaf5','送徐望之郎中提舉舒州靈仙觀','彭汝礪','宋','宋诗','song-poetry','','[]','江瀕遠別幾秋螢，汴曲相逢眼更青。',64,'全唐诗/poet.song.51000.json','["江瀕遠別幾秋螢，汴曲相逢眼更青。", "予志自能同豹變，弋人安得望鴻冥。", "風流綠蟻千鍾酒，香火黄庭一卷經。", "祇恐諸公還薦鶚，未容輕去老岩扃。"]'),
('115c3cb5-9518-4cef-8c34-f97cc5e5622a','送提點少卿丈還鄱陽','彭汝礪','宋','宋诗','song-poetry','','[]','秋風吹雨響梧桐，南岸遙山翠幾重。',64,'全唐诗/poet.song.51000.json','["秋風吹雨響梧桐，南岸遙山翠幾重。", "稍愛樓臺足清曠，可憐樽俎未從容。", "三溪天外橫新水，五老雲間出舊峰。", "邂逅一舟吾亦往，登臨還復與公從。"]'),
('469db357-01c3-400b-8c5f-818c432de8dc','奉和提點少卿來章','彭汝礪','宋','宋诗','song-poetry','','[]','場屋當年翰墨親，故鄉相別九年春。',64,'全唐诗/poet.song.51000.json','["場屋當年翰墨親，故鄉相別九年春。", "相如舊有凌雲賦，居士今惟凈法身。", "素節直須深愛惜，高材未必竟沉淪。", "祇疑龍去須爲雨，不似區區尺蠖伸。"]'),
('9bc9b501-0c15-46a4-982d-487281e0ad34','呈運判學士  其一','彭汝礪','宋','宋诗','song-poetry','','[]','邂逅江濱宿使航，五更窗外月猶黄。',64,'全唐诗/poet.song.51000.json','["邂逅江濱宿使航，五更窗外月猶黄。", "因陪談麈殊優遠，自反機心愈渺茫。", "老馬但羞千岳阻，病翰孰與九臯翔。", "明時頼有吾宗在，敢學西鄰便涕傷。"]'),
('2c6110d9-e391-4c5c-bfcc-c77d674ba716','呈運判學士  其二','彭汝礪','宋','宋诗','song-poetry','','[]','相望冰壺江水濱，渴心枯涸欲生塵。',64,'全唐诗/poet.song.51000.json','["相望冰壺江水濱，渴心枯涸欲生塵。", "忽逢使節何勝喜，又說宗乘得愈真。", "鬢裏雪霜經歲有，眼前風浪與時新。", "茫然未有歸田計，愧以窮通問故人。"]'),
('62b4a65d-f747-47d1-afd4-7ea5cc571189','和十二法曹','彭汝礪','宋','宋诗','song-poetry','','[]','秋來初得兔園書，更有詩來慰索居。',64,'全唐诗/poet.song.51000.json','["秋來初得兔園書，更有詩來慰索居。", "出宿幾時吾稅駕，歸寧何日爾脂車。", "貧如原憲元非病，懶比嵇康老更疏。", "鴻雁池邊知可樂，鶺鴒原上正相胥。"]'),
('124a413f-db48-436e-ab15-37a92140fd32','次韵晦之沿牒楚泗二州','彭汝礪','宋','宋诗','song-poetry','','[]','鷁首爭先鳥翼飛，宦游容易即天涯。',64,'全唐诗/poet.song.51000.json','["鷁首爭先鳥翼飛，宦游容易即天涯。", "漸生世事無由盡，已去年華不易追。", "芍藥遂輸淮上樂，櫻桃終念水邊期。", "雨餘亭外山爭出，幾日相看一酒巵。"]'),
('15cb43fe-88e6-42f4-8073-3a9697973368','苦吟','彭汝礪','宋','宋诗','song-poetry','','[]','苦吟遂見詩鋒銳，獨樂寧思飲社豪。',64,'全唐诗/poet.song.51000.json','["苦吟遂見詩鋒銳，獨樂寧思飲社豪。", "別去性情生淡泊，老來風致長清高。", "紛紛行李君休嘆，瑣瑣乘田吾正勞。", "爭似扁舟碧江上，幾回風物入秋毫。"]'),
('6af84c1e-5361-4f61-b6cc-348506142913','晚風','彭汝礪','宋','宋诗','song-poetry','','[]','南北東西萬里通，往來長與水無窮。',64,'全唐诗/poet.song.51000.json','["南北東西萬里通，往來長與水無窮。", "役心一日空隋力，餘澤千年謝禹功。", "滿道柳陰低翠幄，夾堤橋影臥長虹。", "樂游不及先生快，坐看千航起晚風。"]'),
('c28f119d-aab6-4eab-a9df-1a22b5f04202','四方','彭汝礪','宋','宋诗','song-poetry','','[]','四方難綴游人足，萬里無嗟客子蓬。',64,'全唐诗/poet.song.51000.json','["四方難綴游人足，萬里無嗟客子蓬。", "紅滿桃花生細浪，白翻蘋葉起清風。", "路當吳楚塵相接，源出淮夷勢未窮。", "聞說夜吟清不盡，月明如近水晶宮。"]'),
('70df3bb6-4298-4f7a-964b-1d51a8ac8e12','病中寄妻兄甯文淵','彭汝礪','宋','宋诗','song-poetry','','[]','百年流轉寄風波，老態欺人病更多。',64,'全唐诗/poet.song.51000.json','["百年流轉寄風波，老態欺人病更多。", "頼有子能知管仲，即無人可向維摩。", "悠悠世味祇如此，擾擾人生能幾何。", "南北有時歸計就，考槃終欲共山阿。"]'),
('211ae4ef-785c-41a9-aebc-600a26d835b2','和晦之所感','彭汝礪','宋','宋诗','song-poetry','','[]','萬物初還白帝秋，新寒苒苒上衣裘。',64,'全唐诗/poet.song.51000.json','["萬物初還白帝秋，新寒苒苒上衣裘。", "紅泥爛醉須千日，皓髮悲吟漫四愁。", "氣挹風雲詩易取，分投膠漆意難酬。", "簿書久廢游從樂，最負江山翠滿樓。"]'),
('a40376eb-9575-48fe-8208-5c2c71434b37','送濟叔兄','彭汝礪','宋','宋诗','song-poetry','','[]','風起青蘋去鷁催，江山無路笑言陪。',64,'全唐诗/poet.song.51000.json','["風起青蘋去鷁催，江山無路笑言陪。", "淚生病眼朝千里，愁入枯腸夜九迴。", "秋水忍看鴻獨宿，春風好與燕俱來。", "別期重有文章約，老稚應須眼爲開。"]'),
('434b0b3d-73a4-4f4d-bc99-50daa7097d34','送樊秀才召倪先生','彭汝礪','宋','宋诗','song-poetry','','[]','羣言分散寄遺經，天乞吾儕照未明。',64,'全唐诗/poet.song.51000.json','["羣言分散寄遺經，天乞吾儕照未明。", "猶惜是非迷後世，旁求規矩遺諸生。", "騏驎始信能千里，鵰鶚終須看一鳴。", "杖屨從容問孤跡，爲言心寄海邊城。"]'),
('9c84fe3f-4cf1-4315-b338-74d04f4df0eb','治平諒闇元夕  其一','彭汝礪','宋','宋诗','song-poetry','','[]','上元無樂送長宵，淚灑城陽泣帝堯。',64,'全唐诗/poet.song.51000.json','["上元無樂送長宵，淚灑城陽泣帝堯。", "雲障月華寒淡薄，風吹雨點細飄摇。", "物隨世事生悽愴，天與人心長寂寥。", "不用燈花鬭光景，火爐詩筆慰無聊。"]'),
('c494adbd-a62d-4c9d-b1f7-f1fe9257f223','治平諒闇元夕  其二','彭汝礪','宋','宋诗','song-poetry','','[]','仙樂誰家奏管簫，異香到處合椒聊。',64,'全唐诗/poet.song.51000.json','["仙樂誰家奏管簫，異香到處合椒聊。", "風生雨後聲悲慘，月在雲間影動摇。", "幽徑小溪春寂寂，淡燈寒燭夜寥寥。", "香焚敢效封人意，睿算年年祝帝堯。"]'),
('4efd430c-c120-465d-8530-005a77cec567','寄濟叔兄長','彭汝礪','宋','宋诗','song-poetry','','[]','東南路逕走江淮，萬里波聲日夜迴。',64,'全唐诗/poet.song.51000.json','["東南路逕走江淮，萬里波聲日夜迴。", "流水會將孤夢去，游鱗不寄尺書來。", "風吹雲影東西散，雨點花枝在處開。", "節物傷人心總碎，一春歸興滿蘭陔。"]'),
('587a2958-2860-4b7c-b8f1-c5dccfa25760','次致政張大夫韵二首  其一','彭汝礪','宋','宋诗','song-poetry','','[]','石城山水有清音，賈塹烟蘿路更深。',64,'全唐诗/poet.song.51000.json','["石城山水有清音，賈塹烟蘿路更深。", "松竹門闌初作徑，蒲荷池沼舊成林。", "騑騑出適窮周道，汩汩歸休傍漢陰。", "莫詫大夫能作賦，但逢故老數揮金。"]'),
('0a044080-21e9-4a31-9f86-e61646a1be2a','次致政張大夫韵二首  其二','彭汝礪','宋','宋诗','song-poetry','','[]','李郭曾同溪上船，途人指點作神仙。',64,'全唐诗/poet.song.51000.json','["李郭曾同溪上船，途人指點作神仙。", "松篁老長芰荷密，鳬雁飛浮鸂鶒前。", "霖雨未終岩野地，陽春方擅郢中天。", "文章不敢蘭亭比，翰墨纔能記歲年。"]'),
('dbacf75a-99b3-462c-88c6-08b5d999ffe9','醼亭一首','彭汝礪','宋','宋诗','song-poetry','','[]','未得從君醉醼亭，坐無酒意正醒醒。',64,'全唐诗/poet.song.51000.json','["未得從君醉醼亭，坐無酒意正醒醒。", "雲飛野壁春心遠，蝶悞花枝晝夢驚。", "草履踏泥尋曲徑，紗衣冒雨上重城。", "金絲不厭幽閨地，時向高風葉一聲。"]'),
('689434cd-37be-4c3d-b688-9ec60e8af451','皇甫乞詩爲贈因次其韵','彭汝礪','宋','宋诗','song-poetry','','[]','憶昔丹書下粉闈，諸公接武上瑶池。',64,'全唐诗/poet.song.51000.json','["憶昔丹書下粉闈，諸公接武上瑶池。", "勢淩鵰鶚雙鴻翼，香滿蟾蜍一桂枝。", "議論所存無贅學，聲華此去有真知。", "風松無限溪山樂，時倩秋風寄數詩。"]'),
('e0fd0844-0ad4-4a85-93f6-f58ecec11295','合肥府學中賡諸公韵和正寺翔甫總翠亭','彭汝礪','宋','宋诗','song-poetry','','[]','危亭縹緲壓城端，總拾澄虛入畫欄。',64,'全唐诗/poet.song.51000.json','["危亭縹緲壓城端，總拾澄虛入畫欄。", "地勢西連金斗峻，山容東際湫湖寒。", "行瞻日月光華近，坐覺乾坤器度寬。", "聞說南州畫工在，可能收作一屏看。"]'),
('96e46e44-4461-4230-8fcb-dee0aeff7f0d','和濟叔燈花','彭汝礪','宋','宋诗','song-poetry','','[]','燈花一點照花枝，今夕相看孰是非。',64,'全唐诗/poet.song.51000.json','["燈花一點照花枝，今夕相看孰是非。", "冷艷幾時開密室，春光半夜到重闈。", "稚兒戲蹙寒心落，羈婦爭持喜信歸。", "寄語簾風莫催促，冷吟贏得看芳菲。"]'),
('ee6b5f8f-2138-4610-880a-3d7e1eff505a','雜詠詩  其一','彭汝礪','宋','宋诗','song-poetry','','[]','詩軸親題乞一寮，清心洗濯渴心焦。',64,'全唐诗/poet.song.51000.json','["詩軸親題乞一寮，清心洗濯渴心焦。", "雲移星月來幽隠，風引英莖下寂寥。", "肝膽塵生知幾日，齒牙病起自今朝。", "疏愚强笑爲生計，不識鼇宮路徑遙。"]'),
('bfa9be7b-af16-48e1-acc5-3dfe5f43b809','雜詠詩  其二','彭汝礪','宋','宋诗','song-poetry','','[]','朔風吹雪滿天涯，寂寂朝雲冷萬家。',32,'全唐诗/poet.song.51000.json','["朔風吹雪滿天涯，寂寂朝雲冷萬家。", "試步城頭望坊巷，玉枝無處認梅花。"]'),
('4d1b9374-8e87-4fa2-970f-83c0b48c438b','苦旱和俞都官','彭汝礪','宋','宋诗','song-poetry','','[]','焚燒縱炎日，長養誤薰風。',48,'全唐诗/poet.song.51000.json','["焚燒縱炎日，長養誤薰風。", "責己君臨厚，勞心縣宰忠。", "十州饑饉後，萬里鬰陶中。", "欲寄精誠禱，天心或可通。"]'),
('ed313bf2-92c9-49a8-8c18-a0869381238a','上留守侍讀生辰','彭汝礪','宋','宋诗','song-poetry','','[]','素節于今傑，青春此日生。',120,'全唐诗/poet.song.51000.json','["素節于今傑，青春此日生。", "地還坤德重，天給露華清。", "鴻鵠飛昭曠，騏驎瑞太平。", "雲浮朱檻細，星入畫圖明。", "簪紱師先進，旒綖望老成。", "千齡逢盛際，萬里起修程。", "客獻南山頌，人期北戶榮。", "學高才稱副，仁厚福兼并。", "香薦芝蘭秀，詩言犬馬誠。", "祝公比松柏，早晚席台衡。"]'),
('4ad63d30-8213-45cd-ad6d-824711de53d3','九日獨登城上臺感懷寄兄長  其一','彭汝礪','宋','宋诗','song-poetry','','[]','九日獨登城上臺，南山望盡祇塵埃。',64,'全唐诗/poet.song.51000.json','["九日獨登城上臺，南山望盡祇塵埃。", "黄華雖富紛紛菊，綠蟻誰同灧灧盃。", "時節獨催雙鬢雪，利名還見此心灰。", "池陽星子多朋舊，能有音書萬里來。"]'),
('6feed7b3-95a8-4dd2-b175-4b6005a23a43','九日獨登城上臺感懷寄兄長  其二','彭汝礪','宋','宋诗','song-poetry','','[]','孤城幽谷晚烟重，事緒無過與此同。',32,'全唐诗/poet.song.51000.json','["孤城幽谷晚烟重，事緒無過與此同。", "寒夜獨吟風靜後，扁舟應宿月明中。"]'),
('ef2fb202-7630-49b2-aa4c-4c8602c12402','九日獨登城上臺感懷寄兄長  其三','彭汝礪','宋','宋诗','song-poetry','','[]','秋來常苦客飄蓬，身羨歸鴻飛復東。',32,'全唐诗/poet.song.51000.json','["秋來常苦客飄蓬，身羨歸鴻飛復東。", "欲問江南是何處，亂山擾擾自無窮。"]'),
('bef07c7b-90b3-4e86-8231-f85596b0664e','和應詔吟','彭汝礪','宋','宋诗','song-poetry','','[]','又得華牋是浣溪，短窗翰墨自光輝。',64,'全唐诗/poet.song.51000.json','["又得華牋是浣溪，短窗翰墨自光輝。", "寒梅不動情相炤，幽鳥無聲意欲飛。", "數四恩嘉成海瀆，百千文字粲珠璣。", "風花未稱相望意，特爲君王述萬機。"]'),
('335825d1-decb-45f3-b024-24c57c470595','秋風','彭汝礪','宋','宋诗','song-poetry','','[]','風戰江湖飛斷梗，露零霄漢聽征鴻。',64,'全唐诗/poet.song.51000.json','["風戰江湖飛斷梗，露零霄漢聽征鴻。", "身雖流俗志萬里，昔是少年今老翁。", "雙眼久因塵事黑，病顔今爲酒樽紅。", "夜深胡蝶歸魂夢，飛盡蓬瀛島嶼中。"]'),
('8f5d264b-7f1d-49d2-b8b0-0c0f4afac62a','山林','彭汝礪','宋','宋诗','song-poetry','','[]','鶴瘦松枯不自禁，窮愁千萬欲相侵。',64,'全唐诗/poet.song.51000.json','["鶴瘦松枯不自禁，窮愁千萬欲相侵。", "山林誰識謝公意，風月獨高梁甫吟。", "行視水痕嗟未息，靜看雲影愛無心。", "懶隨塵土趨時態，欲就絲桐丐古音。"]'),
('e5818a6e-92eb-4ffc-ba34-02d0cd81c31f','船中見廬山','彭汝礪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','翠色蒼茫杳藹間，船人指點是廬山。',32,'全唐诗/poet.song.51000.json','["翠色蒼茫杳藹間，船人指點是廬山。", "浮雲作意深藏護，未許行人取次看。"]'),
('1c5a480b-8a7a-4af4-a65f-0bcce89e5e17','浩歌','彭汝礪','宋','宋诗','song-poetry','','[]','歌盡綠洲千古意，陶然初到性情真。',64,'全唐诗/poet.song.51000.json','["歌盡綠洲千古意，陶然初到性情真。", "試臨華岳題詩筆，欲走滄浪買釣綸。", "苔潤一瓢貧氣味，草荒三徑久埃塵。", "我心自有青雲在，安得羈留濁水濱。"]'),
('dbf482d1-e894-4235-8581-a7463141d084','壯心','彭汝礪','宋','宋诗','song-poetry','','[]','銳氣銷磨一水平，壯心非欲避功名。',64,'全唐诗/poet.song.51000.json','["銳氣銷磨一水平，壯心非欲避功名。", "窮通有屬都天意，憂樂無端自物情。", "拂地延留山月影，褰簾收拾水風聲。", "清吟又得松陵侶，誰惜花前酒重傾。"]'),
('8a215b3d-d2b5-4c0a-acba-666be1ff4f04','大笑','彭汝礪','宋','宋诗','song-poetry','','[]','大笑花開傾屈卮，狂來不惜典春衣。',64,'全唐诗/poet.song.51000.json','["大笑花開傾屈卮，狂來不惜典春衣。", "飄浮世態知惟我，淡泊天真得者稀。", "雲漢露寒沾玉液，江天風靜拂金徽。", "樽罍易竭情無盡，海岳蒼茫一夢飛。"]'),
('8bdef680-1b95-4dd3-9f77-aed18d6bf942','步入','彭汝礪','宋','宋诗','song-poetry','','[]','步入浮游淡泊中，紅塵無計到心胸。',64,'全唐诗/poet.song.51000.json','["步入浮游淡泊中，紅塵無計到心胸。", "微之散落詩千首，白也飄零酒百鍾。", "天地寂寥窺夜月，風霜悲慘看春松。", "清晨試引青銅照，一點朱丹入病容。"]'),
('6d8276cd-b5dd-43c1-a33c-abbfdaf7909e','師言','彭汝礪','宋','宋诗','song-poetry','','[]','嘗就師言卜所從，萬爲都起至誠功。',64,'全唐诗/poet.song.51000.json','["嘗就師言卜所從，萬爲都起至誠功。", "天樞亹亹時長北，溪水悠悠夜亦東。", "陋跡已生千古後，微懷方醉六經中。", "竹林交友多才力，應念南軒一病翁。"]'),
('06bc7072-6185-44f4-9997-d03a78f3dc9a','縣舍小飲因就伯逢求饌具','彭汝礪','宋','宋诗','song-poetry','','[]','霜凋老木青楓碎，雪盡空山夜月新。',64,'全唐诗/poet.song.51000.json','["霜凋老木青楓碎，雪盡空山夜月新。", "收拾村醪欲歌笑，咨嗟破突久埃塵。", "分爲白屋窮賓客，迴睠青雲舊主人。", "天地苦寒今有備，醉橫詩筆覺精神。"]'),
('9f101f00-1e57-4fe9-ae08-22dd2c72edd3','累承見酬因謝之','彭汝礪','宋','宋诗','song-poetry','','[]','千夫拱默看文陣，百戰縱橫及醉鄉。',64,'全唐诗/poet.song.51000.json','["千夫拱默看文陣，百戰縱橫及醉鄉。", "齊晉亦當憂魯弱，韓吳終是怯秦强。", "威容敵國矜豪邁，氣壓羸兵急遯藏。", "他日相期坐帷幄，爲君窮力破戎羌。"]'),
('8bf35f58-deda-4585-a333-39d0ac05fa1c','匪躬先之桐廬因作詩送之','彭汝礪','宋','宋诗','song-poetry','','[]','男子生當自樹立，莫令寂默終無名。',64,'全唐诗/poet.song.51000.json','["男子生當自樹立，莫令寂默終無名。", "膏粱孰與文章樂，錦繡不如仁義榮。", "予病淹留豈得已，子今閒暇固當行。", "竹林交契知安否，議論從容爲寄聲。"]'),
('9a45342a-7b40-44fc-9901-2690275a94fa','次韵晦之楚泗道中','彭汝礪','宋','宋诗','song-poetry','','[]','白日紅塵身世勞，羨君詩興自陶陶。',64,'全唐诗/poet.song.51000.json','["白日紅塵身世勞，羨君詩興自陶陶。", "敢因錦繡邀青玉，漫把瑶瓊報木桃。", "冰雪正寒心始見，騏驎已老氣終豪。", "一言起拜先生辱，羞愧無才及楚騷。"]'),
('4b24a18a-c468-4df6-b596-8843cb54d9dd','暮雨','彭汝礪','宋','宋诗','song-poetry','','[]','暮雨忽隨江上舟，寒風彷彿轉清秋。',64,'全唐诗/poet.song.51000.json','["暮雨忽隨江上舟，寒風彷彿轉清秋。", "興隨烟月成千首，醉忤鶑花長四愁。", "不繫可憐波上葉，忘機應喜海邊鷗。", "一聲畫角吹魂夢，散落淮天曉未收。"]'),
('2252f8e9-1e73-43d7-b572-417716989a40','扁舟','彭汝礪','宋','宋诗','song-poetry','','[]','扁舟滿眼送波濤，一夜霜華上鬢毛。',64,'全唐诗/poet.song.51000.json','["扁舟滿眼送波濤，一夜霜華上鬢毛。", "雨脚已收朝日薄，潮頭忽上曉風高。", "江山須信游人樂，簿領還知俗吏勞。", "見說指揮功利白，餘才今見解牛刀。"]'),
('8a6748c9-0771-4c4a-978b-819558fcf360','欲寄','彭汝礪','宋','宋诗','song-poetry','','[]','欲寄予聲無使還，平安始見一書間。',64,'全唐诗/poet.song.51000.json','["欲寄予聲無使還，平安始見一書間。", "偶從淝水經淮水，應對龜山憶蜀山。", "浮世並知俱物役，利途曾復見人閑。", "每言庾信愁難解，果道安仁鬢已斑。"]'),
('5bc952a4-e45b-4b4f-9062-7a8b23fe6416','古廟','彭汝礪','宋','宋诗','song-poetry','','[]','嚴嚴遺廟水岩幽，想像遲回物爲秋。',64,'全唐诗/poet.song.51000.json','["嚴嚴遺廟水岩幽，想像遲回物爲秋。", "堂陛終須辨臣主，山河空復誓王侯。", "地全東海疑先兆，力盡淮陰意未休。", "可恨游人滿門下，不將敧器與君謀。"]'),
('9ee5edd4-6165-4452-8a64-251036561411','楚野','彭汝礪','宋','宋诗','song-poetry','','[]','楚野雲寒山點綴，淮天波盡水徘徊。',64,'全唐诗/poet.song.51000.json','["楚野雲寒山點綴，淮天波盡水徘徊。", "古今寥廓歸談笑，氣象縱橫費剪裁。", "愁日遠隨雙錦翼，離情滿寄百金盃。", "清風正引城頭望，淮上車音幾日來。"]'),
('26a77f42-32f8-4219-bfe3-6a521a00b7f3','次韵劉景文見寄','彭汝礪','宋','宋诗','song-poetry','','[]','萬里飄蓬失舊游，汴隄別去又三秋。',64,'全唐诗/poet.song.51000.json','["萬里飄蓬失舊游，汴隄別去又三秋。", "朔風悵望心先去，夜月相瞻影獨留。", "偶得篇章還自失，喜因文字會忘憂。", "幾時樽俎追平昔，熟醉靈芝最上頭。"]'),
('818e4938-ccae-4162-94aa-e01d9dae44c7','題程則之瑞墨閣','彭汝礪','宋','宋诗','song-poetry','','[]','仁宗事業望唐虞，翰墨仍兼八體書。',64,'全唐诗/poet.song.51000.json','["仁宗事業望唐虞，翰墨仍兼八體書。", "長嘆仙游今寂寞，不知遺跡在樵漁。", "凰鸞影落新安水，奎壁光臨處士廬。", "北望昭陵雲杳靄，倚欄雙淚染衣裾。"]'),
('7e24846d-67b6-45db-9f01-3bdfeb0ece6a','將及下蔡寄仲求','彭汝礪','宋','宋诗','song-poetry','','[]','不見大夫行五年，渡淮欲見淚潺湲。',64,'全唐诗/poet.song.51000.json','["不見大夫行五年，渡淮欲見淚潺湲。", "憂懷荏苒今衰矣，仕宦遲迴亦偶然。", "眼看飛雲難自定，身隨去鳥擬爭先。", "更鞭駑馬登橫嶺，即借長橋濟大川。"]'),
('09e3168c-568d-44fb-b1f8-ccf9631aa357','九日同仲求登高有感','彭汝礪','宋','宋诗','song-poetry','','[]','曾侍靈芝九日觴，登高從此共淒涼。',64,'全唐诗/poet.song.51000.json','["曾侍靈芝九日觴，登高從此共淒涼。", "故鄉江外烟波闊，上國雲中道路長。", "世事祇催蓬鬢雪，秋風不減菊花黄。", "坐看鴻雁天涯遠，甘醉茱萸盞面香。"]'),
('e4e6011c-7016-4c7b-bb1d-59b40a601cc6','別子容','彭汝礪','宋','宋诗','song-poetry','','[]','衣衫塵土待光輝，議論淵源慰渴饑。',64,'全唐诗/poet.song.51000.json','["衣衫塵土待光輝，議論淵源慰渴饑。", "鄙遠尚思同舊學，疲駑常恐誤真知。", "壯懷銷落非前日，孤宦邅迴强此時。", "萬事紛紛知有在，齋心更欲問蓍龜。"]'),
('2d6810e8-c08e-4573-8716-2455e95f4508','自北歸夜夢侍親闈久之既覺感而成詩','彭汝礪','宋','宋诗','song-poetry','','[]','中宵八九夢親闈，笑逐兒童戲綵衣。',64,'全唐诗/poet.song.51000.json','["中宵八九夢親闈，笑逐兒童戲綵衣。", "起覺片身猶逆旅，化爲雙淚落征衣。", "祇嗟輕逐孤蓬轉，安得爭先去鳥飛。", "薄宦自傷無以養，亦知從昔戒脂韋。"]'),
('2c00d1d6-21ba-4637-919a-cbcff35dc721','兄弟約芝山共學未暇辱以詩督之因次元韵','彭汝礪','宋','宋诗','song-poetry','','[]','弟兄相寄玉爲音，洗盡塵埃一寸心。',64,'全唐诗/poet.song.51000.json','["弟兄相寄玉爲音，洗盡塵埃一寸心。", "欲以蚊虻看勢利，能將珠璧現光陰。", "雅游瀟灑知難廢，故約遲留惜未尋。", "北望靈芝山在處，暮雲回合碧沈沈。"]'),
('eb4f9ab4-2dcc-499b-8107-2fa29c3f347b','讀書','彭汝礪','宋','宋诗','song-poetry','','[]','讀書雖苦亦何知，仕宦紛紛强此時。',64,'全唐诗/poet.song.51000.json','["讀書雖苦亦何知，仕宦紛紛强此時。", "舊學望君真短短，新詩愛我已枝枝。", "清生野檻晨風遠，暖度山窗晝日遲。", "出處從今能自卜，不庸蓍蔡已無疑。"]'),
('63d97cab-9b53-48b1-85a8-34b3761ba2c4','清明日仲永游薦福先秋亭晚過芝山他日有坐客獻詩者仲永見率同和','彭汝礪','宋','宋诗','song-poetry','','[]','行背林梢轉水灣，樂游與物共安閑。',64,'全唐诗/poet.song.51000.json','["行背林梢轉水灣，樂游與物共安閑。", "旌旗影散烟波上，金竹聲流島嶼間。", "宿雨未乾花焰焰，晨風不動鳥關關。", "久晴見說春尤好，何日重來訪舊山。"]'),
('085c067e-c217-4716-9a63-065c2d851e4d','送鄒秘丞廣漢赴御史','彭汝礪','宋','宋诗','song-poetry','','[]','清論從來滿士林，君王今日爲虛襟。',64,'全唐诗/poet.song.51000.json','["清論從來滿士林，君王今日爲虛襟。", "謀維已熟言難廢，勢位雖隆望亦深。", "可否謹須要至理，窮通知不異丹心。", "北風會到江南路，日上城頭聽好音。"]'),
('fbb6f361-3568-4997-9bc0-8e61a33647ba','廣漢言事得陵州仁壽縣將以詩迎之','彭汝礪','宋','宋诗','song-poetry','','[]','昨日除書下禁林，詔言明白灑宸襟。',64,'全唐诗/poet.song.51000.json','["昨日除書下禁林，詔言明白灑宸襟。", "誠留魏闕初非淺，望繫朝廷晚更深。", "議論自關天下計，功名非係古人心。", "秋風行李歸來未，旦暮虛懷遲玉音。"]'),
('8e9f55b6-2cd0-4c3a-a0e5-0a0fd943900d','次張同年德父移松杉石楠海棠各賦一首  其一','彭汝礪','宋','宋诗','song-poetry','','[]','孝思知欲寄無窮，手插松枝宅兆東。',64,'全唐诗/poet.song.51000.json','["孝思知欲寄無窮，手插松枝宅兆東。", "始聽靈根來澗底，會看高節入雲中。", "紛紛淚滴枝頭露，擾擾愁隨葉上風。", "老盡雪霜終不變，亦知因此議窮通。"]'),
('c93f9d6f-53c8-4ae9-b49b-232846c51cf6','次張同年德父移松杉石楠海棠各賦一首  其二','彭汝礪','宋','宋诗','song-poetry','','[]','張子紛紛非世情，栽杉爲徑護墳塋。',64,'全唐诗/poet.song.51000.json','["張子紛紛非世情，栽杉爲徑護墳塋。", "烟冥接葉愁俱滿，露落低枝涕泗橫。", "直幹森森才滿握，微陰細細欲盈城。", "栽培會與風霜老，愛護無容螻蟻生。"]'),
('722d2962-720d-4dbd-9375-5664b25d12aa','次張同年德父移松杉石楠海棠各賦一首  其三','彭汝礪','宋','宋诗','song-poetry','','[]','石楠梭木照春山，顔色紛紛亂碧丹。',64,'全唐诗/poet.song.51000.json','["石楠梭木照春山，顔色紛紛亂碧丹。", "剩葉如雲散幽塚，清陰爲蓋覆靈壇。", "沾濡細雨生秋色，摇撼驚風長夜寒。", "應並孤松長共老，好栽慈竹與同看。"]'),
('5e81bafd-6a6c-4a42-9fd5-8d27dbbd5979','次張同年德父移松杉石楠海棠各賦一首  其四','彭汝礪','宋','宋诗','song-poetry','','[]','見說無因寄孝心，自移花種碧山岑。',64,'全唐诗/poet.song.51000.json','["見說無因寄孝心，自移花種碧山岑。", "栽培蒙密春先暖，想像遲回日爲陰。", "多恨祇悲新雨露，遺靈如得舊園林。", "黄鸝不會人情思，亦向枝頭送好音。"]'),
('e565cb70-3d37-4da1-8bc5-ad1382eaa94e','寄學芝山正叔寄詩有想嘆之意次元韵','彭汝礪','宋','宋诗','song-poetry','','[]','想望獨登城上臺，重雲不見首勤回。',64,'全唐诗/poet.song.51000.json','["想望獨登城上臺，重雲不見首勤回。", "久分笑語心幾塞，忽得詩書眼爲開。", "草褐岸巾隨鹿豕，佳山野水外塵埃。", "公名方與風霆遠，未可窺余寂寞來。"]'),
('ab455306-ee3d-4787-bc88-7627c6af50d7','詩寄兄長并示十二十四舍弟','彭汝礪','宋','宋诗','song-poetry','','[]','去年馬走途中雪，今日舟行湖上風。',64,'全唐诗/poet.song.51000.json','["去年馬走途中雪，今日舟行湖上風。", "吾分自天俱有定，此憂如水自無窮。", "誰知雲漢雙飛雁，自笑江湖一斷蓬。", "祇有綵衣情最樂，復嗟不與弟兄同。"]'),
('00889108-e539-45d8-bc4a-3184519f97cf','夏六月公濟與弟六人游安國竹園某有詩','彭汝礪','宋','宋诗','song-poetry','','[]','萬竹紛紛光欲流，花亭况在竹林幽。',64,'全唐诗/poet.song.51000.json','["萬竹紛紛光欲流，花亭况在竹林幽。", "陰藏絕徑爲深谷，風起炎天見早秋。", "此地遂爲千畝勝，吾儕非止七賢游。", "清凉可愛無朝夕，無問昏鴉故未休。"]'),
('ffb1ed72-1325-44d3-9d30-365cff068747','晚行竹林兄弟相率賦詩  其一','彭汝礪','宋','宋诗','song-poetry','','[]','苒苒秋風吹我衣，留連清勝夜忘歸。',32,'全唐诗/poet.song.51000.json','["苒苒秋風吹我衣，留連清勝夜忘歸。", "眉橫雲外新蟾上，雪落林梢白鷺飛。"]'),
('e0540ed0-7455-459e-ba41-724bafc0dfed','晚行竹林兄弟相率賦詩  其二','彭汝礪','宋','宋诗','song-poetry','','[]','碧竹侵雲一萬竿，挾書時此共盤桓。',32,'全唐诗/poet.song.51000.json','["碧竹侵雲一萬竿，挾書時此共盤桓。", "湘沅見說官期逼，預惜朋游別去難。"]'),
('a6f4d4d7-79bc-421a-a0c5-3703fa38ec14','某在合肥嘗夢同子直在橫川舊游遞中有詩往還子直見招因用前韵來寄','彭汝礪','宋','宋诗','song-poetry','','[]','春風把酒共溪邊，南北紛紛遂五年。',64,'全唐诗/poet.song.51000.json','["春風把酒共溪邊，南北紛紛遂五年。", "綠綬終朝寄塵俗，青雲昨夜夢神仙。", "詩多老格知難繼，易外新聞念未傳。", "彷彿異時佳句在，吾遊不敢負橫川。"]'),
('d2ed9085-83f7-4323-8cd8-a335446eaa49','汴水呈祖道','彭汝礪','宋','宋诗','song-poetry','','[]','萬事無庸輕是非，扁舟吾與子同歸。',64,'全唐诗/poet.song.51000.json','["萬事無庸輕是非，扁舟吾與子同歸。", "不知心逐征雲遠，安得身先去鳥飛。", "月入江湖生夜色，風吹花木長春暉。", "鬢毛每笑多新雪，衣带頻驚緩舊圍。"]'),
('b44abbcd-71e7-4527-ade4-91a8ebc932c9','和祖道見致政王中允題壁','彭汝礪','宋','宋诗','song-poetry','','[]','里巷參差一水間，水邊相失復三年。',64,'全唐诗/poet.song.51000.json','["里巷參差一水間，水邊相失復三年。", "舊題想見風規好，清隠傳聞志尚賢。", "道路尚能談舊事，林泉寧復掛塵緣。", "遲回祿仕予真怯，不獨無君郭外田。"]'),
('81264ae2-e944-4951-bbe8-1f65c2854822','江口道中','彭汝礪','宋','宋诗','song-poetry','','[]','道路春晴柳葉長，川原水涸草苽黄。',64,'全唐诗/poet.song.51000.json','["道路春晴柳葉長，川原水涸草苽黄。", "陰晴天氣猶寒食，村郭人家似故鄉。", "地曠馬牛羣放牧，時平兒女自耕桑。", "馬蹄即踏江南路，村店相看酒一觴。"]'),
('21e43405-8358-4062-95c2-f302bf513f2b','和祖道渡江','彭汝礪','宋','宋诗','song-poetry','','[]','歸上慈親酒一觴，吾榮不啻插麾幢。',64,'全唐诗/poet.song.51000.json','["歸上慈親酒一觴，吾榮不啻插麾幢。", "雨沾馬轡行春野，風滿舟檣泛曉航。", "江路好山隨步履，人家流水照軒窗。", "梅仙不怪多詩思，鶑語紛紛燕子雙。"]'),
('e3c74635-8eb3-453d-9110-2927a1b5be2f','曉行','彭汝礪','宋','宋诗','song-poetry','','[]','遲明騎馬聽鷄號，霧露紛紛上鬢毛。',64,'全唐诗/poet.song.51000.json','["遲明騎馬聽鷄號，霧露紛紛上鬢毛。", "烟宿平蕪疑遠水，風鳴高木聽飛濤。", "暖迴宿草春初見，光動扶桑日欲高。", "橫笛一聲還出牧，稚兒無不笑吾勞。"]'),
('6389b3d2-f990-4a9e-98ac-b2127d7d02cc','和致遠登樓有感','彭汝礪','宋','宋诗','song-poetry','','[]','昔人已勸莫登樓，年少登樓應白頭。',64,'全唐诗/poet.song.51000.json','["昔人已勸莫登樓，年少登樓應白頭。", "鳷鵲雪殘冰尚泮，蓬萊雲靜月如流。", "燈棚影闊明千里，樂部聲長在十洲。", "萬物莫如公最樂，詩情應祇爲民憂。"]'),
('88bed600-d3c4-4ea0-90ca-e25c96c9ec0d','贈陳擴秀才','彭汝礪','宋','宋诗','song-poetry','','[]','原憲家無金玉儲，生涯惟有一床書。',64,'全唐诗/poet.song.51000.json','["原憲家無金玉儲，生涯惟有一床書。", "衆人清論誰知子，終日高談謝起予。", "叔夜未嘗聞喜慍，偉容如不辨親疏。", "丈夫當重功名計，天子重閽好曳裾。"]'),
('ba26d5b9-5b8c-44d6-b154-f11ea00e2ffa','寄子文友','彭汝礪','宋','宋诗','song-poetry','','[]','古人湮沒不能見，交道陵夷真可哀。',64,'全唐诗/poet.song.51000.json','["古人湮沒不能見，交道陵夷真可哀。", "與子碧江相別後，到今青眼未曾開。", "幾傷尺素無人寄，猶喜新鴻昨夜來。", "懷抱相思長抑鬰，燕居還念此心哉。"]'),
('1b1cd985-3c29-47c1-9b21-cf6dc65575ea','讀張華傳','彭汝礪','宋','宋诗','song-poetry','','[]','堂堂才業世無鄰，坐揖荆吳屬晉民。',64,'全唐诗/poet.song.51000.json','["堂堂才業世無鄰，坐揖荆吳屬晉民。", "當日若知誅嬖妾，英魂未必死姦臣。", "尚能博識周羣物，誰使無謀衛一身。", "典午基圖從此殆，開編令我涕沾巾。"]'),
('a958dd17-f50a-430f-bfd8-d7e27c7c6a2f','春日','彭汝礪','宋','宋诗','song-poetry','','[]','青春久雨郊原暗，白日新開錦繡明。',64,'全唐诗/poet.song.51000.json','["青春久雨郊原暗，白日新開錦繡明。", "苒苒碧絲垂柳樹，勻勻紅粉上花英。", "人生最貴逢辰樂，暇日終當載酒行。", "無爲草玄成寂寞，便輸風景屬流鶑。"]'),
('aabd033a-d9e5-47ce-9bd1-dc70205b8b1c','和千乘先生詩','彭汝礪','宋','宋诗','song-poetry','','[]','蓬蓽猶淹濟世圖，獨持經術振羣愚。',64,'全唐诗/poet.song.51000.json','["蓬蓽猶淹濟世圖，獨持經術振羣愚。", "困窮自古饒賢者，功業于今屬丈夫。", "天下久思安石起，時人爭笑孟軻迂。", "何時幣聘來莘畝，佇聽嘉言上禁途。"]'),
('03df5f8a-1237-4247-ab0d-8ae8b2df40d1','賦環翠軒池鸂鶒','彭汝礪','宋','宋诗','song-poetry','','[]','池軒澄澈岸花薰，吾愛微禽獨此存。',64,'全唐诗/poet.song.51000.json','["池軒澄澈岸花薰，吾愛微禽獨此存。", "野性尚思江海逸，靈心應識稻粱恩。", "春風鼓舞波濤綠，夜月棲遲藻荇繁。", "沙雁溪鳬應羨汝，光輝終日望華軒。"]'),
('578091d9-487e-4c94-b715-e175817db0c6','與程德林','彭汝礪','宋','宋诗','song-poetry','','[]','俊骨風標固逸倫，况聞才術巧安民。',64,'全唐诗/poet.song.51000.json','["俊骨風標固逸倫，况聞才術巧安民。", "尋常恨不親高誼，邂逅相逢即古人。", "議論恥拘時俗態，笑歌惟取性情真。", "從今便作忘形契，安得相從席上珍。"]'),
('19774fbc-e666-4358-85e0-ecb7b379ec48','病居寄程德林','彭汝礪','宋','宋诗','song-poetry','','[]','槿花時態厭羈貧，誰恤天涯臥病身。',64,'全唐诗/poet.song.51000.json','["槿花時態厭羈貧，誰恤天涯臥病身。", "千里有家歸未得，一心無頼恨長新。", "形容憔悴真衰漢，意氣蕭條似老人。", "恨乏酒樽將寂寞，獨憑詩句訴酸辛。"]'),
('5fe05761-e1f8-48ec-a4fb-5fcd2abdd833','月夜憶伯兄兼寄諸友','彭汝礪','宋','宋诗','song-poetry','','[]','炎暑遁逃天已凉，日陰苦短夜初長。',64,'全唐诗/poet.song.51000.json','["炎暑遁逃天已凉，日陰苦短夜初長。", "風聲日色盡秋意，海角天涯非故鄉。", "鶑谷久離愁滿眼，鴒原一別淚沾裳。", "客情欲借清吟遣，詩就客情彌慘傷。"]'),
('b06ce85d-e202-462d-b062-5d5eba45bb9a','適婺','彭汝礪','宋','宋诗','song-poetry','','[]','浮俗區區走利名，吾儒何事亦勞生。',64,'全唐诗/poet.song.51000.json','["浮俗區區走利名，吾儒何事亦勞生。", "昔騎馬作衢江計，今買舟爲婺女行。", "南北東西無定日，艱難險阻亦常情。", "日多好景誰同詠，樽有清醪且自傾。"]'),
('f57319b2-4b97-4159-af26-06dfb5b40b0b','寄桐廬諸友','彭汝礪','宋','宋诗','song-poetry','','[]','整頓衰羸尚未蘇，信音都向故人疏。',64,'全唐诗/poet.song.51000.json','["整頓衰羸尚未蘇，信音都向故人疏。", "須憐犬子常多病，莫笑嵇康懶作書。", "庠序舊規還在否，道塗新况比何如。", "鱗鴻若到江南地，願寄聲音一起予。"]'),
('55e2bb5e-29fd-4802-9aac-1a1e5c7461c9','寄鄒廣道  其一','彭汝礪','宋','宋诗','song-poetry','','[]','陋學常嗟趣識迷，羨君先得正途歸。',64,'全唐诗/poet.song.51000.json','["陋學常嗟趣識迷，羨君先得正途歸。", "直從前哲評高下，羞與時人較是非。", "長憤荆蒿埋杞梓，忽驚沙礫得珠璣。", "相從未幾又相去，東望門闌心欲飛。"]'),
('117989c4-8e0d-4f7a-ac84-037841d910fc','寄鄒廣道  其二','彭汝礪','宋','宋诗','song-poetry','','[]','夙昔聞君有古風，里閭邂逅一相逢。',64,'全唐诗/poet.song.51000.json','["夙昔聞君有古風，里閭邂逅一相逢。", "金蘭密契雖深結，風月高吟未款從。", "寶玉如能庇嘉穀，微蒿終待倚長松。", "江頭若有東歸雁，時寄聲音慰病容。"]'),
('350b17bf-f552-4690-b887-e0f1aa264eb9','風便示君時叔宜二弟','彭汝礪','宋','宋诗','song-poetry','','[]','掛帆瞬息絕遠水，行李逡巡臨故鄉。',64,'全唐诗/poet.song.51000.json','["掛帆瞬息絕遠水，行李逡巡臨故鄉。", "雨潤棣棠千葉葉，雲深鴻雁一行行。", "清吟未愜溪山勝，熟睡不知岐路長。", "邂逅此時同此樂，萱堂卮酒意難忘。"]'),
('153d6471-ee01-4aa3-b378-d84cfa9ef5e1','簡振道判官','彭汝礪','宋','宋诗','song-poetry','','[]','涉汴浮淮即渡江，一春飽滿看滄浪。',64,'全唐诗/poet.song.51000.json','["涉汴浮淮即渡江，一春飽滿看滄浪。", "臨溪高柳爲誰綠，隔浦幽花還自香。", "暖日魚兒浮密藻，輕風燕子語危檣。", "遙知景物煩酬唱，到日詩成幾百章。"]'),
('90756bca-f463-41d7-8953-afc13581fc6d','江流','彭汝礪','宋','宋诗','song-poetry','','[]','江流繚繞轉天涯，萬幅風帆去若馳。',64,'全唐诗/poet.song.51000.json','["江流繚繞轉天涯，萬幅風帆去若馳。", "紅日遠山開殿閣，青天高木出旌旗。", "蛟龍迴泊鰭鱗動，燕雀飛翻羽翮遲。", "身世百年長擾擾，扁舟多謝捕魚兒。"]'),
('1fca99c2-f716-4be0-99c3-72c1a69bb006','子發南樓餞穎叔適以使事出行因寄拙句','彭汝礪','宋','宋诗','song-poetry','','[]','溪山遠遠綠如如，坐想南樓縱目初。',64,'全唐诗/poet.song.51000.json','["溪山遠遠綠如如，坐想南樓縱目初。", "相別無緣看楊柳，贈行不敢愛瓊琚。", "浮生稍自嘗艱險，遠道非關畏簡書。", "雲去正凝千里目，雁來能寄一行歟。"]'),
('b02175e1-f3e6-4592-a254-4d74d8067d29','送君時東歸夜宿城外并橋上  其一','彭汝礪','宋','宋诗','song-poetry','','[]','疏疏星月帖雲浮，槐葉風聲已轉秋。',32,'全唐诗/poet.song.51000.json','["疏疏星月帖雲浮，槐葉風聲已轉秋。", "欲寄歸帆終未得，徒分心逐水東流。"]'),
('104f5945-30db-482a-9ba4-6bd024fd310e','送君時東歸夜宿城外并橋上  其二','彭汝礪','宋','宋诗','song-poetry','','[]','虹蜺盤泊宿河陰，氣勢凌空幾百尋。',64,'全唐诗/poet.song.51000.json','["虹蜺盤泊宿河陰，氣勢凌空幾百尋。", "月近渾如天上坐，風來不見世間音。", "吾衰祇有臨淵懼，爾壯能無題柱心。", "病眼昏昏長似霧，不堪頻淚欲分襟。"]'),
('dbf82561-8c77-4be4-bca9-a8d13ff05a54','君時與董君佐以鄉薦相次登甲科有詩送之邀予同賦','彭汝礪','宋','宋诗','song-poetry','','[]','青衫慰子久蹉跎，各喜流年壯未過。',64,'全唐诗/poet.song.51000.json','["青衫慰子久蹉跎，各喜流年壯未過。", "金玉曹劉初並價，淵源游夏復同科。", "紅塵去馬侵星月，綠水歸艎觸芰荷。", "邂逅故鄉秋正好，相看憶聽鹿鳴歌。"]'),
('c3352d82-5a12-4fa7-b283-6ff007e57a59','治平赴肥陵幕侍父兄宿大孤山南今復泊于此','彭汝礪','宋','宋诗','song-poetry','','[]','扁舟曾宿此江堧，當日朱顔尚少年。',64,'全唐诗/poet.song.51000.json','["扁舟曾宿此江堧，當日朱顔尚少年。", "彩筆偶攀天上桂，青衫初泛幕中蓮。", "浮生夢幻今衰矣，薄宦風波尚慎旃。", "記得父兄游屣處，淚添溪水欲無邊。"]'),
('cf8a889b-ae5f-4d6b-a3d3-b99626de9c82','送梁晦之','彭汝礪','宋','宋诗','song-poetry','','[]','行李參差久不齊，飄蓬邂逅暫相依。',64,'全唐诗/poet.song.51000.json','["行李參差久不齊，飄蓬邂逅暫相依。", "趨馳靜笑營生拙，老大今知舊態非。", "車馬一朝君北去，江湖何日我南歸。", "人間物物渾虛幻，莫爲分襟淚輒揮。"]'),
('129680a0-9c03-4f5d-8326-09f0db506a32','江口','彭汝礪','宋','宋诗','song-poetry','','[]','北風吹蕩酒旗斜，渡口寥寥數十家。',64,'全唐诗/poet.song.51000.json','["北風吹蕩酒旗斜，渡口寥寥數十家。", "茅屋尺椽貧活計，漁罾一幅舊生涯。", "青雲正著楊柳葉，白雪已開蘆葦花。", "蓬笠焉知慕軒冕，牛羊豈遂勝魚蝦。"]'),
('d4593d51-b0e1-45fd-a363-4dd86298a7b5','粹老召飲滕王閣遂過徐亭泛舟戲呈粹老','彭汝礪','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','溪山高下綠參差，終日清風慰所思。',64,'全唐诗/poet.song.51000.json','["溪山高下綠參差，終日清風慰所思。", "何不並携安石妓，却須一過習家池。", "桐孫轉影隨朱檻，蓮子吹香入酒卮。", "曉色江湖秋更好，微雲恰值雨來時。"]'),
('41bfdf2d-1c89-43b9-b5c9-5c451a57d647','游東湖','彭汝礪','宋','宋诗','song-poetry','','[]','草色蒹葭蘆葦中，蓮花一片萬枝紅。',64,'全唐诗/poet.song.51000.json','["草色蒹葭蘆葦中，蓮花一片萬枝紅。", "斜陽色妬波心日，細雨香吹水面風。", "澤國地開金色界，桃源人在水晶宮。", "扁舟便好如張翰，好在溪邊舊釣筒。"]'),
('3ea22de8-2fad-4f49-ad80-9edbd842094d','詩呈季友殿丞因寄正父兄','彭汝礪','宋','宋诗','song-poetry','','[]','寂寂門無車馬塵，故人相過覺情親。',64,'全唐诗/poet.song.51000.json','["寂寂門無車馬塵，故人相過覺情親。", "焉知軒冕金朱貴，不笑虀鹽藜莧貧。", "看月縱吟頤閣夜，插花沉醉鑑亭春。", "白頭想嘆童兒事，渾屬溪邊自在身。"]'),
('31f11027-6849-4dfc-884c-e5415ece13f6','生日提點少卿公諤惠詩因次元韵','彭汝礪','宋','宋诗','song-poetry','','[]','水日金行共一鄉，丈人每愛我辰良。',64,'全唐诗/poet.song.51000.json','["水日金行共一鄉，丈人每愛我辰良。", "驊騮未解馳千里，弧矢猶知志四方。", "漫與乾坤同作客，笑看兒女已成行。", "貧家祇似尋常日，金玉何爲忽在堂。"]'),
('90f6f886-4b3a-415d-aa45-1c1081e2095d','寄雲居覺老大禪師','彭汝礪','宋','宋诗','song-poetry','','[]','雲中樓閣綠沉沉，杖策城頭望正深。',64,'全唐诗/poet.song.51000.json','["雲中樓閣綠沉沉，杖策城頭望正深。", "山近想瞻師子坐，風來疑聽海潮音。", "三乘漫設牛羊鹿，一路誰分耳目心。", "祇道不增還不減，元來非古亦非今。"]'),
('237ed1b8-851a-48ec-8de3-4b9f4fd6c3fc','和莘老元日時改元豐  其一','彭汝礪','宋','宋诗','song-poetry','','[]','天以元豐號太平，新年風物兆康寧。',64,'全唐诗/poet.song.51000.json','["天以元豐號太平，新年風物兆康寧。", "農人待種滂沱雨，太史仍占潤澤星。", "初日浮陽臨夏屋，宿霜澄澈照寒廳。", "玉津池北池南路，還擬同探柳眼青。"]'),
('1222aadd-a127-4509-88af-e0c66f9d8b21','和莘老元日時改元豐  其二','彭汝礪','宋','宋诗','song-poetry','','[]','衣冠投曉賀元正，草木欣欣共晏寧。',64,'全唐诗/poet.song.51000.json','["衣冠投曉賀元正，草木欣欣共晏寧。", "玉歷已開新歲日，璿璣猶數去年星。", "風流豈遂同烏府，香火還來共水廳。", "漸老莫驚頭欲白，公名久已在丹青。"]'),
('6f7e4928-7e0b-4d35-92b0-0f75c3052545','楊浩然見寄因次其韵','彭汝礪','宋','宋诗','song-poetry','','[]','百年流轉笑浮生，憂思隨時苦未寧。',64,'全唐诗/poet.song.51000.json','["百年流轉笑浮生，憂思隨時苦未寧。", "心膽愛君長似水，鬢毛如我欲垂星。", "春風半夜燒燈院，臘雪窮年祭酒廳。", "夢寐舊游如昔日，可憐庭柏自青青。"]'),
('b90374ae-6770-4c57-9844-6f0ed4436b4e','和大名掾舍弟君時','彭汝礪','宋','宋诗','song-poetry','','[]','大名書到慰離憂，南北還嗟各宦游。',64,'全唐诗/poet.song.51000.json','["大名書到慰離憂，南北還嗟各宦游。", "任責踰涯吾不樂，食功隨分汝何羞。", "客塵汎汎常時味，河水渾渾一片愁。", "綵服欲歸今未可，遙將心寄日邊州。"]'),
('fabf8239-3885-4fd2-b6e8-b989f79f3eeb','和莘老城東齋祠  其一','彭汝礪','宋','宋诗','song-poetry','','[]','鬰鬰葱葱佳氣中，曉天春霧濕濛濛。',64,'全唐诗/poet.song.51000.json','["鬰鬰葱葱佳氣中，曉天春霧濕濛濛。", "山川更洗崇朝雨，草木還催二月風。", "樂國地開金色界，容臺人在水晶宮。", "長年飽食知無補，尚有私誠祝屢豐。"]'),
('daa29cbc-d8c1-49a3-8d30-87c5bf329231','和莘老城東齋祠  其二','彭汝礪','宋','宋诗','song-poetry','','[]','天上春來今幾時，園林已自足光輝。',64,'全唐诗/poet.song.51000.json','["天上春來今幾時，園林已自足光輝。", "桃心欲放輕紅出，柳眼初分嫩綠歸。", "解凍暖風吹浩蕩，養花新雨落霏微。", "知君準擬多行樂，佳句何妨及繡衣。"]'),
('a421e505-74b3-4404-93e2-aa05189c850d','急雨','彭汝礪','宋','宋诗','song-poetry','','[]','遠岫低連野水蒼，田溪急似雨淋浪。',64,'全唐诗/poet.song.51000.json','["遠岫低連野水蒼，田溪急似雨淋浪。", "靈壇冉冉雲烟凈，小徑深深花草香。", "落日客帆千點細，秋風漁笛一聲長。", "詩成未解酬真賞，追逐須將夙願償。"]'),
('5010f271-f689-471d-95c0-0227db5853c1','山堂','彭汝礪','宋','宋诗','song-poetry','','[]','江湖曲曲抱千峰，堂在山光水色中。',64,'全唐诗/poet.song.51000.json','["江湖曲曲抱千峰，堂在山光水色中。", "雲薄祇疑蓬島近，湖深遙覺海門通。", "扁舟蓴菜知無限，促席榴花定不空。", "獨倚欄干西北望，子牟此興亦無窮。"]'),
('4a18fd03-8bc1-441e-b19f-a311f8c34bd3','望雲臺','彭汝礪','宋','宋诗','song-poetry','','[]','欲望都門春正深，高臺孤絕更登臨。',64,'全唐诗/poet.song.51000.json','["欲望都門春正深，高臺孤絕更登臨。", "空雲靄靄生歸思，鳴雁雝雝多好音。", "華蓋熒煌天半際，瀛洲縹緲海中心。", "江天抱病頻搔首，自笑紛紛雪已侵。"]'),
('d68b47dc-9cef-40aa-a744-5e77757c1214','鬰孤臺','彭汝礪','宋','宋诗','song-poetry','','[]','江城塵土日喧喧，中有蒼然一點山。',64,'全唐诗/poet.song.51000.json','["江城塵土日喧喧，中有蒼然一點山。", "日暖蜃樓浮海上，花深蓬島在人間。", "晴雲鶴鶴千峰遠，碧瓦鱗鱗萬屋環。", "却望鍾陵何處所，客心先與水東還。"]'),
('94660fa2-7a24-4704-836d-e02edf9ed4c7','離贛上','彭汝礪','宋','宋诗','song-poetry','','[]','昨夜水生三尺來，匆匆相送若相催。',64,'全唐诗/poet.song.51000.json','["昨夜水生三尺來，匆匆相送若相催。", "大聲振地潜魚躍，白浪粘天高岸摧。", "宿雨未收雲靄靄，春鷗無數雪皚皚。", "問奴新釀猶餘否，爲我臨溪開一盃。"]'),
('84b88e77-c744-4d10-91db-16f82ed996d3','送正夫之鄆','彭汝礪','宋','宋诗','song-poetry','','[]','清河如練月如霜，六月舟行亦自凉。',64,'全唐诗/poet.song.51000.json','["清河如練月如霜，六月舟行亦自凉。", "驄馬何爲輕去國，錦衣不害數還鄉。", "高才落落邦之傑，令問洋洋民所望。", "城上望公公更遠，人間今日日何長。"]'),
('3fce213e-ceb4-4a75-9235-6cf691878831','答趙正夫','彭汝礪','宋','宋诗','song-poetry','','[]','風波久與故人違，臨水登山百爾思。',64,'全唐诗/poet.song.51000.json','["風波久與故人違，臨水登山百爾思。", "世事易令人苟簡，年華稍恨我衰遲。", "尚遷喬木出幽谷，忍舍靈龜觀朵頤。", "魚雁不應嫌寂寞，時將一字寄天涯。"]'),
('d72c8dd0-f8af-494a-829d-6d6781ddf79a','以去年詩再答正夫','彭汝礪','宋','宋诗','song-poetry','','[]','不願與公終食違，別離草草不勝思。',64,'全唐诗/poet.song.51000.json','["不願與公終食違，別離草草不勝思。", "老便靜處溪山好，懶見閑中日月遲。", "論易朱雲折其角，說詩匡鼎解人頤。", "歲云暮矣來何晚，倚杖相望一水涯。"]'),
('155f3067-4281-4420-afbf-4543b785323c','飲君宜弟所寄緇衣酒繼得書因成小詩奉寄','彭汝礪','宋','宋诗','song-poetry','','[]','少年離別似尋常，老大別離多感傷。',64,'全唐诗/poet.song.51000.json','["少年離別似尋常，老大別離多感傷。", "飲酒看雲心散漫，開書對雨淚淋浪。", "棣棠密織花成錦，鴻雁斜書字作行。", "未到與人貪富貴，會須同汝老耕桑。"]'),
('6e843214-e9f6-492b-a21a-d6256f8d859f','寄君時學正弟','彭汝礪','宋','宋诗','song-poetry','','[]','亦與兒童酌酒醪，焚香頌祝不勝勞。',64,'全唐诗/poet.song.51000.json','["亦與兒童酌酒醪，焚香頌祝不勝勞。", "命如千載松難老，德比九疑山更高。", "頂上少時多鶴髮，眉間近日有霜毫。", "江湖復見年時雁，倚杖孤城首重搔。"]'),
('e263d8d1-a111-41ad-834d-922bd167c0c7','敏叔家會仙洞','彭汝礪','宋','宋诗','song-poetry','','[]','大松十里建旌麾，曉日朝霞五色衣。',64,'全唐诗/poet.song.51000.json','["大松十里建旌麾，曉日朝霞五色衣。", "幽谷靜聞猿一嘯，白雲時見鶴雙飛。", "花開洞府春長在，人會瀛洲夜未歸。", "家近武陵時入夢，詩成更憶故山薇。"]'),
('8b260ae1-b8ea-4af5-ad59-91f84734d0ee','答周考功惠黄絲棕心席玉面界方','彭汝礪','宋','宋诗','song-poetry','','[]','老年離別欲心折，不似舊時少年時。',64,'全唐诗/poet.song.51000.json','["老年離別欲心折，不似舊時少年時。", "人世匆忙疑是夢，鬢毛感慨欲成絲。", "剛嚴碧玉方無玷，潤澤黄絲席有儀。", "觀物似公長在眼，祝公千歲比靈龜。"]'),
('0d360777-ca79-4b70-ba97-7e25851740d6','和通判章承議  其一','彭汝礪','宋','宋诗','song-poetry','','[]','决勝從容樽俎間，一軍爭死不知還。',64,'全唐诗/poet.song.51000.json','["决勝從容樽俎間，一軍爭死不知還。", "拔旗往蹈烏丸壘，杖箠橫封函谷關。", "畫像麒麟天上閣，銘功雞鹿雪中山。", "我榮不與諸公比，歸見慈親一解顔。"]'),
('01c49ba2-ef0a-4a84-a079-45a4c2c92b7b','和通判章承議  其二','彭汝礪','宋','宋诗','song-poetry','','[]','盧商舟淅兩岐間，四月軍行八月還。',64,'全唐诗/poet.song.51000.json','["盧商舟淅兩岐間，四月軍行八月還。", "龜息不妨窺道奧，鼠偷無敢近禪關。", "雲迷漢水滄浪水，雨溼蒲山岌嶪山。", "曷日與君同此樂，清言猶可慰衰顔。"]'),
('9c323ebd-a010-45a2-8a9f-0d634dd97eee','答毛提舉惠新酒雞頭依韵奉寄幸一笑','彭汝礪','宋','宋诗','song-poetry','','[]','齊鵠順風飛上天，空籠遂至扣猶全。',64,'全唐诗/poet.song.51000.json','["齊鵠順風飛上天，空籠遂至扣猶全。", "滑思琥珀千鍾滿，軟憶珠璣一樣圓。", "舉白醉攻愁自破，硫黄暖與病相便。", "南歸幾夢凉堂會，咫尺書來更愴然。"]'),
('5c063e64-8bf4-4290-ac9c-20f18e747094','和張侍讀游蜀山','彭汝礪','宋','宋诗','song-poetry','','[]','日光拂拂已破卯，野色依依猶带秋。',64,'全唐诗/poet.song.51000.json','["日光拂拂已破卯，野色依依猶带秋。", "風卷旌旗出城曲，雲迎步履過林幽。", "欲扳懸崖訪猿鶴，更逐去鳥窮淵丘。", "脫灑塵埃坐清曠，靜窺萬物都蜉蝣。"]'),
('6fcd67c7-fd5d-48fe-ada4-0760b9f1a9dd','送熊次道因寄了元','彭汝礪','宋','宋诗','song-poetry','','[]','去入紅蓮幕，來儀振鷺庭。',72,'全唐诗/poet.song.51000.json','["去入紅蓮幕，來儀振鷺庭。", "文詞元潤澤，才力更精靈。", "須作晚成器，擬看新發硎。", "綵衣長暇日，多聚讀書螢。", "若見焦山老，相煩爲寄聲。", "別來頭上雪，添得一千莖。"]'),
('81e4f45d-82b3-42f5-b7be-db460091f8c6','寄周朝議至樂堂  其一','彭汝礪','宋','宋诗','song-poetry','','[]','賞花載酒百花洲，看雪開筵白雪樓。',64,'全唐诗/poet.song.51000.json','["賞花載酒百花洲，看雪開筵白雪樓。", "不盡山川長在目，忘機鷗鳥自隨舟。", "當時一笑有餘味，今日相思翻百憂。", "聞說作堂名至樂，幾時還得與公遊。"]'),
('98f25601-c96c-4116-b1be-e01d2e8466a5','寄周朝議至樂堂  其二','彭汝礪','宋','宋诗','song-poetry','','[]','世味中人醉不醒，公歸正似解人酲。',64,'全唐诗/poet.song.51000.json','["世味中人醉不醒，公歸正似解人酲。", "歸雲意思閑方見，瘦鶴精神老更清。", "但與堯民時擊壤，何須秦女會吹笙。", "淵明已有歸來賦，沮溺應容作耦耕。"]'),
('b22ebd1d-e562-4aa8-97af-bc520510b847','和鄒漢廣見寄','彭汝礪','宋','宋诗','song-poetry','','[]','征旆飛飛度夕陽，畫橈隠隠照溪光。',64,'全唐诗/poet.song.51000.json','["征旆飛飛度夕陽，畫橈隠隠照溪光。", "白雲點綴千峰綠，青女摧殘萬葉黄。", "林外小花留蛺蝶，岸邊深藻宿鴛鴦。", "滄浪可愛須沉醉，詩老無疑緩報章。"]'),
('0f8a0b79-04f3-49c9-8830-7d0e9852cd29','濟叔潤之兄弟見送出小渡','彭汝礪','宋','宋诗','song-poetry','','[]','欲寄窮通逐水漚，共君歌舞醉新秋。',64,'全唐诗/poet.song.51000.json','["欲寄窮通逐水漚，共君歌舞醉新秋。", "詩辭可愛題黄葉，別意難忘寄綠洲。", "雨過微風催去棹，夜凉明月滿歸舟。", "又隨天外一飛鵠，可羨波前雙白鷗。"]'),
('3bf846a2-8bf8-4479-b59d-35f2b046f918','晚晴','彭汝礪','宋','宋诗','song-poetry','','[]','萬里無雲雨意醒，江湖滿載夕陽明。',64,'全唐诗/poet.song.51000.json','["萬里無雲雨意醒，江湖滿載夕陽明。", "老翁暮釣扁舟去，稚子歸樵一笛橫。", "溪月悠悠含夜意，林風細細作秋聲。", "詩魂散落無羈束，試效樊川賦晚晴。"]'),
('5134fbcf-85ad-4920-b07a-4d192c9d990a','山游','彭汝礪','宋','宋诗','song-poetry','','[]','試拂塵衣訪遠蹤，詩魂獨與賞心同。',64,'全唐诗/poet.song.51000.json','["試拂塵衣訪遠蹤，詩魂獨與賞心同。", "低低弱柳啼秋雨，細細寒螿嘯晚風。", "岩石溪流相照綠，草花楓葉一般紅。", "玉琴寫盡逍遙意，疑到蓬瀛島嶼中。"]'),
('e1ee4cd3-302a-48ab-8df1-ca351d1316b5','過嶺上','彭汝礪','宋','宋诗','song-poetry','','[]','山幽漸失塵埃路，勢險方知造物功。',64,'全唐诗/poet.song.51000.json','["山幽漸失塵埃路，勢險方知造物功。", "岩溜飛光動天上，樵斤遺響落雲中。", "烟迷曲島千峰細，日轉寰區萬里空。", "安得謫仙來並此，醉浮風馭過蟾宮。"]'),
('202b18cf-74ce-4ccb-a786-f213a5a7fc68','將寄豫章以詩先寄文淵秘校','彭汝礪','宋','宋诗','song-poetry','','[]','已傳靈耗煩晨鵲，更作新詩寄塞鴻。',64,'全唐诗/poet.song.51000.json','["已傳靈耗煩晨鵲，更作新詩寄塞鴻。", "千里薄寒沾暮雨，百壺清笑望秋風。", "仙人樓閣重湖外，帝子亭臺翠靄中。", "謝傅未忘丘壑意，待携歌妓醉山東。"]'),
('d382c7dc-95dd-49a8-8a48-325bd1921a7c','刑部丈寄酒因成短詩以謝','彭汝礪','宋','宋诗','song-poetry','','[]','玉壺寄酒來三島，蓬鬢持盃學八仙。',64,'全唐诗/poet.song.51000.json','["玉壺寄酒來三島，蓬鬢持盃學八仙。", "詩句剪裁揮翰墨，賞心飛舞度林泉。", "秋風會圃尋霜實，明月歸舟載錦鮮。", "甘倚白雲窮一醉，爲公吟盡洞中天。"]'),
('834ae1ca-b882-4d3d-90f3-8318c637ff81','徐中文赴新建以詩寄之','彭汝礪','宋','宋诗','song-poetry','','[]','童稚歡呼喜欲顛，蕩舟爭揖縣公賢。',64,'全唐诗/poet.song.51000.json','["童稚歡呼喜欲顛，蕩舟爭揖縣公賢。", "荆蒿自覺風霜逼，花木須驚雨露偏。", "天下事煩宜振領，古人材銳戒窺淵。", "君心舊得中和說，定與龔黄議後先。"]'),
('06f49f98-9376-453d-be56-06fc9ff07ad5','新建宰徐中文尉甯文淵出城見餞','彭汝礪','宋','宋诗','song-poetry','','[]','詩句飛華照彩牋，酒花浮綠動金船。',64,'全唐诗/poet.song.51000.json','["詩句飛華照彩牋，酒花浮綠動金船。", "眼看世態嗟無益，心到天真喜自然。", "盛德優容聞邵父，清才脫灑愛梅仙。", "却嗟風雨催行色，不得相從醉洞天。"]'),
('0db09d0c-4b59-4d50-9a50-0beb57053e5e','別子直','彭汝礪','宋','宋诗','song-poetry','','[]','高秋惜別苦匆匆，不得清吟日日同。',64,'全唐诗/poet.song.51000.json','["高秋惜別苦匆匆，不得清吟日日同。", "步履忽迎春色合，肺腸甘逐酒樽空。", "一舟喜逐征帆北，千里愁逢去鷁東。", "恰似江神惜離袂，夜來故作打頭風。"]'),
('15fb70f7-7b1f-4eb4-a865-34f64451390a','次韵周戶曹水軒','彭汝礪','宋','宋诗','song-poetry','','[]','新闢頹牆得小軒，未成詩思已相關。',64,'全唐诗/poet.song.51000.json','["新闢頹牆得小軒，未成詩思已相關。", "一窗嫩綠分肥水，十里澄輝接蜀山。", "近岸雨收風滿徑，暮天雲靜月當顔。", "參軍莫作塵埃嘆，今有幽虛伴若閑。"]'),
('f661459b-b83b-4d92-ba81-996af878e692','寄明甫約出餞城西既以病告遂已','彭汝礪','宋','宋诗','song-poetry','','[]','結束行裝赴早秋，愛憐交論重遲留。',64,'全唐诗/poet.song.51000.json','["結束行裝赴早秋，愛憐交論重遲留。", "罇空北海虛前約，病告東陽益別愁。", "征旆幾時歸偃月，客心一夜夢藏舟。", "塵埃日日無窮盡，能免幽人笑我不。"]'),
('908bf5a5-2ca4-4818-b737-3a5d5e4e3c90','和戶曹池亭韵','彭汝礪','宋','宋诗','song-poetry','','[]','水光苒苒上朱欄，六月軒楹起薄寒。',64,'全唐诗/poet.song.51000.json','["水光苒苒上朱欄，六月軒楹起薄寒。", "誰約醉翁同酒艇，欲尋溪叟問漁竿。", "風飄翠芰清如洗，雨裛蒼苔綠未乾。", "見說諸公游興愜，夢魂終夕爲盤桓。"]'),
('846db533-1401-4f06-adc3-ad414fbf97b5','和史司理水軒','彭汝礪','宋','宋诗','song-poetry','','[]','收拾澄虛過斷牆，軒楹從此有輝光。',64,'全唐诗/poet.song.51000.json','["收拾澄虛過斷牆，軒楹從此有輝光。", "草侵兩岸春應好，水接雙溪晚自凉。", "詩念松陵頻縱筆，會思河朔重飛觴。", "漁舟占盡江湖樂，應笑吾儕簿領忙。"]'),
('c3a031c8-063b-4ea6-80bc-82ae3354034e','次周戶曹見寄','彭汝礪','宋','宋诗','song-poetry','','[]','車馬欹危冒險艱，烟塵衰颯病容顔。',64,'全唐诗/poet.song.51000.json','["車馬欹危冒險艱，烟塵衰颯病容顔。", "游心自惜相逢晚，歸興能忘一笑閑。", "野色無涯秋苒苒，溪聲不息夜潺潺。", "而今幕府文書少，須約詩筒重往還。"]'),
('695afe6d-7f76-45a9-9ed6-8fa2b7c1f385','長嶺值風','彭汝礪','宋','宋诗','song-poetry','','[]','江上避風苦流滯，林邊步竹强遲留。',64,'全唐诗/poet.song.51000.json','["江上避風苦流滯，林邊步竹强遲留。", "山迎草色渾青黛，浪逐鷗羣盡白頭。", "垂柳絲絲縈渚岸，落花片片入溪流。", "興來却喜閭閻少，雙眼無塵事事幽。"]'),
('904fc039-7f58-44f2-972a-181d68f7bad1','西口值風','彭汝礪','宋','宋诗','song-poetry','','[]','逐處烟嵐照水村，誰家草色接衡門。',64,'全唐诗/poet.song.51000.json','["逐處烟嵐照水村，誰家草色接衡門。", "山藏曲圃非塵路，花滿幽蹊似故園。", "海燕鬭風輕笑語，林鶑带雨巧飛翻。", "天時似有清明意，自作新歌慰旅魂。"]'),
('460d9ad3-3feb-48b9-9a20-1fd5d52662d3','和廣漢旅中韵','彭汝礪','宋','宋诗','song-poetry','','[]','苒苒征衣冒曉霜，客心衰寂鬢毛蒼。',64,'全唐诗/poet.song.51000.json','["苒苒征衣冒曉霜，客心衰寂鬢毛蒼。", "故人行李來江外，游子飄蓬念異鄉。", "言失筌蹄知意得，醉遺簪紱覺形忘。", "青衫四十猶羈旅，嘆息泥沙困乘黄。"]'),
('e3c3a160-3695-4439-a8a7-f6f89f591835','席上分題得長字','彭汝礪','宋','宋诗','song-poetry','','[]','肥上相逢各異鄉，笑歌猶得慰參商。',64,'全唐诗/poet.song.51000.json','["肥上相逢各異鄉，笑歌猶得慰參商。", "人心未盡文章樂，馬首還趨道路長。", "鶴髮久堙宗廟器，荷衣行覲赭袍光。", "功名自有天時在，更盡林邊酒一觴。"]'),
('cd39ee92-cb50-402d-91f3-92849fe7902c','得趙吏部所附第二書','彭汝礪','宋','宋诗','song-poetry','','[]','日月不停如轉車，匆匆還見歲其除。',64,'全唐诗/poet.song.51000.json','["日月不停如轉車，匆匆還見歲其除。", "已行沙漠數千里，纔得京華第二書。", "一讀令人喜不寐，萬金於我實何如。", "遙知日月從三友，弟勸兄酬樂只且。"]'),
('3eb040f6-ae26-4005-98c9-b10cb630a3f4','與磁倅郭公域','彭汝礪','宋','宋诗','song-poetry','','[]','熙寧天子作文功，揀點官師在學宮。',64,'全唐诗/poet.song.51000.json','["熙寧天子作文功，揀點官師在學宮。", "璧水三年嗟我拙，蘭英一笑憶君同。", "青衫昔日俱强壯，白髮今時已老翁。", "邂逅欲言渾不及，別離三四嘆西風。"]'),
('03baddf9-999b-4570-b52a-a92118080d42','元日','彭汝礪','宋','宋诗','song-poetry','','[]','玉律陰陽會，璿璣日月新。',72,'全唐诗/poet.song.51000.json','["玉律陰陽會，璿璣日月新。", "熙寧萬歲歷，元祐八千春。", "卦象已乘泰，斗杓方建寅。", "白頭諳守歲，紅燭最知春。", "柏酒人懷遠，餳盤客薦新。", "老來長道路，慚愧百年身。"]'),
('9fd022c4-1a4e-4cdd-a73c-9f92746f4fba','答相州司諫同年','彭汝礪','宋','宋诗','song-poetry','','[]','白簡風聲雨雪霜，幾回趨走並鵷行。',64,'全唐诗/poet.song.51000.json','["白簡風聲雨雪霜，幾回趨走並鵷行。", "清名久自還吾黨，治譽今尤慰所望。", "安穩慈親行小徑，光輝彩服侍華堂。", "我今不復有此樂，一讀君詩三斷腸。"]'),
('25254e4b-ffcb-44a7-aec8-30f72df4b4eb','望雲嶺飲酒','彭汝礪','宋','宋诗','song-poetry','','[]','班荆解馬面遙岑，北勸南酬喜倍尋。',64,'全唐诗/poet.song.51000.json','["班荆解馬面遙岑，北勸南酬喜倍尋。", "天色與人相似好，人情似酒一般深。", "豚魚尚可及人信，胡越何難推以心。", "立望堯雲搔短髮，不堪霜雪苦相侵。"]'),
('c9cc6432-8d88-466d-884e-41a73720c13c','北使還代書寄穎叔','彭汝礪','宋','宋诗','song-poetry','','[]','南行湖海北幽州，不見故人今幾秋。',64,'全唐诗/poet.song.51000.json','["南行湖海北幽州，不見故人今幾秋。", "萬事塵沙渾是夢，百年露電只如流。", "欲觀王儉紅蓮幕，更上庾公明月樓。", "舊說楞嚴多少義，由來祇在一毫頭。"]'),
('1195fb91-fb76-4b06-b8dd-683edf3d28f9','尚德','彭汝礪','宋','宋诗','song-poetry','','[]','萬里沙陀險且遙，雪霜塵土共蕭條。',64,'全唐诗/poet.song.51000.json','["萬里沙陀險且遙，雪霜塵土共蕭條。", "草萊長大牛羊衆，窟穴阻深豺虎驕。", "往日御夷誰似宋，今時尚德莫如堯。", "試看虞舜岩廊上，何羨呼韓渭水朝。"]'),
('a353b34a-1b21-4cfe-bdd5-49d62586159f','南歸','彭汝礪','宋','宋诗','song-poetry','','[]','匆匆燈火着征衫，客勸賓酬酒既酣。',64,'全唐诗/poet.song.51000.json','["匆匆燈火着征衫，客勸賓酬酒既酣。", "老馬經時俱首北，大鵬今日會圖南。", "擬尋樂事羞華髮，欲問生涯指舊庵。", "貪惜上恩歸未得，素餐自愧百無堪。"]'),
('53f0911c-e44b-4661-8c23-ecc0f79dd2d3','廣平甸謂虜地險至此廣大而平易云','彭汝礪','宋','宋诗','song-poetry','','[]','四更起趁廣平朝，上下沙陀道路遙。',64,'全唐诗/poet.song.51000.json','["四更起趁廣平朝，上下沙陀道路遙。", "洞入桃源花點綴，門橫葦箔草蕭條。", "時平主客文何縟，地大君臣氣已驕。", "莫善吾皇能尚德，將軍不用霍嫖姚。"]'),
('2d1b632c-1e88-4be9-a8ee-2c7fa6d60866','諸君約歸日','彭汝礪','宋','宋诗','song-poetry','','[]','黄金束带錦貂裘，白髮追隨每自羞。',64,'全唐诗/poet.song.51000.json','["黄金束带錦貂裘，白髮追隨每自羞。", "已見冰澌流碧水，遙知春色滿皇州。", "紅開金谷樓前面，綠暗玉津池上頭。", "衰病到家應稍健，爲公須醉百金甌。"]'),
('a2f3cce6-374b-4eca-bc9d-b5ecbd9e8ba1','歸期','彭汝礪','宋','宋诗','song-poetry','','[]','歸期元約是花時，曲指花時定可歸。',64,'全唐诗/poet.song.51000.json','["歸期元約是花時，曲指花時定可歸。", "日暖擁雲迎馬首，天寒飄雪點人衣。", "老胡淚落不忍別，野鵲性靈相近飛。", "到得歸時春更晚，故園桃李正芳菲。"]'),
('be5c7761-198c-43ec-99ee-c6cc7287fcee','沙陀逢正旦使副','彭汝礪','宋','宋诗','song-poetry','','[]','踏雪予今濟土河，驅車君始入沙陀。',64,'全唐诗/poet.song.51000.json','["踏雪予今濟土河，驅車君始入沙陀。", "異鄉邂逅不可得，別酒留連能幾何。", "縹緲飛鴻無限意，凋零白草不勝歌。", "到家正是花時節，酒飲休辭盃數多。"]'),
('3a2fb0bb-38ab-461a-aec6-32cdd3484548','送鄱陽太守  其一','彭汝礪','宋','宋诗','song-poetry','','[]','青春一日錦衣還，酒上親闈喜動顔。',64,'全唐诗/poet.song.51000.json','["青春一日錦衣還，酒上親闈喜動顔。", "靜視浮名雖羽翼，回瞻明德已丘山。", "身留桑梓孤衷結，目斷旌麾一淚潸。", "初仕正憂民事拙，願書餘訓起疏頑。"]'),
('6657ab49-40e5-4aef-bbbb-cf846551e90a','送鄱陽太守  其二','彭汝礪','宋','宋诗','song-poetry','','[]','朝星一夜渡寒江，千里瞻依重慨慷。',64,'全唐诗/poet.song.51000.json','["朝星一夜渡寒江，千里瞻依重慨慷。", "荆土定能碑峴首，召南安敢廢甘棠。", "遺恩未散波濤潤，令德長餘錦繡香。", "吟盡肺腸還自惜，江湖不似去思長。"]'),
('90291d70-02bf-42db-8d8c-4c3625085df0','送鄱陽太守  其三','彭汝礪','宋','宋诗','song-poetry','','[]','天明下詔寂寥濱，師帥高才得獻臣。',64,'全唐诗/poet.song.51000.json','["天明下詔寂寥濱，師帥高才得獻臣。", "事出中和民自懌，令捐苛細物長春。", "紅裙涕泣瞻征旆，白首驩呼滯去輪。", "簪紱相先問行色，幾時携節渡江瀕。"]'),
('c2779ba6-4a8e-4490-9827-8a53c4dd8e0f','和程秀才望五老峰','彭汝礪','宋','宋诗','song-poetry','','[]','憶步靈芝望翠巒，扁舟今入望中山。',64,'全唐诗/poet.song.51000.json','["憶步靈芝望翠巒，扁舟今入望中山。", "沾濡曉霧仙衣濕，點綴春苔鶴髮班。", "幽谷靜聞寒布落，重崖晴見暮雲還。", "世途正爲聲榮困，誰伴蒼顔老此間。"]'),
('52e09221-207e-4d81-ad5a-2e1b188a3c5a','和謁孝肅祠堂','彭汝礪','宋','宋诗','song-poetry','','[]','聲容不見見靈祠，眷惜徘徊重嘆咨。',64,'全唐诗/poet.song.51000.json','["聲容不見見靈祠，眷惜徘徊重嘆咨。", "樵牧萬家歌舊澤，簪紳百拜望英資。", "深圖遂失商霖遠，清論空隨海月垂。", "欲拾緒言嗟未得，風流喜讀大夫碑。"]'),
('4d25dd83-4f26-488c-bea3-def1e27c1df1','和李餘干干越亭','彭汝礪','宋','宋诗','song-poetry','','[]','溪流可到非千里，客夢相望欲十年。',64,'全唐诗/poet.song.51000.json','["溪流可到非千里，客夢相望欲十年。", "勝概昔聞遺老說，樂游今見令君賢。", "月移波影歸珠箔，風轉灘聲落綺筵。", "安得浩歌尋澗曲，獨飛綸釣醉霜天。"]'),
('2677d728-6c1a-422e-a98e-6bac07a86e16','次皇甫登興化水亭韵','彭汝礪','宋','宋诗','song-poetry','','[]','簿領終朝困蒸暑，危亭一息得微凉。',64,'全唐诗/poet.song.51000.json','["簿領終朝困蒸暑，危亭一息得微凉。", "草迷幽徑回環綠，花落滄波在處香。", "永夜鶴聲雙唳月，清秋松色自凌霜。", "平生愛樂澄虛地，一夢遲留夜未忘。"]'),
('a757dd40-8855-47a4-8ba7-fa533aace13a','同游獨山  其一','彭汝礪','宋','宋诗','song-poetry','','[]','路蹊曲曲上喬岑，風物疏疏接遠林。',64,'全唐诗/poet.song.51000.json','["路蹊曲曲上喬岑，風物疏疏接遠林。", "携妓笑無安石樂，愛山喜似晉公心。", "步尋翠石傷荆玉，行接幽岩望傅霖。", "別去幾時重會此，欲君無避酒船深。"]'),
('4f437129-aa7d-4da6-8369-d15085c525a1','同游獨山  其二','彭汝礪','宋','宋诗','song-poetry','','[]','獨山亭子山之心，萬竹相圍盡翠陰。',64,'全唐诗/poet.song.51000.json','["獨山亭子山之心，萬竹相圍盡翠陰。", "古剎地幽紅日永，懸崖人靜碧雲深。", "輕風細細無朝夕，勁節依依自古今。", "吏役幾嗟詩筆廢，興來不惜爲君吟。"]'),
('7ce8cabb-6dad-402d-9cc6-1bf251f97477','同游獨山  其三','彭汝礪','宋','宋诗','song-poetry','','[]','城樓日日望霄垠，車馬今來訪舊聞。',64,'全唐诗/poet.song.51000.json','["城樓日日望霄垠，車馬今來訪舊聞。", "寒石萬尋圍翠竹，危峰一點綴青雲。", "灑然自有林泉樂，去矣吾非鳥獸羣。", "安得畫工圖絕致，盡收蒼翠寄諸君。"]'),
('3b8521fe-04cc-4f92-9427-1bfd3bcc719e','同游獨山  其四','彭汝礪','宋','宋诗','song-poetry','','[]','相期一罇樂，共宿獨山青。',48,'全唐诗/poet.song.51000.json','["相期一罇樂，共宿獨山青。", "塵土不能污，夢魂還自醒。", "夕陽登絕徑，明月步危亭。", "爲我題僧壁，炎天此日經。"]'),
('b91c9020-205a-4085-8688-3f5c47951efa','謝公權賜蜀牋','彭汝礪','宋','宋诗','song-poetry','','[]','君得奇牋自蜀溪，緘封密密寄幽棲。',64,'全唐诗/poet.song.51000.json','["君得奇牋自蜀溪，緘封密密寄幽棲。", "香銷翠玉花枝軟，影落青雲鳳翼低。", "書橐一朝豐綺繡，詩心半夜振虹霓。", "報之重愧無瓊玖，强拾芻言細細題。"]'),
('60479a0c-3a27-41da-8abc-5cab45ff6236','次韵答劉行甫同年','彭汝礪','宋','宋诗','song-poetry','','[]','江外書來墨未乾，笑言可惜礙雲山。',64,'全唐诗/poet.song.51000.json','["江外書來墨未乾，笑言可惜礙雲山。", "字無塵蹟精神健，詩有天才態度閑。", "皓月分明生海上，仙韶容易落人間。", "夜深一夢無拘束，飛度重湖曉未還。"]'),
('e5225c32-e3fd-45bb-97b2-707e2bf24603','和張侍讀總翠亭','彭汝礪','宋','宋诗','song-poetry','','[]','城隅東北起危亭，臥棟飛簷控地形。',64,'全唐诗/poet.song.51000.json','["城隅東北起危亭，臥棟飛簷控地形。", "萬井不藏平野綠，一湖纔見遠山青。", "春歸會圃低華幄，雨歇寒蕪露翠屏。", "日暮登臨望樓闕，誤隨飛鳥下南溟。"]'),
('c783df8b-ba8d-41d9-9e47-07137a14a442','和館閣諸公游池韵','彭汝礪','宋','宋诗','song-poetry','','[]','達士超然獨若遺，賦詩行酒似兒嬉。',64,'全唐诗/poet.song.51000.json','["達士超然獨若遺，賦詩行酒似兒嬉。", "一盃相屬非人力，四者難并異昔時。", "高柳去隨波鬭綠，啼鶑未與燕爲期。", "春晴豈但羣公樂，萬物紛紛總自私。"]'),
('7f385553-04ca-4e73-8972-5166df3d0e23','和致遠學士游池  其一','彭汝礪','宋','宋诗','song-poetry','','[]','堤外波瀾浸彩霓，花間宮殿出高枝。',64,'全唐诗/poet.song.51000.json','["堤外波瀾浸彩霓，花間宮殿出高枝。", "風高夭矯鳳飛去，雨止蜿蜒龍倒垂。", "早晚烟霞相間雜，浮沉魚鳥並游嬉。", "文王臺沼羣賢至，不比山陰祓禊時。"]'),
('0a89671b-3516-44b7-af84-e86d269bda94','和致遠學士游池  其二','彭汝礪','宋','宋诗','song-poetry','','[]','岸岸垂楊障綠陰，時時好鳥囀清音。',64,'全唐诗/poet.song.51000.json','["岸岸垂楊障綠陰，時時好鳥囀清音。", "昭回河漢波瀾闊，方丈蓬萊雨露深。", "到處香烟濃作霧，誰家珠翠密成林。", "爭標想見千人唱，聲入青雲畫鼓深。"]'),
('f36d2cb3-7a64-4edf-b8b0-5ce0755132a0','送程給事并次中丞雜端韵','彭汝礪','宋','宋诗','song-poetry','','[]','公去江淮今幾年，歡謠今日尚紛然。',64,'全唐诗/poet.song.51000.json','["公去江淮今幾年，歡謠今日尚紛然。", "恩榮復擁千兵出，課最應當一路先。", "詩字細題幽寺竹，酒卮深泛碧池蓮。", "風流會續蘭亭盛，幕府能無竇鞏賢。"]'),
('8330d31a-50d4-457b-b413-b9c64f188d51','持正率和中丞諸公喜雨詩二首用前韵','彭汝礪','宋','宋诗','song-poetry','','[]','滂沱自足慰民憂，更洗甌閩四五州。',64,'全唐诗/poet.song.51000.json','["滂沱自足慰民憂，更洗甌閩四五州。", "風入遠林驚海坼，水吞平陸看川流。", "禾麻嶷嶷私時澤，魚鳥欣欣愜所求。", "凉簟飽眠吾亦樂，靜窺槐葉擬開秋。"]'),
('189f8007-d227-40b7-a779-502b5a8cdd5b','次中丞韵','彭汝礪','宋','宋诗','song-poetry','','[]','人家碧瓦照朱丹，縹緲烟濤密瑣關。',64,'全唐诗/poet.song.51000.json','["人家碧瓦照朱丹，縹緲烟濤密瑣關。", "一水北鄰千里海，萬峰南揖四明山。", "鳥啼浮世塵埃外，人在青雲道路間。", "祇恐公歸難久駐，匆匆便捧詔書還。"]'),
('79aeaca8-f072-461e-8857-86c3fa2ec681','次雜端韵','彭汝礪','宋','宋诗','song-poetry','','[]','畫舫參差看欲飛，紛紛車馬壓塵泥。',64,'全唐诗/poet.song.51000.json','["畫舫參差看欲飛，紛紛車馬壓塵泥。", "右軍筆墨空蘭渚，安道風流訪剡溪。", "白首得時歸莫遽，丹心懷國去猶稽。", "月明會醉蓬萊閣，應笑雲霄自有梯。"]'),
('8b9ecb3c-7d95-4c36-8988-8d0d6b960df8','持正率和諸太一宮詩','彭汝礪','宋','宋诗','song-poetry','','[]','上方憂樂共元元，祠宇知非泥故言。',128,'全唐诗/poet.song.51000.json','["上方憂樂共元元，祠宇知非泥故言。", "真室轉臨雙闕近，清壇還拱五神尊。", "光輝散燭光華旦，動植歸藏厚載坤。", "旗出荆旛威震疊，馬來龍種瑞便蕃。", "溶溶遠水浮仙島，苒苒晴霞近紫垣。", "畫像百靈朝閟宇，制名千福徧重門。", "壺中日永春長在，洞口雲深晝亦昏。", "但祝君王千萬歲，人心無以報隆恩。"]'),
('0261be19-e7dd-4022-b3a3-c5499fe6dd93','問龔深之疾往復  其一','彭汝礪','宋','宋诗','song-poetry','','[]','未識先生病所因，調料想亦費精神。',64,'全唐诗/poet.song.51000.json','["未識先生病所因，調料想亦費精神。", "無人可問維摩疾，顧我徒知管仲貧。", "未肯一經終皓首，不應千里漫思蓴。", "藤床臥對爐烟細，想岸淵明漉酒巾。"]'),
('a3c7fa90-2358-426f-8185-0472847415ad','問龔深之疾往復  其二','彭汝礪','宋','宋诗','song-poetry','','[]','居士如泡如焰身，目前應接亦非神。',64,'全唐诗/poet.song.51000.json','["居士如泡如焰身，目前應接亦非神。", "枝辭自已知吾拙，飽學誰能笑子貧。", "午飲頻來同鱠鯉，朝虀漫說欲羹蓴。", "黄昏急雨秋風溼，想見青燈一幅巾。"]'),
('fd72ce46-0308-4f68-ab65-0c2e99c88d1f','問龔深之疾往復  其三','彭汝礪','宋','宋诗','song-poetry','','[]','丈室寬閒獨病身，一經反覆足怡神。',64,'全唐诗/poet.song.51000.json','["丈室寬閒獨病身，一經反覆足怡神。", "漫從方外論空色，笑與人間共賤貧。", "菊有細花浮楚醴，魚無圓鯽煮吳蓴。", "初凉願與厭厭飲，預判荒荒月滿巾。"]'),
('bcedee6b-fffe-4e14-b528-8e44dd2a539c','和上官彥衡齋祠  其一','彭汝礪','宋','宋诗','song-poetry','','[]','廊陛紛紛響珮環，半天星月曉班班。',64,'全唐诗/poet.song.51000.json','["廊陛紛紛響珮環，半天星月曉班班。", "誤瞻宮闕星辰上，疑聽金絲闕里間。", "萬國祭祠嚴穀旦，百年文物盛賢關。", "奉常固不煩爲最，太史徒知詠仰山。"]'),
('67c2a1b3-fdaa-43ff-a6b6-7271646b7276','和上官彥衡齋祠  其二','彭汝礪','宋','宋诗','song-poetry','','[]','五更欲踏月明還，去意遲留馬亦班。',64,'全唐诗/poet.song.51000.json','["五更欲踏月明還，去意遲留馬亦班。", "棟宇參差天左界，綖旒隠約殿中間。", "簡編雅有多聞富，杖履清無一事關。", "俗狀情知煩愛惜，更容棲息道家山。"]'),
('9627d9aa-0f96-42a5-b0d6-9474ab2f1e5c','出城呈君玉都官','彭汝礪','宋','宋诗','song-poetry','','[]','天寒雨氣滿林幽，道上風塵擁布裘。',64,'全唐诗/poet.song.51000.json','["天寒雨氣滿林幽，道上風塵擁布裘。", "萬室未堪今日弊，一官敢念此生浮。", "平常素拙公家事，夙夜聊分縣尹憂。", "見說至尊方旰食，吾儕何術補涓流。"]'),
('f3207662-c6a7-4e7c-986f-0d89e3eef187','舟中暮雨','彭汝礪','宋','宋诗','song-poetry','','[]','騎馬昔由建春去，泛舟今自美豐歸。',64,'全唐诗/poet.song.51000.json','["騎馬昔由建春去，泛舟今自美豐歸。", "水中仙子紅蓮出，物外幽人白鷺飛。", "風起岸蘋寒苒苒，雨生烟谷細霏霏。", "吏情轉覺塵埃醜，嘆息滄浪屬釣磯。"]'),
('7fdc0b12-566d-4926-bb80-ca19e8af53bd','春雨','彭汝礪','宋','宋诗','song-poetry','','[]','三月江淮物正新，等閑風雨挫芳春。',64,'全唐诗/poet.song.51000.json','["三月江淮物正新，等閑風雨挫芳春。", "狂飄柳色低垂地，暗損花枝自惱人。", "壟畝千家知有望，江湖萬里喜通津。", "鴒原莫放朝華去，共約新晴醉綠茵。"]'),
('b11f1b27-4210-46ad-9781-b6a2f10671ad','漁艇寄蓮花','彭汝礪','宋','宋诗','song-poetry','','[]','鳥飛池曲冒塵埃，眼看蓮花葉葉開。',64,'全唐诗/poet.song.51000.json','["鳥飛池曲冒塵埃，眼看蓮花葉葉開。", "行李偶隨孤艇出，好風飄寄一枝來。", "雨中秀色供吟眼，風外清香入酒盃。", "半夜夢魂生枕簟，神仙無語下陽臺。"]'),
('44d255b9-b27f-4746-885d-86d6fa8d7898','驟雨','彭汝礪','宋','宋诗','song-poetry','','[]','乍喜物情爭發育，無端驟雨欲殘春。',64,'全唐诗/poet.song.51000.json','["乍喜物情爭發育，無端驟雨欲殘春。", "閻閭已負游芳意，畎畝猶滋望歲人。", "厚澤顒顒蘇品彙，微波泛泛漲江津。", "城頭便好狂吟去，草木青紅襯錦茵。"]'),
('fdab7ae1-3737-4080-b98a-780a09dbc25a','感懷','彭汝礪','宋','宋诗','song-poetry','','[]','浪計尋思直逕歸，大疏不與世情宜。',64,'全唐诗/poet.song.51000.json','["浪計尋思直逕歸，大疏不與世情宜。", "吟成白雪無人問，歌盡清風祇自知。", "是否不能尋物議，窮通渾欲付天時。", "軻雄已矣吾誰適，猶有塵編舊訓辭。"]'),
('dd69697a-db50-438a-a8b5-0b0b0a5e124b','次張德甫朔雪韵','彭汝礪','宋','宋诗','song-poetry','','[]','朔風吹雪落天涯，醉立飛樓四望賒。',64,'全唐诗/poet.song.51000.json','["朔風吹雪落天涯，醉立飛樓四望賒。", "糞壤不知涵潤澤，蒿萊無復見纖瑕。", "半宵庭檻光爭曉，窮臘園林物自花。", "誰借一舟湖北岸，月明東訪戴生家。"]'),
('e2a03183-06d1-4d32-b270-c89b390234e2','梅','彭汝礪','宋','宋诗','song-poetry','','[]','春入園林總不知，牆頭初見一梅枝。',64,'全唐诗/poet.song.51000.json','["春入園林總不知，牆頭初見一梅枝。", "朔風不挫寒冰骨，夜月偏饒白玉姿。", "密意忍容鶑蝶污，英心長與雪霜期。", "人情願得和羹實，無縱羌童把笛吹。"]'),
('5e69c8ad-a1a5-4591-8be5-06c5fada1a13','睡覺','彭汝礪','宋','宋诗','song-poetry','','[]','漏急難留一夢清，燈寒相伴寸心明。',64,'全唐诗/poet.song.51000.json','["漏急難留一夢清，燈寒相伴寸心明。", "暖薰繡被春風信，寒戰莎階夜雨聲。", "盡曉絲篁來竹幄，何時錦繡滿花城。", "病夫不稱詩魔役，愁見吟魂續續生。"]'),
('d53bd4ef-9bfa-4023-b1ee-7ceb64ff93c0','送太守舒郎中赴闕  其一','彭汝礪','宋','宋诗','song-poetry','','[]','英謀一發破昏冥，道路喁喁側耳聽。',64,'全唐诗/poet.song.51000.json','["英謀一發破昏冥，道路喁喁側耳聽。", "千里嘯歌趨雨露，百胥姦猾避雷霆。", "閭閻有讓風長暖，囹圄無塵草自青。", "朝罷雍容問民瘼，願言康樂上宸庭。"]'),
('fb632042-8cec-4415-af8f-f10895fb7167','送太守舒郎中赴闕  其二','彭汝礪','宋','宋诗','song-poetry','','[]','陋跡遲迴寂寞濱，欲聞高誼嘆無津。',64,'全唐诗/poet.song.51000.json','["陋跡遲迴寂寞濱，欲聞高誼嘆無津。", "聲華未及膺門客，揖讓猶皆蜀守民。", "白日忽收千里詔，清風長挾萬家春。", "窮途傾睠陶鈞力，吟盡肝腸一慘神。"]'),
('680560d4-caf9-4da3-93e8-c29e15f77d17','送太守舒郎中赴闕  其三','彭汝礪','宋','宋诗','song-poetry','','[]','解郡西南促去程，扁舟西下照江明。',64,'全唐诗/poet.song.51000.json','["解郡西南促去程，扁舟西下照江明。", "旌麾益近青雲路，劍佩行朝白玉京。", "勢位久淹猶郡國，光華此去即公卿。", "山林願聽功名起，野拙猶能頌治聲。"]'),
('9d953a94-9944-4313-a938-12e68843d3d9','過陶太尉廟','彭汝礪','宋','宋诗','song-poetry','','[]','劉石紛紜正憂戈，盡心收得晉山河。',64,'全唐诗/poet.song.51000.json','["劉石紛紜正憂戈，盡心收得晉山河。", "巍巍功業能如此，藉藉浮言意若何。", "風雨舊祠藏石壁，丹青遺像落江波。", "黄昏欲作溪頭釣，願丐當時壁上梭。"]'),
('27a4711c-6736-46bd-8047-2a8976752319','伯兄歸自桐江未至因有作示諸弟','彭汝礪','宋','宋诗','song-poetry','','[]','遙思徒馭去江干，道路誰何共險艱。',64,'全唐诗/poet.song.51000.json','["遙思徒馭去江干，道路誰何共險艱。", "長使庭闈終日望，不知車馬幾時還。", "佇期笑樂同塵席，應有文章慰病顔。", "酒甕半空爲收拾，筮言當見立談間。"]'),
('bf5a639e-9904-4ab8-85cc-7b71da6a9c1a','將歸寄潤之弟','彭汝礪','宋','宋诗','song-poetry','','[]','紛紛窮緒不能禁，一縷俄驚百萬尋。',64,'全唐诗/poet.song.51000.json','["紛紛窮緒不能禁，一縷俄驚百萬尋。", "風月正牽相望眼，山川難繫欲歸心。", "蕭條又作新秋意，牢落誰同永夜吟。", "車馬鼎來吾即起，夢魂先傍竹亭陰。"]'),
('1a54c81a-4427-40c9-841a-1e53895f7cdb','奉別張伯逢先生','彭汝礪','宋','宋诗','song-poetry','','[]','强鞭駑蹇逐塵蹤，百駕方成跬步功。',64,'全唐诗/poet.song.51000.json','["强鞭駑蹇逐塵蹤，百駕方成跬步功。", "天地有心成草木，蚊蠅無力負衡嵩。", "紛然又見瓜期及，晚矣猶思吾道東。", "一寸古心長自歉，依依餘恨滿西風。"]'),
('5397f2b6-1654-4fc7-b564-831c995b535e','斷編','彭汝礪','宋','宋诗','song-poetry','','[]','斷編塵簡即吾師，萬里徘徊得路遲。',64,'全唐诗/poet.song.51000.json','["斷編塵簡即吾師，萬里徘徊得路遲。", "覽照忽驚顔色古，臨空嘆息羽毛衰。", "迂愚未盡田瞿學，庸賤空收鮑叔知。", "安有微波增海曲，願因窮臘看松枝。"]'),
('5cf63d6f-39c7-4d06-8ca4-de5d7bbfd3bb','高議','彭汝礪','宋','宋诗','song-poetry','','[]','高議軒昂破麗淫，清風遺散落塵襟。',64,'全唐诗/poet.song.51000.json','["高議軒昂破麗淫，清風遺散落塵襟。", "倚山漸識浮雲意，臨水方思太古音。", "無狀欲隨仁義老，未完猶怯是非侵。", "西歸須念津塗惑，願丐中庸鏤腹心。"]'),
('2830f875-abdf-4518-a58a-8f5445d5b0e8','牢落','彭汝礪','宋','宋诗','song-poetry','','[]','牢落歸來水一隅，臥思天闕自煩紆。',64,'全唐诗/poet.song.51000.json','["牢落歸來水一隅，臥思天闕自煩紆。", "祇知今夕又明日，不覺少年成壯夫。", "禍去不虞堪太息，勢臨無備獨長吁。", "憂時未有如君老，願聽丹囊上禁塗。"]'),
('2cb65854-5b5b-4a36-9ad0-db312ec5947d','王太博自浮梁移蒙州作送之','彭汝礪','宋','宋诗','song-poetry','','[]','平時沉伏草萊間，見說昌江治政賢。',64,'全唐诗/poet.song.51000.json','["平時沉伏草萊間，見說昌江治政賢。", "愛浹羽毛人自畏，詩成金玉俗爭傳。", "一麾出守今行矣，萬室傾思正慘然。", "祇恐又膺明詔去，蒙山無計重留連。"]'),
('9aa0a5e7-c787-4ca6-8039-318c41314bc0','送周掾赴闕','彭汝礪','宋','宋诗','song-poetry','','[]','白駒一擲起塵埃，紫鳳高鶱出草萊。',64,'全唐诗/poet.song.51000.json','["白駒一擲起塵埃，紫鳳高鶱出草萊。", "盛德日隨流水遠，清聲時逐好風來。", "百年正屬文明際，萬事猶須幹濟才。", "薦牘幾多聞九極，寵章何日下三台。"]'),
('32097601-ac17-4ce2-8ca3-c00c157c5081','寄伯兄兼問子文  其一','彭汝礪','宋','宋诗','song-poetry','','[]','富貴浪圖雖汩汩，詩書餘力尚桓桓。',96,'全唐诗/poet.song.51000.json','["富貴浪圖雖汩汩，詩書餘力尚桓桓。", "聖門一室相從易，世路多岐欲合難。", "儀鳳穩依深閣宿，老蛟寒即碧溪蟠。", "青雲有侶歌魚藻，空谷無朋唱考槃。", "緣木退藏沖漢翼，扁舟歸整釣鼇竿。", "臨風願聽王陽仕，洗手思彈貢禹冠。"]'),
('9f1be453-6d53-417a-a44a-e7e9a07ecd0c','寄伯兄兼問子文  其二','彭汝礪','宋','宋诗','song-poetry','','[]','壯志當年欲請纓，孤蹤今日尚飄萍。',96,'全唐诗/poet.song.51000.json','["壯志當年欲請纓，孤蹤今日尚飄萍。", "塵埃易染羈容黑，氣義難邀俗眼青。", "馮客劍寒長自擊，伯牙弦古欲誰聽。", "風雲勇膽馳燕塞，社稷丹心望漢庭。", "思入鶺原愁四散，夢馳鶑谷涕雙零。", "客悰願託詩情見，吟盡清宵卒未醒。"]'),
('5a0c62a2-4378-4648-ae5f-388284dd7f41','送子文赴闕','彭汝礪','宋','宋诗','song-poetry','','[]','槿花時態甘相失，金玉交情喜獨親。',64,'全唐诗/poet.song.51000.json','["槿花時態甘相失，金玉交情喜獨親。", "慷慨有心探虎穴，邅迴無計附龍鱗。", "君方奮翼青冥上，我即潜舟寂寞濱。", "從事功名有餘力，勉爲書寄考槃人。"]'),
('e50b89e4-965d-4e12-ab78-fda9c6685902','寄潤之弟兼附呈伯兄  其一','彭汝礪','宋','宋诗','song-poetry','','[]','一棹孤舟接杳冥，無聊長恨別離輕。',64,'全唐诗/poet.song.51000.json','["一棹孤舟接杳冥，無聊長恨別離輕。", "利名汩汩亂人意，南北悠悠分我情。", "風觸鶺鴒寒影散，日蒙棠棣綠陰成。", "莫令澤國頻回首，時倩江鱗寄一聲。"]'),
('0be2dc90-83cb-43dc-a263-ee466da0820a','寄潤之弟兼附呈伯兄  其二','彭汝礪','宋','宋诗','song-poetry','','[]','江外如今獨轉蓬，思君不敢望飛鴻。',64,'全唐诗/poet.song.51000.json','["江外如今獨轉蓬，思君不敢望飛鴻。", "寸心引逐征雲北，孤夢爭先落葉東。", "臥病此時千里隔，微吟何日一樽同。", "却嗟逐客爲羈客，還見春風換朔風。"]'),
('d9b7621e-03eb-4d71-898e-c439104bb4a6','寄潤之弟兼附呈伯兄  其三','彭汝礪','宋','宋诗','song-poetry','','[]','風規落落已非俗，氣宇堂堂知有才。',64,'全唐诗/poet.song.51000.json','["風規落落已非俗，氣宇堂堂知有才。", "安得驊騮歸道路，不甘楩梓滯蒿萊。", "青陽路逕新萌柳，白雪林亭欲放梅。", "願逐羽翰歸故國，相從歌酒趁春來。"]'),
('109e2e28-97cb-4bd2-bc2e-0eb2616534d9','東流道遇伯兄西歸寄二篇  其一','彭汝礪','宋','宋诗','song-poetry','','[]','君棲京國我天涯，病眼相望淚滿衣。',64,'全唐诗/poet.song.51000.json','["君棲京國我天涯，病眼相望淚滿衣。", "邂逅得爲千里會，倉皇不及一言歸。", "窮通固屬時之遇，取舍猶慚議者非。", "未得寵光榮里落，久行猶足慰庭闈。"]'),
('6f6fe922-3911-4495-931f-c85c1ebfa41d','東流道遇伯兄西歸寄二篇  其二','彭汝礪','宋','宋诗','song-poetry','','[]','久雨泥塗惡，春風草木花。',48,'全唐诗/poet.song.51000.json','["久雨泥塗惡，春風草木花。", "相逢一笑樂，欲去百咨嗟。", "何日定行役，此時應到家。", "平居傾望意，汗漫正無涯。"]'),
('b4ca0dd1-691a-40bb-9276-1f6dcf881526','喜文淵登第因寄二篇  其一','彭汝礪','宋','宋诗','song-poetry','','[]','春風吹詔落天涯，喜聽君榮及盛時。',64,'全唐诗/poet.song.51000.json','["春風吹詔落天涯，喜聽君榮及盛時。", "桂籍功名知自取，雲臺事業舊相期。", "騏驎有力爭千里，燕雀無才寄一枝。", "士稚果能先越石，蘇秦應欲憤張儀。"]'),
('63b9f4d4-b2c8-4e85-a25d-dc03e05226b8','喜文淵登第因寄二篇  其二','彭汝礪','宋','宋诗','song-poetry','','[]','十年共力詩書學，萬里相期將相科。',64,'全唐诗/poet.song.51000.json','["十年共力詩書學，萬里相期將相科。", "白屋自知難掩抑，青山聊得慰蹉跎。", "寵榮未有如君早，衰病爭加若我何。", "燈下無人知此意，獨鳴寒劍一悲歌。"]'),
('cc4f6649-58af-43e8-91ac-dc75180b2675','喜擇之子文至桐江次伯兄韵','彭汝礪','宋','宋诗','song-poetry','','[]','病夫憔悴浙江邊，誰惻窮途舊橐單。',64,'全唐诗/poet.song.51000.json','["病夫憔悴浙江邊，誰惻窮途舊橐單。", "尺素不聞傾塞雁，扁舟未至望沙灘。", "羈栖久客情無頼，邂逅相逢意倍歡。", "幽夜冥冥思取火，與君同取白榆鑽。"]'),
('3e5cd20c-750e-4d4f-a4d8-96e422f87281','聞庭佐不安因馳歸','彭汝礪','宋','宋诗','song-poetry','','[]','山居傾睠舊朋儔，日落原頭望不收。',64,'全唐诗/poet.song.51000.json','["山居傾睠舊朋儔，日落原頭望不收。", "奴僕忽來傳汝病，信音不寄使人愁。", "羈懷縷縷無窮盡，歸意飛飛可滯留。", "一舍道途千里遠，那堪風雨重衣裘。"]'),
('e839f41a-01b0-40c4-a103-541240671b9b','自東流歸','彭汝礪','宋','宋诗','song-poetry','','[]','久鬰圭蓬困不勝，狂游天地眼雙明。',64,'全唐诗/poet.song.51000.json','["久鬰圭蓬困不勝，狂游天地眼雙明。", "行逢梅浦不能去，步接松林無限清。", "風雨寂寥知物意，山川崎曲見人情。", "愁悰觸物紛無寄，喜聽村壚賣酒聲。"]'),
('f858d0f6-3ea6-42d5-b5dd-d2f128131c35','東流道中作','彭汝礪','宋','宋诗','song-poetry','','[]','輕快飛輿出古城，蟠迂行徑轉沙汀。',64,'全唐诗/poet.song.51000.json','["輕快飛輿出古城，蟠迂行徑轉沙汀。", "鸕鷀映日露纁翅，鴻鵠鬭風開雪翎。", "水瘦不藏寒石綠，雲歸纔見遠峰青。", "苦憐野色溪光好，倍覺詩魂酒魄醒。"]'),
('305c885f-7bff-47b8-aecf-8b577a3647ca','喜徐景宗秀才至','彭汝礪','宋','宋诗','song-poetry','','[]','久客羈栖正無頼，故人邂逅一相逢。',64,'全唐诗/poet.song.51000.json','["久客羈栖正無頼，故人邂逅一相逢。", "紅泥綠酒方沈醉，白雪清吟未款從。", "昏翳忽收塵耳目，歡欣爭入病顔容。", "秋風且醉江山碧，莫縱離愁到客悰。"]'),
('5b6189d2-803b-44e4-be03-07114b10f94c','元祐三年同深之學士子開侍郎在初考今復承乏有懷舊游因作此詩并幕次唱酬二章寄呈深之學士子開侍郎  其一','彭汝礪','宋','宋诗','song-poetry','','[]','集英今日事，全似戊辰春。',48,'全唐诗/poet.song.51000.json','["集英今日事，全似戊辰春。", "文彩窺多士，游從憶故人。", "抗旌浮海角，艤棹即河漘。", "試作詩相寄，詩成更損神。"]'),
('614e5073-3d6f-4d6c-a555-446f7e0155d1','元祐三年同深之學士子開侍郎在初考今復承乏有懷舊游因作此詩并幕次唱酬二章寄呈深之學士子開侍郎  其二','彭汝礪','宋','宋诗','song-poetry','','[]','數燭知歸日，思家似老人。',48,'全唐诗/poet.song.51000.json','["數燭知歸日，思家似老人。", "此凡三鎖宿，今復一經旬。", "猛着棋銷日，深憑酒送春。", "蕭條雙短鬢，半夜總如銀。"]'),
('9262081d-a37b-4534-9b44-00bc299b97bc','和致遠學士韵','彭汝礪','宋','宋诗','song-poetry','','[]','落筆千人畏，揮談一坐傾。',48,'全唐诗/poet.song.51000.json','["落筆千人畏，揮談一坐傾。", "竹林冬更好，星斗夜深明。", "愛古情何遠，憂時氣未平。", "老人無見解，祇願酒頻行。"]'),
('9fde8a33-0083-4dd9-97b8-0afaee888ba5','十四弟得書承已次東流赴省試因寄小詩呈推官承務弟','彭汝礪','宋','宋诗','song-poetry','','[]','恰見蜘蛛喜，便知鴻雁來。',48,'全唐诗/poet.song.51000.json','["恰見蜘蛛喜，便知鴻雁來。", "大波窺洶湧，遙岫見崔嵬。", "懷土欲心折，拆書先眼開。", "繫舟龍化處，亭子舊名雷。"]'),
('b87a48ec-5b95-47c0-83fe-091dd0d38426','雲蓋老僧八十二','彭汝礪','宋','宋诗','song-poetry','','[]','邂逅還相見，慇懃復自陳。',48,'全唐诗/poet.song.51000.json','["邂逅還相見，慇懃復自陳。", "三千大千界，八十二年人。", "衲衣雲水舊，頭鬢雪霜新。", "手種庭前柏，如今大似身。"]'),
('c2f6aac8-9217-4279-bdec-a382eab846bb','雲居相送至下杉莊','彭汝礪','宋','宋诗','song-poetry','','[]','莫宿昏初黑，晨裝曉已分。',48,'全唐诗/poet.song.51000.json','["莫宿昏初黑，晨裝曉已分。", "雞啼江上月，犬吠嶺邊雲。", "好去龐居士，善來洪上人。", "臨行須一勘，臘後幾時春。"]'),
('a80c1c93-5bfd-4591-b80c-d901cb629c61','昨日陪深之學士飯浄因登羅漢閣期致遠不至憶山陰弟各賦一首遂寄二君','彭汝礪','宋','宋诗','song-poetry','','[]','丹鳳禁城近，青鴛寶閣開。',48,'全唐诗/poet.song.51000.json','["丹鳳禁城近，青鴛寶閣開。", "九天瞻佛日，萬國在春臺。", "東觀人何處，山陰弟未來。", "飛雲來自在，相望興悠哉。"]'),
('09c9c59d-5272-4e0b-ba5b-2dd3ffd1c956','宿金鈎','彭汝礪','宋','宋诗','song-poetry','','[]','絕域三千里，窮村五七家。',48,'全唐诗/poet.song.51000.json','["絕域三千里，窮村五七家。", "雲深無去雁，日暮有棲鴉。", "霧擁雲垂野，霜連月在沙。", "夜長無復寐，寂寞聽寒笳。"]'),
('f3727326-f8f3-41ad-a489-bcdc508e6fcb','惠州  其一','彭汝礪','宋','宋诗','song-poetry','','[]','城壘四五尺，閭閻千百家。',48,'全唐诗/poet.song.51000.json','["城壘四五尺，閭閻千百家。", "朝塵疑作雨，暮雪欲飛花。", "舊寺僧何在，空堂鬼自邪。", "三更愁不寐，相笑是皇華。"]'),
('5ba10e35-8f50-4193-9fc6-c79542ecfa87','惠州  其二','彭汝礪','宋','宋诗','song-poetry','','[]','霧暗山千疊，冰寒水一涯。',48,'全唐诗/poet.song.51000.json','["霧暗山千疊，冰寒水一涯。", "風高天作雪，日晚露迷沙。", "居士身如夢，行人驛是家。", "青燈無意緒，點點自成花。"]'),
('0751aa0e-030e-438f-a12f-581565266043','惠州  其三','彭汝礪','宋','宋诗','song-poetry','','[]','絕域冬猶暖，孤村日易斜。',48,'全唐诗/poet.song.51000.json','["絕域冬猶暖，孤村日易斜。", "浮雲點晴漢，幽鳥篆平沙。", "白草單于壘，青燈渤海家。", "夜蟾無定處，流轉共天涯。"]'),
('24ba7a3c-16ac-4064-bc12-a450288dc214','途中見接伴曰三得家書因作是詩寄候','彭汝礪','宋','宋诗','song-poetry','','[]','誰似老胡喜，一朝三得書。',48,'全唐诗/poet.song.51000.json','["誰似老胡喜，一朝三得書。", "去家長念汝，觸事獨愁予。", "水凍魚全少，天寒雁更疏。", "三冬多壅熱，安否比何如。"]'),
('7ae5f16a-e6b3-4793-afc9-54c8c9a415d8','長垣路中  其一','彭汝礪','宋','宋诗','song-poetry','','[]','欲作圖南翼，却乘之北轅。',48,'全唐诗/poet.song.51000.json','["欲作圖南翼，却乘之北轅。", "百年隨所值，萬事擬無言。", "短髮霜如白，孤心葉似丹。", "夜深何許夢，雙闕九重閽。"]'),
('db680fcb-12aa-4c64-a637-aa3d9c2ea891','長垣路中  其二','彭汝礪','宋','宋诗','song-poetry','','[]','身似水中木，險夷惟所遭。',48,'全唐诗/poet.song.51000.json','["身似水中木，險夷惟所遭。", "不堪誇拙速，可復嘆賢勞。", "雨脚三冬少，塵頭一丈高。", "故鄉何處是，南望首重搔。"]'),
('aa4d5ec7-a42b-4df4-acde-46794e2dfe25','天保弟被薦繼得子因寄是詩','彭汝礪','宋','宋诗','song-poetry','','[]','雁足書何速，燈花喜更頻。',48,'全唐诗/poet.song.51000.json','["雁足書何速，燈花喜更頻。", "桂攀天上近，珠入掌中新。", "驥種仍多子，龍標又得人。", "賀觴俱見在，留待禁城春。"]'),
('6cb2c87a-14ad-49d4-8710-1d2d9f00fefd','和瑛師','彭汝礪','宋','宋诗','song-poetry','','[]','澤國春初好，江城雨易昏。',48,'全唐诗/poet.song.51000.json','["澤國春初好，江城雨易昏。", "繫舟林下寺，步屧水邊村。", "法悅長如此，詩情剩欲論。", "歸心師莫問，一旆正翻翻。"]'),
('2eab75fa-66c4-48dd-b821-ef6346635318','和通判承議','彭汝礪','宋','宋诗','song-poetry','','[]','水邊人不到，吾與子同行。',48,'全唐诗/poet.song.51000.json','["水邊人不到，吾與子同行。", "始見游魚樂，時聞幽鳥聲。", "山如仁者靜，風是聖之清。", "擬買扁舟去，江湖老此生。"]'),
('0ba16105-1ee9-4c24-a89d-ae7e71efa6d7','南安道中','彭汝礪','宋','宋诗','song-poetry','','[]','南安窮且僻，况復阻凶饑。',48,'全唐诗/poet.song.51000.json','["南安窮且僻，况復阻凶饑。", "破屋人何在，空山鳥自歸。", "兒童多素韠，婦女祇青衣。", "好雨兆豐歲，斯民其庶幾。"]'),
('65478835-200b-40b4-bfbf-77d35a690498','癸未偕子仲都官文淵節推游東湖分題和子仲湖字韵','彭汝礪','宋','宋诗','song-poetry','','[]','泛泛林邊晚，扁舟憶五湖。',48,'全唐诗/poet.song.51000.json','["泛泛林邊晚，扁舟憶五湖。", "丹青難作賦，水墨好爲圖。", "龍蟄雲長在，霜寒草自枯。", "詩翁足幽興，瀟洒在蓬壺。"]'),
('e6c2c6e7-d6ed-402b-b0f1-3c659d342f19','和文淵同字韵','彭汝礪','宋','宋诗','song-poetry','','[]','湖上多佳致，清樽况不空。',48,'全唐诗/poet.song.51000.json','["湖上多佳致，清樽况不空。", "樂游今日並，幽思幾人同。", "苒苒芰荷雨，蕭蕭蘆葦風。", "南州人不見，流水自無窮。"]'),
('58a6dd4b-3573-4614-baef-0b10a9a92173','送甯和仲','彭汝礪','宋','宋诗','song-poetry','','[]','玉粒稻初熟，霜螯蟹正肥。',48,'全唐诗/poet.song.51000.json','["玉粒稻初熟，霜螯蟹正肥。", "薄言酌我酒，聊以送君歸。", "疊翠屏疑畫，淩空鳳欲飛。", "山前猿與鶴，最識舊征衣。"]'),
('05fb221d-f60e-4e43-8e91-e0e3be752d3d','和君宜弟詩韵蘄州所寄','彭汝礪','宋','宋诗','song-poetry','','[]','棠棣花開處，衡陽雁去時。',48,'全唐诗/poet.song.51000.json','["棠棣花開處，衡陽雁去時。", "封題開遠信，涕淚裛新詩。", "知道頻嗟晚，謀田更恨遲。", "去留君莫問，方寸正如絲。"]'),
('84e8e30f-d07c-40c5-85c1-147989a53655','有感','彭汝礪','宋','宋诗','song-poetry','','[]','往復何爲者，功名安在哉。',48,'全唐诗/poet.song.51000.json','["往復何爲者，功名安在哉。", "茅心迷簿領，蓬鬢老塵埃。", "魚蠹生書帙，蛛絲在酒盃。", "淵明緣底事，苦死賦歸來。"]'),
('9c36df1a-0a3c-4b23-9f1f-834a6664b1ca','溪上','彭汝礪','宋','宋诗','song-poetry','','[]','濯髮溪頭水，披衣林際風。',48,'全唐诗/poet.song.51000.json','["濯髮溪頭水，披衣林際風。", "低枝折楊柳，高葉蔭梧桐。", "魚躍浮萍上，鳥啼幽谷中。", "清凉仍各有，彼此一無窮。"]'),
('e6a558c3-f074-44c9-9263-12f4df31c31b','君宜得種茶詩予和韵','彭汝礪','宋','宋诗','song-poetry','','[]','始傍東園種，初從北苑移。',48,'全唐诗/poet.song.51000.json','["始傍東園種，初從北苑移。", "本根原自好，造化總無私。", "紫笋時名誤，烏程舊種卑。", "酪奴吾不問，酒聖爾何爲。"]'),
('738aca9b-95b2-4b51-9330-ebcccc3859a8','病中','彭汝礪','宋','宋诗','song-poetry','','[]','富貴來何晚，窮愁固有餘。',48,'全唐诗/poet.song.51000.json','["富貴來何晚，窮愁固有餘。", "病多皇甫謐，貧甚馬相如。", "思亂詩魂散，憂深酒興疏。", "此心無可奈，徒爾重欷歔。"]'),
('1f80b59d-561a-4fae-b722-fcb53f008714','病起','彭汝礪','宋','宋诗','song-poetry','','[]','失意憂多病，予今喜少痊。',48,'全唐诗/poet.song.51000.json','["失意憂多病，予今喜少痊。", "寢興今泰矣，容質尚蒼然。", "鬰抑丹心塞，紛紜萬慮闐。", "此情無可奈，整頓頼詩篇。"]'),
('7a70a524-bd55-464c-a0b6-49c23227c472','醉極有感','彭汝礪','宋','宋诗','song-poetry','','[]','飲極人之樂，余心反自傷。',48,'全唐诗/poet.song.51000.json','["飲極人之樂，余心反自傷。", "氣因人憤激，情與酒飛颺。", "淚落侵雙鬢，愁多鬰寸腸。", "空贏山簡醉，不似樂天狂。"]'),
('8251083f-24ae-4b4d-9618-cd5004cb180d','小徑','彭汝礪','宋','宋诗','song-poetry','','[]','南北通官道，東西隘亂山。',48,'全唐诗/poet.song.51000.json','["南北通官道，東西隘亂山。", "無時輪迹道，經雨蘚痕斑。", "世路同欹側，人心共險艱。", "亟由平易去，寧苦險巇間。"]'),
('d3a9db15-4aa3-4079-9e3e-a3b811bdee92','日暮','彭汝礪','宋','宋诗','song-poetry','','[]','人去紅塵息，林幽晚意清。',48,'全唐诗/poet.song.51000.json','["人去紅塵息，林幽晚意清。", "秋陽紅旆亂，夕靄翠紳橫。", "新月淡無色，微風寒有聲。", "此吟猶未竟，城吏已嚴更。"]'),
('9d2f3083-5272-44c5-973f-e8da381ae51a','嘆交','彭汝礪','宋','宋诗','song-poetry','','[]','兒童不可近，况復與之親。',48,'全唐诗/poet.song.51000.json','["兒童不可近，况復與之親。", "薤露不終刻，松風知幾春。", "嚬嚬徒滿目，切切竟何人。", "誦罷鶑鳴詠，空餘涕滿巾。"]'),
('c33412e1-3d29-4e20-80e8-2bbe351c59a8','陳秀才擴因旬休不至以詩呼之','彭汝礪','宋','宋诗','song-poetry','','[]','寂寂碧窗下，業同詩酒歡。',48,'全唐诗/poet.song.51000.json','["寂寂碧窗下，業同詩酒歡。", "暌違纔一日，恨悵已千端。", "無忽離羣異，須矜會友難。", "相望正展轉，行矣莫盤桓。"]'),
('200cbef9-d27e-4786-8344-c91969c52884','題揚州因大師小池','彭汝礪','宋','宋诗','song-poetry','','[]','闃寂黄金宇，清泠碧玉池。',48,'全唐诗/poet.song.51000.json','["闃寂黄金宇，清泠碧玉池。", "軒楹收冷淡，松竹讓幽奇。", "岸蹙源流淺，山陰月到遲。", "未能活魚鱉，安可臥蛟螭。"]'),
('a1a16cd0-e4c4-4be0-b8cd-ac1ddffd2374','題袁州紫翠軒','彭汝礪','宋','宋诗','song-poetry','','[]','黯淡襟橫野，迢遙面古城。',48,'全唐诗/poet.song.51000.json','["黯淡襟橫野，迢遙面古城。", "丹青難盡意，紫翠漫爲名。", "山石開新雨，溪楓照晚晴。", "杖藜饒縱目，談笑不無情。"]'),
('9042f695-fd9d-46a4-ac75-213dcf99624c','寄庭佐弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','願我今黄髮，嗟君亦白頭。',48,'全唐诗/poet.song.51000.json','["願我今黄髮，嗟君亦白頭。", "讀書少不競，從士老堪羞。", "陋巷曷其樂，首陽何所求。", "一廛如好在，聊欲與君謀。"]'),
('2038fec0-625b-4464-86b2-59aaf5d32fd3','寄庭佐弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','幸免葬魚腹，更難騎虎頭。',48,'全唐诗/poet.song.51000.json','["幸免葬魚腹，更難騎虎頭。", "少狂真忍恥，老退似包羞。", "蓬葦逕非遠，桑麻田可求。", "浮生一箭速，火急爲兄謀。"]'),
('453a6fb1-3b95-4796-866c-877f6a8294ae','江上','彭汝礪','宋','宋诗','song-poetry','','[]','柳翠蘆尤碧，楓殷蓼更紅。',48,'全唐诗/poet.song.51000.json','["柳翠蘆尤碧，楓殷蓼更紅。", "金波連夕照，玉浪起秋風。", "霄漢雙飛鳥，波瀾一釣篷。", "江湖如許景，總合付詩翁。"]'),
('485f3397-4e27-4eb9-a184-26ad68a2ed57','伏承寵示滕王閣佳句因用原韵','彭汝礪','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王帝子閣，徐孺聘君亭。',48,'全唐诗/poet.song.51000.json','["滕王帝子閣，徐孺聘君亭。", "南浦水秋漲，東湖雲晝冥。", "江山晴更碧，松檜雪逾青。", "安得泛舟去，與君同醉醒。"]'),
('4397fd1f-6ac0-446b-835f-52d8fac7d70e','送和仲','彭汝礪','宋','宋诗','song-poetry','','[]','心因行已老，事更與心違。',48,'全唐诗/poet.song.51000.json','["心因行已老，事更與心違。", "惡景多離合，浮生半是非。", "愁聞南浦雁，夢采北山薇。", "昨日見之子，問予胡不歸。"]'),
('4055683a-564c-4096-b2a5-b58b45498328','詩示庭佐弟','彭汝礪','宋','宋诗','song-poetry','','[]','世味祇如此，消憂奚所娛。',48,'全唐诗/poet.song.51000.json','["世味祇如此，消憂奚所娛。", "心煩多惡酒，眼病頓捐書。", "倦倚筇枝竹，寒圍木火爐。", "公寧機械廢，我拙笑公愚。"]'),
('5fd0b414-0c16-4126-95bb-ee0a647ca283','夜坐謹成小詩呈晦堂心老','彭汝礪','宋','宋诗','song-poetry','','[]','修鍊清徹骨，斡旋幽入神。',48,'全唐诗/poet.song.51000.json','["修鍊清徹骨，斡旋幽入神。", "寸絲縛九虎，一指掛三鈞。", "丈室夜忽旦，寒崖冬自春。", "師乎何所命，學佛亦非人。"]'),
('1cf0d194-fa20-405c-886e-1bc28572c3b8','和題真相院','彭汝礪','宋','宋诗','song-poetry','','[]','山色隨行止，溪聲滿見聞。',48,'全唐诗/poet.song.51000.json','["山色隨行止，溪聲滿見聞。", "燈花秋寂淡，香火夜氛氳。", "野色迷修竹，厨烟長白雲。", "大夫材力健，故寵寺僧懃。"]'),
('d3e49109-3b42-429c-b2e6-7c932fb30938','和題浄慈寺','彭汝礪','宋','宋诗','song-poetry','','[]','已失禪關治，空嚴古殿尊。',48,'全唐诗/poet.song.51000.json','["已失禪關治，空嚴古殿尊。", "佛香塵草莽，僧飯飽魚豚。", "萬竹藏秋色，豐碑落燒痕。", "廢興俱物鑑，誰似語公孫。"]'),
('5ce2bdc7-a7ce-43b3-a4b6-e64ceec2ae71','道中時有山水之遇因用林字韵','彭汝礪','宋','宋诗','song-poetry','','[]','我今倦塵土，邂逅得幽林。',48,'全唐诗/poet.song.51000.json','["我今倦塵土，邂逅得幽林。", "雲外千山色，溪邊萬竹陰。", "還憎俗吏態，稍快野夫心。", "世事非樽酒，天寒不自禁。"]'),
('3d8ce706-2d2b-467d-ab1c-42e9ed7cb6e1','寄公權','彭汝礪','宋','宋诗','song-poetry','','[]','靈源起幽谷，蕭灑與秋宜。',48,'全唐诗/poet.song.51000.json','["靈源起幽谷，蕭灑與秋宜。", "世事有窮處，泉聲無盡時。", "流沾一山足，澤入萬田滋。", "祇恐明朝別，清風到夢思。"]'),
('f9730c1f-a1f8-4733-a191-013a4128df9e','欲雨','彭汝礪','宋','宋诗','song-poetry','','[]','車馬冒蒸暑，道途傷久晴。',48,'全唐诗/poet.song.51000.json','["車馬冒蒸暑，道途傷久晴。", "雲生蜀山靜，風度遠秋清。", "白蟻紛紛鬭，鳲鳩在在鳴。", "微陰知雨意，失意問農耕。"]'),
('e5439e3c-c458-49e4-8185-f1e42c438d3b','薄荷','彭汝礪','宋','宋诗','song-poetry','','[]','神農取辛苦，病客愛清新。',48,'全唐诗/poet.song.51000.json','["神農取辛苦，病客愛清新。", "寂淡花無色，虛凉藥有神。", "煩心侵冰雪，眩目失埃塵。", "自是芝蘭臭，非同草木春。"]'),
('654264ac-7935-40d9-b118-99fae3cac027','寄鄒秘丞同赴京師','彭汝礪','宋','宋诗','song-poetry','','[]','馬上梅曾賦，林邊酒記賒。',48,'全唐诗/poet.song.51000.json','["馬上梅曾賦，林邊酒記賒。", "乾坤新帝業，山野舊人家。", "自昔餘篇翰，經年五歲華。", "詩成無雁寄，一夢入天涯。"]'),
('ab8449f9-4186-43d6-986f-91354467a217','春秋成字韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','鳳鳥知何處，麟經卒告成。',48,'全唐诗/poet.song.51000.json','["鳳鳥知何處，麟經卒告成。", "人人無義戰，歲歲有王正。", "秦楚空强力，桓文漫主盟。", "是非微旨在，終始願深明。"]'),
('a446afb8-bafd-4818-b6c9-74e3361e39e7','春秋成字韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','法爲衰周起，文因舊史成。',48,'全唐诗/poet.song.51000.json','["法爲衰周起，文因舊史成。", "有權皆反正，無事亦書正。", "泣血葵丘會，傷心首止盟。", "三家自螢爝，未助太陽明。"]'),
('54b6716a-d380-4c07-a37d-1edbb13c9dfd','春秋成字韵  其三','彭汝礪','宋','宋诗','song-poetry','','[]','聖念周邦弱，經因魯史成。',48,'全唐诗/poet.song.51000.json','["聖念周邦弱，經因魯史成。", "尊王常謹始，罪隠不書正。", "弗義嗟頻戰，無常嘆屢盟。", "幽微今煥若，寧復比丘明。"]'),
('eb15c4fc-645e-455d-ab24-6e1df624ca40','春秋成字韵  其四','彭汝礪','宋','宋诗','song-poetry','','[]','賞罰陵遲久，春秋筆削成。',48,'全唐诗/poet.song.51000.json','["賞罰陵遲久，春秋筆削成。", "稱人譏楚僭，書月謹周正。", "國國强并弱，時時會復盟。", "前賢褒貶在，一覽是非明。"]'),
('77aa71f3-3715-43ac-a499-3874e7e77e20','和深父傷字韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','鄭棄非人棄，梁亡只自亡。',48,'全唐诗/poet.song.51000.json','["鄭棄非人棄，梁亡只自亡。", "危機交弊弱，血刃第爭强。", "恃力雖千國，推尊獨一王。", "衰微今已往，掩卷益增傷。"]'),
('243e78c9-2632-42c7-b156-189e709d2c99','和深父傷字韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','前史權衡在，當時法度亡。',48,'全唐诗/poet.song.51000.json','["前史權衡在，當時法度亡。", "力扶周室弱，深抑楚人强。", "言戰嗟無義，書元示有王。", "細推褒貶意，掩卷一悲傷。"]'),
('1afa529c-c54f-4922-90ef-c1984e19cdcb','和深父傷字韵  其三','彭汝礪','宋','宋诗','song-poetry','','[]','戰伐周綱替，春秋捄已亡。',48,'全唐诗/poet.song.51000.json','["戰伐周綱替，春秋捄已亡。", "綴旒憂主弱，問鼎嘆臣强。", "蕭斧懲當世，蓍龜鑑後王。", "最憐君學苦，能爲古人傷。"]'),
('48ae0f62-17b8-4b42-84c0-a1f2a8c2eeda','和深父傷字韵  其四','彭汝礪','宋','宋诗','song-poetry','','[]','春秋二百戰，一一敘興亡。',48,'全唐诗/poet.song.51000.json','["春秋二百戰，一一敘興亡。", "書戰皆非義，稱人亦貶强。", "臨文常抑楚，謹始必尊王。", "窮究當時事，應須發感傷。"]'),
('e59cedde-20ba-46a0-af79-3d375199af11','深父學士示易詩四首某輒和韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','學易非吾敢，疲駑亦勉旃。',48,'全唐诗/poet.song.51000.json','["學易非吾敢，疲駑亦勉旃。", "冥心二篇策，皓首一韋編。", "憂患生拘羑，幾微續草玄。", "相期須畛域，慎勿泥蹄筌。"]'),
('a272c482-33d9-4d66-9166-3f5dd0585eae','深父學士示易詩四首某輒和韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','大易誠微矣，吾門敢捨旃。',48,'全唐诗/poet.song.51000.json','["大易誠微矣，吾門敢捨旃。", "文雖重舊旨，孔亦斷殘編。", "道遠爲功駿，言微蓄意玄。", "江魚如可得，朝夕自忘筌。"]'),
('bb04bf7f-735d-49bf-b8f5-ce584b3c85f5','深父學士示易詩四首某輒和韵  其三','彭汝礪','宋','宋诗','song-poetry','','[]','聖意藏羲易，人心勿捨旃。',48,'全唐诗/poet.song.51000.json','["聖意藏羲易，人心勿捨旃。", "玩爻知上古，經火嘆遺編。", "六畫功成簡，三才道亦玄。", "兄今微大過，默默識真筌。"]'),
('07ed6406-9708-4aba-b44e-d84d57e246b0','深父學士示易詩四首某輒和韵  其四','彭汝礪','宋','宋诗','song-poetry','','[]','易道更三古，愚心願勉旃。',48,'全唐诗/poet.song.51000.json','["易道更三古，愚心願勉旃。", "研幾甘白首，窮理自黄編。", "西伯爻于繇，揚雄準以玄。", "意先言象得，從此捨魚筌。"]'),
('0a436f15-b4e4-470a-89a4-30d4ee754cea','毛詩  其一','彭汝礪','宋','宋诗','song-poetry','','[]','美刺詩之奧，予今得所歸。',48,'全唐诗/poet.song.51000.json','["美刺詩之奧，予今得所歸。", "議收天地遠，心到聖賢微。", "雅頌藏興廢，蟲魚隠是非。", "篇章三百五，一一數珠璣。"]'),
('2bd0c193-33c3-48b4-a5ce-68a8d0732783','毛詩  其二','彭汝礪','宋','宋诗','song-poetry','','[]','古詩皆有托，正道豈無歸。',48,'全唐诗/poet.song.51000.json','["古詩皆有托，正道豈無歸。", "風雅收功遠，弦歌得趣微。", "王劉終少是，毛鄭亦多非。", "儒氏潜深愛，篇篇盡玉璣。"]'),
('2379cc2b-4471-4745-8ed4-66bf76d91356','毛詩  其三','彭汝礪','宋','宋诗','song-poetry','','[]','周魯詩三百，篇篇自有歸。',48,'全唐诗/poet.song.51000.json','["周魯詩三百，篇篇自有歸。", "人心散堙鬰，物意露幽微。", "原本今無復，風華比益非。", "遒人不知採，空此綴明璣。"]'),
('11462d28-ce6a-4651-9656-c9131711f8c4','和章承議通判來章','彭汝礪','宋','宋诗','song-poetry','','[]','近水班荆坐，緣山拄杖行。',48,'全唐诗/poet.song.51000.json','["近水班荆坐，緣山拄杖行。", "雲烟窺勝概，風雨聽寒聲。", "久累維摩病，多慚衛玠清。", "波瀾終未息，衮衮共勞生。"]'),
('320ae399-080d-4803-b69f-44401a1a4cab','問侗','彭汝礪','宋','宋诗','song-poetry','','[]','知現維摩病，莫淫皇甫書。',48,'全唐诗/poet.song.51000.json','["知現維摩病，莫淫皇甫書。", "去歸吾未可，調治爾何如。", "眼忌時時拭，頭便日日梳。", "首先懲忿怒，次第學呵噓。"]'),
('c5bf8563-ba02-4b2e-8167-2c7ebde705bc','雲蓋寺','彭汝礪','宋','宋诗','song-poetry','','[]','舊日蛇虺穴，今時薝蔔林。',48,'全唐诗/poet.song.51000.json','["舊日蛇虺穴，今時薝蔔林。", "寒泉三井舊，高閣五峰深。", "翠竹娟娟老，長松漠漠陰。", "鳳凰池好在，誰得老師心。"]'),
('21f706bb-41d2-476f-8f30-a3cac1d526b8','漁家','彭汝礪','宋','宋诗','song-poetry','','[]','小徑通山塢，扁舟宿釣磯。',48,'全唐诗/poet.song.51000.json','["小徑通山塢，扁舟宿釣磯。", "兒童汲水上，婦女背樵歸。", "臘月魚蝦足，豐年雞鴨肥。", "是非人世事，應不到柴扉。"]'),
('44f8dcaf-60f8-4f31-857d-78082b3e63b7','道中','彭汝礪','宋','宋诗','song-poetry','','[]','湖天冬不雪，山地晚多風。',48,'全唐诗/poet.song.51000.json','["湖天冬不雪，山地晚多風。", "岸草猶全綠，村花或自紅。", "差池歲聿暮，寂寞雨其濛。", "南北隨蓬轉，浮生旅寓中。"]'),
('ccdcefb9-6777-4779-a5a0-badd0302e81f','馬上讀書寄君時  其一','彭汝礪','宋','宋诗','song-poetry','','[]','夜秣駸駸馬，晨脂繹繹車。',48,'全唐诗/poet.song.51000.json','["夜秣駸駸馬，晨脂繹繹車。", "更行猶挾策，漸老欲捐書。", "漫意窺原委，非工辨魯魚。", "相知今亦少，舍汝更誰歟。"]'),
('94d2c616-53ef-4f75-ae5a-ac4a6cf1d3c0','馬上讀書寄君時  其二','彭汝礪','宋','宋诗','song-poetry','','[]','獨自鞭駑馬，誰何惜後車。',48,'全唐诗/poet.song.51000.json','["獨自鞭駑馬，誰何惜後車。", "浮雲看富貴，陳迹泥詩書。", "畫虎豈類狗，忘筌在得魚。", "田園須稍葺，吾與汝歸歟。"]'),
('2f8bb3d6-d791-44da-9714-374e5f7d8418','某聞老母到葉未得平安家書作小詩寄君時弟','彭汝礪','宋','宋诗','song-poetry','','[]','慈闈聞及葉，坐待到天明。',48,'全唐诗/poet.song.51000.json','["慈闈聞及葉，坐待到天明。", "望月魂先往，聞更夢不成。", "花開燈有信，書少雁無情。", "欲往終多畏，遲留嘆此生。"]'),
('6009f405-a25a-4bf7-a4a8-851bb9d65f9d','和念一弟詩韵','彭汝礪','宋','宋诗','song-poetry','','[]','事如車轉軸，日夜不曾周。',48,'全唐诗/poet.song.51000.json','["事如車轉軸，日夜不曾周。", "固各有分定，疑皆非本謀。", "能鳴君似雁，不繫我爲舟。", "擾擾膠膠者，憐渠不自由。"]'),
('21b32665-00f5-4235-af5d-52ea151fec73','內鄉招提寺','彭汝礪','宋','宋诗','song-poetry','','[]','淫雨宿蕭寺，白雲思楚山。',48,'全唐诗/poet.song.51000.json','["淫雨宿蕭寺，白雲思楚山。", "病催顔色老，淚裛鬢毛斑。", "流水終何事，飛禽倦未還。", "夢歸無別處，鷲嶺鳳林關。"]'),
('771611d1-a957-4609-96aa-4bb0f7e67272','春陰呈兄長  其一','彭汝礪','宋','宋诗','song-poetry','','[]','春陰祇欲睡，世事固相尋。',48,'全唐诗/poet.song.51000.json','["春陰祇欲睡，世事固相尋。", "簿領麤官意，塵埃故國心。", "風吹花點點，雨壓柳陰陰。", "幾日城頭步，乾坤共醉吟。"]'),
('29441434-8174-48f7-82fe-70ac14d01e4f','春陰呈兄長  其二','彭汝礪','宋','宋诗','song-poetry','','[]','春容猛狼藉，暑意已侵尋。',48,'全唐诗/poet.song.51000.json','["春容猛狼藉，暑意已侵尋。", "寂寞悲時事，凄凉上客心。", "鶑飛啼野色，蝶戲落花陰。", "喜有城隅望，乘風聽苦吟。"]'),
('e5acb88e-bc03-44b7-be27-44e96fbab286','春陰呈兄長  其三','彭汝礪','宋','宋诗','song-poetry','','[]','花開初熟醉，月上夜微吟。',48,'全唐诗/poet.song.51000.json','["花開初熟醉，月上夜微吟。", "志節傷時序，詩書愛寸陰。", "未忘他日意，無用此時心。", "更約藏舟步，餘芳尚可尋。"]'),
('23ae831f-f178-462d-b2ec-6c2240403c5f','途中早起寄兄弟','彭汝礪','宋','宋诗','song-poetry','','[]','爲惜庭闈別，方驚道路難。',48,'全唐诗/poet.song.51000.json','["爲惜庭闈別，方驚道路難。", "醉憐山月古，病怯野風寒。", "駐馬詢農耜，臨溪問釣竿。", "新詩如有得，寫染寄歸翰。"]'),
('32266dbb-7d71-43e3-864f-4d72357a2125','和巖夫如字韵','彭汝礪','宋','宋诗','song-poetry','','[]','霆聲破幽鬰，雨點散空虛。',48,'全唐诗/poet.song.51000.json','["霆聲破幽鬰，雨點散空虛。", "日夕分長短，陰陽競慘舒。", "柳絲吹細細，花片落疏疏。", "試望孤城遠，江山畫不如。"]'),
('fe0b0586-3578-4eea-8ea5-8b3a965d4823','送巖夫庭佐歸寧  其一','彭汝礪','宋','宋诗','song-poetry','','[]','花滿春來路，雲歸雨後天。',48,'全唐诗/poet.song.51000.json','["花滿春來路，雲歸雨後天。", "紅塵一馬去，白日寸肝懸。", "秀色歌棠棣，歸心聽杜鵑。", "東風吹眼尾，客淚滴涓涓。"]'),
('e7fa8eb9-9d9e-41e2-86dc-a49deec669e5','送巖夫庭佐歸寧  其二','彭汝礪','宋','宋诗','song-poetry','','[]','春雨傷行色，秋風問後期。',48,'全唐诗/poet.song.51000.json','["春雨傷行色，秋風問後期。", "欲吟黄鳥意，更遺白華詩。", "客路看山色，親幃有夢思。", "遙知到家日，正好采蓴絲。"]'),
('5300aad9-9f6e-48a0-aacc-6fbece0f632d','武岡驛','彭汝礪','宋','宋诗','song-poetry','','[]','破屋山間驛，窮閻溪上村。',48,'全唐诗/poet.song.51000.json','["破屋山間驛，窮閻溪上村。", "雲山能近郭，池水故當門。", "氣象生詩筆，波瀾動酒樽。", "夜長歸夢遠，憑爾與招魂。"]'),
('674c10b1-8fd4-4948-aa78-9a68cb6303f7','驛前人家小池','彭汝礪','宋','宋诗','song-poetry','','[]','黄茅前驛路，闇淡小池園。',48,'全唐诗/poet.song.51000.json','["黄茅前驛路，闇淡小池園。", "春近花林好，日斜鳬鴨喧。", "幕雲寒苒苒，眉月夜番番。", "莫笑村居僻，誰如拙養尊。"]'),
('89d41a46-c960-4b77-a590-1f65dbda6f7d','武陽寨聞峒中作樂','彭汝礪','宋','宋诗','song-poetry','','[]','成康已措刑，文景不言兵。',48,'全唐诗/poet.song.51000.json','["成康已措刑，文景不言兵。", "夷俗家家曲，蠻歌處處聲。", "長腰筒拍鼓，細竹葫蘆笙。", "物意惟安樂，人間共一情。"]'),
('1bb24971-c42c-46b6-8b54-32b105b35b7c','武陽寨見村中梅花','彭汝礪','宋','宋诗','song-poetry','','[]','茅屋蠻溪路，梅花亦自開。',48,'全唐诗/poet.song.51000.json','["茅屋蠻溪路，梅花亦自開。", "雪深憂思遠，風靜暗香來。", "故國春何似，孤城興遠哉。", "晚風吹片片，恣意點蒼苔。"]'),
('0e5632f1-4f0a-40c7-8fc4-d149c9f36e67','寄二弟時在白彪莊  其一','彭汝礪','宋','宋诗','song-poetry','','[]','携篋戴星去，荷鋤衝雨行。',48,'全唐诗/poet.song.51000.json','["携篋戴星去，荷鋤衝雨行。", "隄防詢故老，銍艾倚新甿。", "移竹三千箇，添松一萬莖。", "但能逃凍餓，吾不慕公卿。"]'),
('b77b5da8-ab4d-4d20-9044-63d8ef8a59a3','寄二弟時在白彪莊  其二','彭汝礪','宋','宋诗','song-poetry','','[]','伊尹初耕野，兒寬自带經。',48,'全唐诗/poet.song.51000.json','["伊尹初耕野，兒寬自带經。", "故須聊假手，無或甚勞形。", "曲曲水如带，峨峨山似屏。", "夜窗吟更老，不負讀書聲。"]'),
('606366c5-5d06-42f8-ab58-21a109977a32','催君時歸并寄君宜弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','命彼僕夫駕，晨雞初一聲。',48,'全唐诗/poet.song.51000.json','["命彼僕夫駕，晨雞初一聲。", "朔風不可渡，南徑却堪行。", "貧莫甚今日，瘦無如爾兄。", "故慚魚得計，最愛雁能鳴。"]'),
('e0cfa7b8-0b48-4249-96a1-2e3bf8c90bd2','催君時歸并寄君宜弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','三復棣華賦，俛焉懷古風。',48,'全唐诗/poet.song.51000.json','["三復棣華賦，俛焉懷古風。", "少時貪壯决，老去自童蒙。", "以病故有病，既空何用空。", "不須多問此，萬劫剎那中。"]'),
('1a7921f7-1c72-4c3c-9302-46e4485bc24e','和君時弟','彭汝礪','宋','宋诗','song-poetry','','[]','老馬青驄色，扁舟畫鷁文。',48,'全唐诗/poet.song.51000.json','["老馬青驄色，扁舟畫鷁文。", "長烟橫作带，疊浪似成紋。", "北嶺夜收雨，南岡朝出雲。", "賦詩知有意，畎畝不忘君。"]'),
('bc0331b5-cf3c-4b92-a4a7-ba054fa28698','答君時弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','塤箎與鴻雁，一氣更同聲。',48,'全唐诗/poet.song.51000.json','["塤箎與鴻雁，一氣更同聲。", "鼓則與桴應，形惟從影行。", "無如我宜弟，頗笑爾難兄。", "洵美歌棠棣，仍須聽鶴鳴。"]'),
('ee5c4222-eedf-4d46-98e2-abf8c6bbcfc2','答君時弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','塤箎無俗韵，鴻雁有秋聲。',48,'全唐诗/poet.song.51000.json','["塤箎無俗韵，鴻雁有秋聲。", "更類偲偲友，非同踽踽行。", "愛無踰玉季，名有愧龍兄。", "莫作升堂賦，相期以道鳴。"]'),
('aface4a3-2d6a-434d-8c50-680f346c9d7f','答君時弟  其三','彭汝礪','宋','宋诗','song-poetry','','[]','夢覺山頭月，歸乘湖面風。',48,'全唐诗/poet.song.51000.json','["夢覺山頭月，歸乘湖面風。", "遠林寒寂寂，幽徑曉蒙蒙。", "反哺烏鳴屋，成行雁貼空。", "物情緣底事，祇欲攪予中。"]'),
('efaa56c6-68c7-4395-a9e9-5c9404d64a5d','答君時弟  其四','彭汝礪','宋','宋诗','song-poetry','','[]','是露復是電，非鈴亦非風。',48,'全唐诗/poet.song.51000.json','["是露復是電，非鈴亦非風。", "應作如是解，無爲彼所蒙。", "世累不見累，真空亦非空。", "欲知如是意，不在內外中。"]'),
('dba0b6b5-b34c-4213-8fbd-7b867173cdac','和子忠弟見寄元韵','彭汝礪','宋','宋诗','song-poetry','','[]','詩書非不樂，富貴竟何加。',48,'全唐诗/poet.song.51000.json','["詩書非不樂，富貴竟何加。", "歲月流年晚，山川行路賒。", "學須千古到，行畏一毫差。", "閫閾相期遠，寧惟效兔罝。"]'),
('a8bf09f8-0dbd-4b5c-a41f-c11a8abb576d','和運幹奉議見贈元韵','彭汝礪','宋','宋诗','song-poetry','','[]','沉碑萬山脚，騎馬習池頭。',48,'全唐诗/poet.song.51000.json','["沉碑萬山脚，騎馬習池頭。", "元凱亦過慮，山公聊自謀。", "青烟鹿門浄，黄竹鳳林秋。", "興廢不可問，登臨徒百憂。"]'),
('9e26ec54-4ec8-4b1b-b1b1-3c2bf004ba08','離武陽寨','彭汝礪','宋','宋诗','song-poetry','','[]','山谷多時雨，乾坤昨夜晴。',48,'全唐诗/poet.song.51000.json','["山谷多時雨，乾坤昨夜晴。", "經年淹壞舍，破曉出邊城。", "青女吹風急，常娥伴月明。", "人間春到久，寂寞壯心驚。"]'),
('27ba7723-e80a-4027-b04c-0c043648c4d7','和君時弟洗竹','彭汝礪','宋','宋诗','song-poetry','','[]','斬伐奚傷性，繁枝漫作陰。',48,'全唐诗/poet.song.51000.json','["斬伐奚傷性，繁枝漫作陰。", "靜留朝日暖，寒聚晚烟深。", "葉有禽栖息，根無蟻蠹侵。", "龍孫今轉盛，終待鳳凰音。"]'),
('1a230d94-0402-48a2-80e2-dd2b0eb9c3f3','和君時弟有感','彭汝礪','宋','宋诗','song-poetry','','[]','鬢髮非蓬草，秋來亦自衰。',48,'全唐诗/poet.song.51000.json','["鬢髮非蓬草，秋來亦自衰。", "簡書公迫促，歲月細推移。", "見客簪裳懶，登樓杖履遲。", "故園松菊在，歸計定何時。"]'),
('14cb20eb-ff85-4232-a7cf-dd14c46cc5bf','和君時弟生辰時八月十四日也','彭汝礪','宋','宋诗','song-poetry','','[]','月行正幾望，露潤欲爲霜。',48,'全唐诗/poet.song.51000.json','["月行正幾望，露潤欲爲霜。", "箕斗能符契，桑蓬可感傷。", "少時材獨出，老去德方將。", "看取華亭鶴，何嫌髮鬢蒼。"]'),
('5df2aa1c-bc58-4368-991d-ecf9c163237d','示君時弟刈禾有感','彭汝礪','宋','宋诗','song-poetry','','[]','終朝風且息，五日雨奚妨。',48,'全唐诗/poet.song.51000.json','["終朝風且息，五日雨奚妨。", "白嫩禾先老，黄花菊擬香。", "大夫誇作賦，公子恨無裳。", "曷日同舟去，白彪池水陽。"]'),
('fcdd1dce-e5f7-43cd-8a6c-20d04b45c2e5','示君時弟','彭汝礪','宋','宋诗','song-poetry','','[]','天寒雲不散，泱漭路猶迷。',48,'全唐诗/poet.song.51000.json','["天寒雲不散，泱漭路猶迷。", "烏雀飽棲屋，蒼鷹饑啄泥。", "樂耕莘氏媵，敬饁冀人妻。", "山色碧千仞，願同君子躋。"]'),
('394445fa-7e70-4414-afb4-0ce9381ca363','承和途中四韵','彭汝礪','宋','宋诗','song-poetry','','[]','此身俱是客，何處合爲鄉。',48,'全唐诗/poet.song.51000.json','["此身俱是客，何處合爲鄉。", "雨後春山好，天晴晝日長。", "三年穰下郡，一信赭陂陽。", "鴻雁非中澤，鳲鳩祇在桑。"]'),
('bd7cff01-7de1-43a9-8384-43e07b18e3f2','和君時寄叔韵','彭汝礪','宋','宋诗','song-poetry','','[]','屈首隨溫暖，低頭避譴呵。',48,'全唐诗/poet.song.51000.json','["屈首隨溫暖，低頭避譴呵。", "靈根無挺拔，古鑑少揩磨。", "故里三千遠，浮生四十過。", "漢江魚不少，書寄莫嫌多。"]'),
('31778e8a-3266-41ce-a13b-7db49d1f4726','和致政侍郎書懷因寄贈侍親及鄧以中使計會剗刷軍器改途先之唐因寄是詩','彭汝礪','宋','宋诗','song-poetry','','[]','霧露星軺濕，塵埃羽檄馳。',48,'全唐诗/poet.song.51000.json','["霧露星軺濕，塵埃羽檄馳。", "君王非好武，天下合防危。", "樂事難并合，浮生易別離。", "頼知春好在，五日與君期。"]'),
('1666cb61-8f43-4586-891d-91afc036ae10','桃李','彭汝礪','宋','宋诗','song-poetry','','[]','南陽多桃李，寂寞自成蹊。',48,'全唐诗/poet.song.51000.json','["南陽多桃李，寂寞自成蹊。", "白雪千林闊，紅雲一片低。", "人非劉氏子，路近武陵溪。", "故國春相似，瞻觀處處迷。"]'),
('73462a16-d5c9-41d8-8610-7a8c528291eb','老馬','彭汝礪','宋','宋诗','song-poetry','','[]','今日衰翁馬，當時御史驄。',48,'全唐诗/poet.song.51000.json','["今日衰翁馬，當時御史驄。", "少嘗更險阻，老更識西東。", "力憚馳驅遠，恩從莝秣豐。", "不應思伯樂，未便誤桓公。"]'),
('656f6c2e-aa73-486e-9bfc-0b0e2ae5c366','送和仲','彭汝礪','宋','宋诗','song-poetry','','[]','遠宦無情思，君來慰病容。',48,'全唐诗/poet.song.51000.json','["遠宦無情思，君來慰病容。", "棣華開韡韡，鳴雁去雝雝。", "天上張公子，雲間陸士龍。", "聖門多閫奧，更願與君從。"]'),
('ff563142-20cc-40c0-965d-cdbfeb7f290f','病起','彭汝礪','宋','宋诗','song-poetry','','[]','抱疾漳濱久，衰顔一倍增。',48,'全唐诗/poet.song.51000.json','["抱疾漳濱久，衰顔一倍增。", "髮疏簪不穩，足蹇杖難憑。", "身病他何欲，家貧去不能。", "世緣知不早，今日似纏藤。"]'),
('8d167690-2180-41d6-b13e-46e6d33540c4','送君時','彭汝礪','宋','宋诗','song-poetry','','[]','未曉乾坤大，能容此類蕃。',48,'全唐诗/poet.song.51000.json','["未曉乾坤大，能容此類蕃。", "連雲障飛翼，穴石聚遺根。", "籃縷誰家子，奔忙幾處村。", "焉知神聖意，饑渴念元元。"]'),
('5dc325f0-a770-4375-9ee5-58d04ee2f5ef','和君玉捕蝗雜詠  其一','彭汝礪','宋','宋诗','song-poetry','','[]','草木經春老，牛羊薄晚歸。',48,'全唐诗/poet.song.51000.json','["草木經春老，牛羊薄晚歸。", "水痕長淡薄，花片巧菲微。", "感物愁盈斛，勞形带緩圍。", "利名勞有此，今日已知非。"]'),
('8201007d-c363-4234-bce7-975646149f07','和君玉捕蝗雜詠  其二','彭汝礪','宋','宋诗','song-poetry','','[]','澤畔行蕭灑，山邊宿寂寥。',48,'全唐诗/poet.song.51000.json','["澤畔行蕭灑，山邊宿寂寥。", "烟塵牽永日，風月自澄霄。", "水旱憂千里，農桑念七條。", "君材知有待，歸夢莫迢迢。"]'),
('352286ca-dcaa-49e6-bbf4-9d427b9f9052','和君玉捕蝗雜詠  其三','彭汝礪','宋','宋诗','song-poetry','','[]','燕拂低枝出，鶑尋接葉藏。',48,'全唐诗/poet.song.51000.json','["燕拂低枝出，鶑尋接葉藏。", "地平山影薄，溪急水聲長。", "零露溼人鬢，飄風吹我裳。", "道邊花更好，還亦似河陽。"]'),
('6a4cb137-c3e6-4e84-bed1-87a32fe5490f','和君玉捕蝗雜詠  其四','彭汝礪','宋','宋诗','song-poetry','','[]','南北驅之既，東西長又多。',48,'全唐诗/poet.song.51000.json','["南北驅之既，東西長又多。", "已知蠹人力，毋亦沴天和。", "號令趨風雨，鞭笞畏網羅。", "相看愁欲死，恐未及驩歌。"]'),
('928b328d-50d1-4ab5-aa5c-9313e24c9ee8','和君玉捕蝗雜詠  其五','彭汝礪','宋','宋诗','song-poetry','','[]','馬病風塵裏，人疲簿領間。',48,'全唐诗/poet.song.51000.json','["馬病風塵裏，人疲簿領間。", "旱枯憂澤竭，汗浹怨風慳。", "時雨恩終厚，驕陽勢苦頑。", "降真香一炷，百拜望南山。"]'),
('47c216ac-2830-4075-850d-856aad690f10','小飲次幕長晦之韵并簡王路分','彭汝礪','宋','宋诗','song-poetry','','[]','小飲支風色，清言慰客襟。',48,'全唐诗/poet.song.51000.json','["小飲支風色，清言慰客襟。", "皂鵰寒獨出，雲影淡無心。", "短日催冬至，長更報夜深。", "幾時辱車轍，重約盍朋簪。"]'),
('20ec7993-3cfb-432b-a6ce-1d2e7c29362e','次德甫韵','彭汝礪','宋','宋诗','song-poetry','','[]','露染黄柑熟，霜添紫蟹肥。',48,'全唐诗/poet.song.51000.json','["露染黄柑熟，霜添紫蟹肥。", "天真俱自得，世路偶相依。", "飲數初憂病，歡成復忘歸。", "醉吟侵夜色，星月凈輝輝。"]'),
('332adc08-2009-46c4-abba-86eca57ba69c','游泰寧因登衆樂亭望仙閣賦詩得同字韵','彭汝礪','宋','宋诗','song-poetry','','[]','久雨生新水，初秋足好風。',48,'全唐诗/poet.song.51000.json','["久雨生新水，初秋足好風。", "柳枝低嫩碧，蓮萼落輕紅。", "萬室游從樂，何年締構功。", "高材終不俗，會與衆人同。"]'),
('005d7300-102c-415d-83ca-51eb6d8bdf94','和巖夫花字韵','彭汝礪','宋','宋诗','song-poetry','','[]','幽亭隔世路，高閣見天涯。',48,'全唐诗/poet.song.51000.json','["幽亭隔世路，高閣見天涯。", "綠散林邊葉，紅生水上花。", "人歸越溪藕，僧進壑源茶。", "可念詩翁物，都歸野叟家。"]'),
('cb7aa1e5-ba3d-4dab-9e39-f212696b895d','試諸葛生筆因書所懷寄諸弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','臘雪催寒盡，春風送暖微。',48,'全唐诗/poet.song.51000.json','["臘雪催寒盡，春風送暖微。", "浪爲青綬繫，愁望白雲飛。", "塵事朝朝在，鄉心夜夜歸。", "歲時如故國，憶戲老萊衣。"]'),
('0e51d896-3257-4afa-86c9-056c96897f27','試諸葛生筆因書所懷寄諸弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','塵土千鄉闊，風波一宦微。',48,'全唐诗/poet.song.51000.json','["塵土千鄉闊，風波一宦微。", "雲中鴻雁去，原上鶺鴒飛。", "終日青樓望，何時畫鷁歸。", "作詩聊自遣，還欲淚沾衣。"]'),
('82834afb-5447-4ad2-a45a-46cdf26fd8f0','試諸葛生筆因書所懷寄諸弟  其三','彭汝礪','宋','宋诗','song-poetry','','[]','後生戒輕侮，初學慎嬉游。',48,'全唐诗/poet.song.51000.json','["後生戒輕侮，初學慎嬉游。", "親膝今霜鬢，家風祇布裘。", "詩書起門戶，文字取公侯。", "十上才猶拙，知音爲汝憂。"]'),
('581a264c-33bd-4ef4-8ed0-251349776907','試諸葛生筆因書所懷寄諸弟  其四','彭汝礪','宋','宋诗','song-poetry','','[]','自別番江夜，還移楚水春。',48,'全唐诗/poet.song.51000.json','["自別番江夜，還移楚水春。", "寄聲何草草，流誨已諄諄。", "世路文章貴，人生手足親。", "杜詩賈馬賦，數數寄魚鱗。"]'),
('f8f49ab9-3abe-4bda-936d-1efc945b4a05','試諸葛生筆因書所懷寄諸弟  其五','彭汝礪','宋','宋诗','song-poetry','','[]','寄聲王與蔡，安否比何如。',48,'全唐诗/poet.song.51000.json','["寄聲王與蔡，安否比何如。", "迢遞身難接，淹延歲又除。", "顔淵一簞食，惠子五車書。", "勉就先生學，文章或起予。"]'),
('fb6a4e88-c19a-4e1f-924f-cda3019f2c46','試諸葛生筆因書所懷寄諸弟  其六','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林檜，婆娑一檻陰。',48,'全唐诗/poet.song.51000.json','["最憶東林檜，婆娑一檻陰。", "寒枝生自好，細葉長還深。", "記憶花香近，憂虞草蠹侵。", "弟兄勤愛惜，留慰百年心。"]'),
('1554b91f-4e60-4b25-9b68-a3c5ac1860fc','試諸葛生筆因書所懷寄諸弟  其七','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林竹，蕭疏入夢魂。',48,'全唐诗/poet.song.51000.json','["最憶東林竹，蕭疏入夢魂。", "秋枝餘鳳實，春逕長龍孫。", "聲轉晨風細，陰生夜月繁。", "幾時歸袂接，爛熟醉芳樽。"]'),
('69622d9c-e8ea-4e5d-9f9d-7a6c57f1d30d','試諸葛生筆因書所懷寄諸弟  其八','彭汝礪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長憶東林橘，秋深箇箇圓。',48,'全唐诗/poet.song.51000.json','["長憶東林橘，秋深箇箇圓。", "青雲衆星聚，碧海萬枝聯。", "染露光相照，經霜味十全。", "能將洞庭種，分寄楚江邊。"]'),
('daf0a488-2fa0-41ce-8a95-ca0995bd7c2c','試諸葛生筆因書所懷寄諸弟  其九','彭汝礪','宋','宋诗','song-poetry','','[]','每憶東林菊，秋風一萬枝。',48,'全唐诗/poet.song.51000.json','["每憶東林菊，秋風一萬枝。", "盡饒春卉盛，不爲曉霜衰。", "故國三年別，高朋九日期。", "籬邊自開落，熟醉負金巵。"]'),
('5a80c918-3d9c-47ff-97e6-8c0be5e01a16','試諸葛生筆因書所懷寄諸弟  其一○','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林好，真珠細細花。',48,'全唐诗/poet.song.51000.json','["最憶東林好，真珠細細花。", "滄溟分瑞色，蓬蓽見春華。", "雨壓纖枝轉，風吹小葉斜。", "化工纖巧甚，無怪世情奢。"]'),
('b7356b2c-d37e-48c3-9587-bb6262ceb4bf','試諸葛生筆因書所懷寄諸弟  其一一','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林景，占春見早梅。',48,'全唐诗/poet.song.51000.json','["最憶東林景，占春見早梅。", "仙花自瀟灑，雅思不塵埃。", "却恐隨風散，長疑带雪開。", "淮濆終少有，驛使亦能來。"]'),
('84533e92-7d45-43d6-bd98-c3f1f713f038','試諸葛生筆因書所懷寄諸弟  其一二','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林勝，花間舊種橙。',48,'全唐诗/poet.song.51000.json','["最憶東林勝，花間舊種橙。", "龍珠相照應，鵠殻未飛鳴。", "香臭先羣衆，龍光望太清。", "良庖不遐棄，亦足效和羹。"]'),
('6648b83b-ab45-47d9-9927-aea7aee852d7','試諸葛生筆因書所懷寄諸弟  其一三','彭汝礪','宋','宋诗','song-poetry','','[]','最憶東林側，花開季季同。',48,'全唐诗/poet.song.51000.json','["最憶東林側，花開季季同。", "豈無十日好，長占四時紅。", "愛玩迷光景，偏私見化工。", "可嗟桃李盛，榮落獨春風。"]'),
('b081f0c4-3091-4876-9589-36334dd43288','試諸葛生筆因書所懷寄諸弟  其一四','彭汝礪','宋','宋诗','song-poetry','','[]','鴨脚東林畔，慈親手自栽。',48,'全唐诗/poet.song.51000.json','["鴨脚東林畔，慈親手自栽。", "取心俱有實，視表獨非材。", "白玉成千粒，紅紗寄百枚。", "江南春去早，花復幾時開。"]'),
('3093d64b-e634-48d8-b26e-7089445c6aed','試諸葛生筆因書所懷寄諸弟  其一五','彭汝礪','宋','宋诗','song-poetry','','[]','棠棣東林秀，紛紛近北堂。',48,'全唐诗/poet.song.51000.json','["棠棣東林秀，紛紛近北堂。", "池荷羞葉綠，籬菊釀花黄。", "裊裊風前態，飄飄雨後香。", "讀書憶兄弟，迴首淚千行。"]'),
('cf53b2ea-fd08-49f9-b39b-9b09baf9ead1','試諸葛生筆因書所懷寄諸弟  其一六','彭汝礪','宋','宋诗','song-poetry','','[]','二月東林勝，千花貴牡丹。',48,'全唐诗/poet.song.51000.json','["二月東林勝，千花貴牡丹。", "笑迎春日暖，困怯曉風寒。", "仙子迷蓬島，貧家富綺紈。", "詠思魂欲斷，誰寄畫圖看。"]'),
('297eed19-cf13-476d-98be-b32c0e4db4bc','試諸葛生筆因書所懷寄諸弟  其一七','彭汝礪','宋','宋诗','song-poetry','','[]','榴結東林秀，維揚得此栽。',48,'全唐诗/poet.song.51000.json','["榴結東林秀，維揚得此栽。", "春風百花落，暑雨數苞開。", "轉影臨粧鏡，飛香上酒盃。", "江淮千里遠，安得一枝來。"]'),
('8b0ec7fb-fc16-4319-856b-4890da76aba9','試諸葛生筆因書所懷寄諸弟  其一八','彭汝礪','宋','宋诗','song-poetry','','[]','見說東林地，盆池近種蓮。',48,'全唐诗/poet.song.51000.json','["見說東林地，盆池近種蓮。", "清風生綠水，酷日冒炎天。", "物外無雙格，花中第一仙。", "即今春已到，應復葉田田。"]'),
('38088fd0-5a14-4194-b9ed-6167e7557b16','試諸葛生筆因書所懷寄諸弟  其一九','彭汝礪','宋','宋诗','song-poetry','','[]','吾憶東林北，庭前巧作山。',48,'全唐诗/poet.song.51000.json','["吾憶東林北，庭前巧作山。", "乍晴風苒苒，久雨蘚班班。", "漁釣滄洲靜，樵歌白日閑。", "蓬瀛仙世界，容易落人間。"]'),
('4ac7d39f-abe3-4631-8975-fa52680dd0fb','試諸葛生筆因書所懷寄諸弟  其二○','彭汝礪','宋','宋诗','song-poetry','','[]','吾愛東林靜，幽亭學結茅。',48,'全唐诗/poet.song.51000.json','["吾愛東林靜，幽亭學結茅。", "風雲生石谷，烟霧接林梢。", "短檻仙禽宿，疏櫺乳燕巢。", "更無塵俗到，瀟灑似寒郊。"]'),
('656b569d-fa8d-473d-8b74-fccc46052797','又憶東林','彭汝礪','宋','宋诗','song-poetry','','[]','夫君自南國，有信寄西風。',48,'全唐诗/poet.song.51000.json','["夫君自南國，有信寄西風。", "天上曾攀桂，江邊復轉蓬。", "試爲千里約，敢慍一囊空。", "相望看明月，高秋復在中。"]'),
('2d18145c-905f-4a46-8408-7e9229a828a3','初夏詠','彭汝礪','宋','宋诗','song-poetry','','[]','簿領紛相壓，塵埃懶未堪。',48,'全唐诗/poet.song.51000.json','["簿領紛相壓，塵埃懶未堪。", "輕陰人割麥，微雨客憂蠶。", "照水荷衣薄，迎風柳鬢鬖。", "微吟聊自釋，一夢滿江南。"]'),
('2da7f0ab-37cb-4523-902b-2fd1fda5cb7b','圍爐分題得書屏','彭汝礪','宋','宋诗','song-poetry','','[]','巧製方還曲，黄編卷復舒。',48,'全唐诗/poet.song.51000.json','["巧製方還曲，黄編卷復舒。", "廢興千古意，窮達一屏書。", "光素侵殘雪，塵埃拂蠹魚。", "粗官久不用，慎勿怨相疏。"]'),
('2ee9073a-c75f-4590-a728-a77468be8cc1','和潤之硯冰','彭汝礪','宋','宋诗','song-poetry','','[]','晨風凝不散，硯石凍初成。',48,'全唐诗/poet.song.51000.json','["晨風凝不散，硯石凍初成。", "翠失蒼龍骨，寒餘一鑑清。", "纖毫隔冰雪，寶墨妬瑶瓊。", "莫近朝陽暖，留看夜月明。"]'),
('277fd5d9-bc0d-453f-b1a8-9cb628a39eec','和庭佐酒船','彭汝礪','宋','宋诗','song-poetry','','[]','紅錦圍歌席，黄金飾酒船。',48,'全唐诗/poet.song.51000.json','["紅錦圍歌席，黄金飾酒船。", "興撩江外客，香忤飲中仙。", "憂慮無風雨，歡娛揖聖賢。", "空餘中夕夢，一棹倚江天。"]'),
('58a94c0b-583b-42d2-aaf4-9fecf460a713','端午','彭汝礪','宋','宋诗','song-poetry','','[]','日上天心直，風生水檻寒。',48,'全唐诗/poet.song.51000.json','["日上天心直，風生水檻寒。", "羈窮念時節，草次具盤餐。", "買藥知衰病，開樽得小歡。", "醉懷江國味，撥棹倚江干。"]'),
('3d18eacd-50be-41cf-8ed9-fab8972df302','禱雨','彭汝礪','宋','宋诗','song-poetry','','[]','萬物紛紛出，驕陽苦蠹侵。',48,'全唐诗/poet.song.51000.json','["萬物紛紛出，驕陽苦蠹侵。", "盛衰占物理，憂樂念人心。", "又作祇園禱，誰爲傅說霖。", "無誠動幽隠，子細卜山禽。"]'),
('1931ac95-9bb2-449e-ab2e-de7a57084086','宿鄧橋','彭汝礪','宋','宋诗','song-poetry','','[]','一舍山頭路，數家溪上村。',48,'全唐诗/poet.song.51000.json','["一舍山頭路，數家溪上村。", "泥塗淹白晝，風月宿黄昏。", "松徑笙簧雜，蛙池鼓吹喧。", "寂寥無酒興，迢遞有歸魂。"]'),
('01857c45-c528-4b0f-bcb3-a0d4ce2ed70d','和子堅同游東湖游字韵','彭汝礪','宋','宋诗','song-poetry','','[]','小徑行幽草，回塘汎杪秋。',48,'全唐诗/poet.song.51000.json','["小徑行幽草，回塘汎杪秋。", "風波魚自樂，芹藻雁同游。", "暇日容携酒，晴天好放舟。", "夕陽歸旆晚，更向水邊留。"]'),
('947bcdf6-4346-4c4a-a90c-8bad65eb042b','次芸叟韵','彭汝礪','宋','宋诗','song-poetry','','[]','雪霜歸漢塞，星露近蘇天。',48,'全唐诗/poet.song.51000.json','["雪霜歸漢塞，星露近蘇天。", "金錯千兵甲，花團五馬韉。", "春從今夜好，月勝別時圓。", "頗笑荆溪老，猶談般若禪。"]'),
('a7274143-65d3-47c8-b548-aa822a33f8c3','水軒晝寢','彭汝礪','宋','宋诗','song-poetry','','[]','曉步迎晨旭，昏歸踏暮鐘。',48,'全唐诗/poet.song.51000.json','["曉步迎晨旭，昏歸踏暮鐘。", "簿書分意思，塵土病顔容。", "隔岸柳陰細，侵簾波影重。", "諸公惜駑蹇，一息養疏慵。"]'),
('b01b147c-dc01-4330-babd-cc97d45ef003','暮宿驛舍','彭汝礪','宋','宋诗','song-poetry','','[]','別袂風輕動，離裝雨薄沾。',48,'全唐诗/poet.song.51000.json','["別袂風輕動，離裝雨薄沾。", "斷霞孤鶩落，新月一眉纖。", "鳥羽棲幽徑，蛩聲滿畫簾。", "稍贏詩思健，還覺旅魂添。"]'),
('31725297-148a-4170-8caa-27227d32fe2f','磁州','彭汝礪','宋','宋诗','song-poetry','','[]','初聞神鐵語，舊記滏陽名。',48,'全唐诗/poet.song.51000.json','["初聞神鐵語，舊記滏陽名。", "地擅磁毛富，時無石鼓聲。", "夕陽神武冢，秋水武安城。", "嘆息彼之子，奚爲蝸角爭。"]'),
('e8429c00-c9ea-451c-9c12-6f944d92abbb','雪後會仙洞','彭汝礪','宋','宋诗','song-poetry','','[]','座見會仙石，逕觀羣玉峰。',48,'全唐诗/poet.song.51000.json','["座見會仙石，逕觀羣玉峰。", "寒聲無近水，幽徑旋移松。", "晚日烟霞雜，歸雲粉黛重。", "天寒宜飲酒，衰疾每相容。"]'),
('a945e5a5-589f-4cc9-8284-48f925e1a4f2','接伴太傅離新館其兄迓于途','彭汝礪','宋','宋诗','song-poetry','','[]','使者乘軺至，將軍走馬迎。',48,'全唐诗/poet.song.51000.json','["使者乘軺至，將軍走馬迎。", "侏離何所語，踴躍不勝情。", "寓目鴻雁澤，傷心杕杜行。", "天乎非有間，我老獨無兄。"]'),
('0845006c-1e93-4934-b4dc-4cc89f90e5c7','和濟叔兄書齋言志一首','彭汝礪','宋','宋诗','song-poetry','','[]','讌處重尋舊，淹留怪此身。',192,'全唐诗/poet.song.51000.json','["讌處重尋舊，淹留怪此身。", "是非方背俗，趨向且依仁。", "講論青瑶重，文章白日新。", "材謀强訓練，機務默經綸。", "抱策期寧漢，潜輝豈避秦。", "幽扉重蘚跡，永巷絕車轔。", "奧域爭先到，夷途約荐臻。", "方從三友益，肯顧一瓢貧。", "學以充吾志，思期惠爾民。", "如何迷要路，未得泛通津。", "雖謂神龍屈，寧慚尺蠖伸。", "廟堂方致理，巖穴肯遺人。", "自顧蓬蒿跡，終非草莽臣。", "佇期携素業，相與奉嚴宸。", "執己清成雪，謀邦銳應斤。", "力求三代治，追復在昌辰。"]'),
('f301c165-095f-43b2-aae4-e4b0cd80c892','倒押前韵','彭汝礪','宋','宋诗','song-poetry','','[]','幽齋置圖史，相與樂清辰。',192,'全唐诗/poet.song.51000.json','["幽齋置圖史，相與樂清辰。", "世路寬鞿靮，心茅得斧斤。", "圭蓬思魏闕，寤寐想楓宸。", "困阨孟東野，羈窮朱買臣。", "惠時空有策，知己尚無人。", "跡退心猶銳，時窮道益伸。", "鳳潜傾帝閣，龍蟄望天津。", "業負青雲器，寧期白屋民。", "第增材德富，休笑室家貧。", "蓽戶此時隠，金門異日臻。", "世途雖晏晏，邊寇尚轔轔。", "邂逅得歸漢，箴規當借秦。", "安危歸指畫，可否屬經綸。", "力振朝綱弊，期增治具新。", "致君儒者事，康世士之仁。", "蓄極符亨矣，無羞困辱身。"]'),
('f57a7149-3a23-4742-89da-467c039ae2dd','勉友人張生一首','彭汝礪','宋','宋诗','song-poetry','','[]','羣英偕奮迅，夫子尚埃塵。',84,'全唐诗/poet.song.51000.json','["羣英偕奮迅，夫子尚埃塵。", "辜負青雲器，淹留白屋身。", "孟軻雖欲仕，原憲固安貧。", "甚矣逢時晚，歸歟樂道真。", "林泉遯華耀，詩酒毓精神。", "天子真明主，朝家况盛辰。", "忍令伊尹輩，終老止耕莘。"]'),
('f5152255-4616-4e46-92d0-1cc378ac6495','次儀父春日草韵一首','彭汝礪','宋','宋诗','song-poetry','','[]','一室浮塵外，重門翠嶺坳。',144,'全唐诗/poet.song.51000.json','["一室浮塵外，重門翠嶺坳。", "愧非南土秀，輒繼竹林交。", "共喜逢佳節，狂遊過碧郊。", "綠垂溪柳線，紅舞野花梢。", "歷亂禽相語，芊茸草漸包。", "賞心須載酒，席地不誅茆。", "野眺幽歡入，羈窮舊恨拋。", "川原真勝境，雞黍亦嘉餚。", "清唱溪泉激，虛談佩玉敲。", "醉腸波浩蕩，銳氣虎炰烋。", "天子今堯舜，吾門豈許巢。", "亨途行决矣，何必俟占爻。"]'),
('f26115a7-856d-4fd8-95a2-5d77ede35886','上劉推官一首','彭汝礪','宋','宋诗','song-poetry','','[]','盛旦登高第，青衫偃壯圖。',240,'全唐诗/poet.song.51000.json','["盛旦登高第，青衫偃壯圖。", "蘭臺收碩德，蓮幙得真儒。", "江左風流敝，鄱陽習俗污。", "晨昏叢獄訟，利病倚謀謨。", "郡政頹綱整，都民舊瘼蘇。", "英聲傳士庶，清議滿江湖。", "事業人之表，機籌帝所需。", "大臣交薦擢，榮召計須臾。", "有客材無似，謀身計大迂。", "志憎時態薄，道欲古人俱。", "寓跡文章苑，棲魂典籍郛。", "傾螺思測海，擿埴强求塗。", "不見孔之卓，安知柴也愚。", "駑蹤誰警策，弱質寡持扶。", "與物睽違甚，惟公顧盼殊。", "滯頑真瓦礫，拂拭過璠璵。", "陋學慚無狀，浮名出不虞。", "見知雖鮑叔，蒙遇豈夷吾。", "朽木依刀尺，堅金屬範模。", "會須終盛賜，俾得望亨衢。"]'),
('fdd78c9a-1cf4-4d90-846a-74a11b203437','夜泊睦州桐江','彭汝礪','宋','宋诗','song-poetry','','[]','一水連銀漢，千山擁古城。',108,'全唐诗/poet.song.51000.json','["一水連銀漢，千山擁古城。", "客乘清夜息，舟倚碧溪橫。", "皓月危峰影，清風細浪聲。", "嘔啞殊俗語，慘淡異鄉情。", "途旅淹時月，羈窮獨弟兄。", "剛腸雙古劍，蕩跡一流萍。", "道路人皆厭，風波我亦驚。", "胡爲甘險阻，所得喜豪英。", "俗眼無相笑，吾非逐利名。"]'),
('66b9d471-b21d-45ef-abb8-9f956242a650','昔在橫港西山與張季友儀父游相別各數年矣今冬邂逅于此相與飲酒道故舊甚樂因各爲詩以見所懷','彭汝礪','宋','宋诗','song-poetry','','[]','久別西山夜，每懷橫水春。',144,'全唐诗/poet.song.51000.json','["久別西山夜，每懷橫水春。", "珪璋元自合，手足更相親。", "頗笑曾參魯，尤知管仲貧。", "酒行脩水石，詩就寫松筠。", "薄宦分南北，浮生共屈伸。", "往來俱日月，出入見參辰。", "驛騎歸何晚，郵書寄稍頻。", "離羣初會面，話別故傷神。", "束縛隨時世，低徊喪本真。", "點衣塵土舊，侵鬢雪霜新。", "蝴蝶南華夢，芭蕉居士身。", "幾時江海去，相看老垂綸。"]'),
('4a84f6ff-3a7d-4f64-8903-11dc0ac757ff','送葉憲  其一','彭汝礪','宋','宋诗','song-poetry','','[]','棠棣榮何盛，皇華節更尊。',48,'全唐诗/poet.song.51000.json','["棠棣榮何盛，皇華節更尊。", "雨深鴻雁澤，春滿脊令原。", "載錫康侯馬，重吹伯氏壎。", "從來公愷悌，獄訟看平反。"]'),
('05a50abd-8428-4306-864a-4f1a968736dd','送葉憲  其二','彭汝礪','宋','宋诗','song-poetry','','[]','老大愁相別，紛紛鬢欲斑。',48,'全唐诗/poet.song.51000.json','["老大愁相別，紛紛鬢欲斑。", "雨封明月峽，水礙白鹽山。", "迢遞看持節，逡巡聽賜環。", "西江如箭急，數寄尺書還。"]'),
('cebed1e5-f7bd-4925-a8eb-bf674bcee00d','秋日吟二首呈諸友時在合肥作  其一','彭汝礪','宋','宋诗','song-poetry','','[]','綠髮猶年少，衰顔苦病多。',120,'全唐诗/poet.song.51000.json','["綠髮猶年少，衰顔苦病多。", "陰寒傷物色，淫雨蠹天和。", "盃酒開寥落，靈蓍問轗軻。", "凋疏頭鬢亂，欹側齒音訛。", "苒苒時難得，紛紛日易蹉。", "荆蒿太狼藉，圭角未消磨。", "廢棄今如此，云爲竟若何。", "嗟傷仁者遠，幸望故人過。", "臘意生幽徑，春心漾綠波。", "幾時樽俎共，爛醉聽清歌。"]'),
('6642aca4-ba16-4ded-ba26-4b6ae7985dcb','秋日吟二首呈諸友時在合肥作  其二','彭汝礪','宋','宋诗','song-poetry','','[]','露下風高頭鬢凋，愆陽不雨肺肝焦。',64,'全唐诗/poet.song.51000.json','["露下風高頭鬢凋，愆陽不雨肺肝焦。", "短窗竟日添憔悴，座榻無人問寂寥。", "點綴詩篇空夜夜，封題藥裹自朝朝。", "重雲苒苒蓬瀛隔，步武相忘萬里遙。"]'),
('9599e880-269f-4d8d-b4d5-29d2b43819c7','在合肥幕中有作','彭汝礪','宋','宋诗','song-poetry','','[]','幕府開雄盛，朋游望俊髦。',120,'全唐诗/poet.song.51000.json','["幕府開雄盛，朋游望俊髦。", "雙松鬭冰雪，一鶚出蓬蒿。", "春雨吟花蒂，秋霜擘蟹螯。", "山川留翰墨，天地入風騷。", "感慨驚多變，微生病一號。", "酒巵餘寂淡，詩筆惠英豪。", "憂思生心腑，塵埃上鬢毛。", "簿書今日困，道路此身勞。", "小雨開濡滯，清飈散鬰陶。", "小亭山可見，由此欲登高。"]'),
('4ab53b0b-2c75-48ac-a8cb-b6ef65382b36','上合肥太守侍讀傅公','彭汝礪','宋','宋诗','song-poetry','','[]','肥水當時守，商岩幾代孫。',216,'全唐诗/poet.song.51000.json','["肥水當時守，商岩幾代孫。", "精明應玄象，清白接靈源。", "山岳分凝重，球琳讓粹溫。", "一書開主惑，羣力破姦魂。", "萬事非吾計，孤忠自所存。", "遺聲雙禁闥，寵錫兩朱轓。", "道路生新樂，江湖洗舊民。", "澤餘沾草木，孚至及魚豚。", "不肖塵華幕，無材愧素餐。", "誤懸徐孺榻，喜上李膺門。", "簿領才傷拙，塵埃貌苦村。", "初終承至訓，老稚飲殊恩。", "遂恐徵書至，還歸近侍尊。", "蛟龍不潜隠，鵰鶚自飛翻。", "會亦懲衰弊，應須正本原。", "紀綱維盡力，狐鼠可忘言。", "鼎鼐開先烈，鹽梅及後昆。", "祇知心繾綣，不覺語真繁。"]'),
('1a7df575-d88e-4ffc-944d-fc8fd796e115','送虞資道赴闕','彭汝礪','宋','宋诗','song-poetry','','[]','睿詔搜遺逸，羣英恥屈蟠。',108,'全唐诗/poet.song.51000.json','["睿詔搜遺逸，羣英恥屈蟠。", "荆邦收齒革，雍土貢琅玕。", "競擲莘耕耒，俱投渭釣竿。", "茅雖征以彙，鴻獨漸于磐。", "直氣凌鵰鶚，芳名掩蕙蘭。", "處囊錐穎脫，辭獄劍鋒寒。", "子去歌魚藻，予歸詠考槃。", "別離一慷慨，涕泗兩汍瀾。", "第喜青雲近，無傷去路難。"]'),
('f2202ec4-e66d-4669-bb5b-9e6b27509827','送吳子正赴召','彭汝礪','宋','宋诗','song-poetry','','[]','主上登前烈，宗丞用老儒。',240,'全唐诗/poet.song.51000.json','["主上登前烈，宗丞用老儒。", "飲冰宵去楚，衣錦晝歸吳。", "餞別成游寺，乘歡更泛湖。", "固難逢邂逅，能復惜踟躕。", "道路春初好，山原日未晡。", "雲中山隠約，野外水縈紆。", "洒落傾賢範，荒淫看伯圖。", "故園餘壯觀，遺址入荒蕪。", "檜柏高千尺，松杉聳萬株。", "輕風花散漫，細雨草沾濡。", "簿領容休暇，形骸外縶拘。", "縱橫棋有力，禮樂酒無踰。", "一鶚沖高漢，雙輪上坦途。", "道途留絕詠，宣室得明謨。", "自昔行猶蹇，于今用可需。", "願言思本末，無用較錙銖。", "仕路誠相照，年家契自殊。", "幾成嵇叔懶，敢謂孟軻迂。", "陋學真膠柱，危蹤近跋胡。", "應須寄珠玉，方願刻肌膚。"]'),
('518ca2b1-0549-4f86-aff6-e2e175126dc4','送劉器之待制知真定府','彭汝礪','宋','宋诗','song-poetry','','[]','時平謀帥重，侍從輟名卿。',96,'全唐诗/poet.song.51000.json','["時平謀帥重，侍從輟名卿。", "龍種三千騎，虬髯十萬兵。", "紅蓮王儉幙，細柳亞夫營。", "列道諸侯謁，還鄉故老迎。", "試詢三將宅，應過五梁城。", "莫樂潭園勝，難忘魏闕情。", "守株嗟我老，杖鉞壯公行。", "祇恐非朝夕，君王召賈生。"]'),
('b2c0c58d-fd0b-43a3-8684-7309d537e164','城上懷古','彭汝礪','宋','宋诗','song-poetry','','[]','水漲藏舟浦，雲浮偃月城。',48,'全唐诗/poet.song.51000.json','["水漲藏舟浦，雲浮偃月城。", "寒蕪隨地遠，漫水與天平。", "險阻生姦僞，乾坤入聖明。", "杖藜登絕徑，談笑不忘情。"]'),
('9ffd9d2a-7731-4fbd-ade4-3856f6048881','題外舅評事秀實堂','彭汝礪','宋','宋诗','song-poetry','','[]','地勝風長暖，堂開美亦并。',48,'全唐诗/poet.song.51000.json','["地勝風長暖，堂開美亦并。", "溪聲留几席，山影上簷楹。", "田野多真趣，詩書足義榮。", "本根今日好，華實看俱成。"]'),
('22dfd97b-2ba0-486c-b1ea-ba8d004c4397','江上晚起','彭汝礪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水昏如欲雨，霧落復非雲。',48,'全唐诗/poet.song.51000.json','["水昏如欲雨，霧落復非雲。", "浩蕩重波隠，微茫小岸分。", "大明瞻日曉，微暖報風薰。", "隠約廬山寺，孤鐘續續聞。"]'),
('25531c09-98d5-4742-b38c-c535f0227ba2','答吳節推','彭汝礪','宋','宋诗','song-poetry','','[]','吳子新詩好，輕容俗吏傳。',48,'全唐诗/poet.song.51000.json','["吳子新詩好，輕容俗吏傳。", "芝蘭元自秀，騏驥不須鞭。", "萬象生塵外，千林宿水邊。", "欲歌無意緒，甘讓古人先。"]'),
('b39659c4-67d4-4f90-be9d-fbaf2d6bb6f4','和白酒','彭汝礪','宋','宋诗','song-poetry','','[]','村醪薄滋味，市俗固安便。',48,'全唐诗/poet.song.51000.json','["村醪薄滋味，市俗固安便。", "酃水東湖咏，青囊杜甫錢。", "宴遊知有地，塵俗自非仙。", "我醉非關飲，昏昏坐欲眠。"]'),
('c084e400-af8a-411c-89b3-14a63738a07e','和思歸','彭汝礪','宋','宋诗','song-poetry','','[]','嗟予苦山野，愛子有光輝。',48,'全唐诗/poet.song.51000.json','["嗟予苦山野，愛子有光輝。", "飽學詩渾好，多愁慮益微。", "幙中方倚辦，江上可言歸。", "况有高風便，行看俊鶻飛。"]'),
('95fa7537-7c9a-46a2-9c44-9a4627ef7bd7','和春城北','彭汝礪','宋','宋诗','song-poetry','','[]','何曾看好春，已復見春深。',48,'全唐诗/poet.song.51000.json','["何曾看好春，已復見春深。", "水漲千溪綠，松低一路陰。", "簿書淹世態，鷄黍亂鄉心。", "莫廢清和飲，枝頭李可沉。"]'),
('608c8a1a-5e94-4277-b721-31ed046f53d4','和晚北園','彭汝礪','宋','宋诗','song-poetry','','[]','天氣非相逼，東風已自歸。',48,'全唐诗/poet.song.51000.json','["天氣非相逼，東風已自歸。", "樂遊終少及，世事故多違。", "桃杏春如在，溪山暑尚微。", "早期荃楫泛，頻縱角觴飛。"]'),
('cde09d75-2743-4228-aace-80885f3ee21f','和自遣','彭汝礪','宋','宋诗','song-poetry','','[]','春花競狼藉，暮鳥學啁嘲。',48,'全唐诗/poet.song.51000.json','["春花競狼藉，暮鳥學啁嘲。", "勁節松千尺，奇文鳳九苞。", "杲之蓮府客，嵇紹竹林交。", "欲看歸廊廟，胡然憶舊巢。"]'),
('91cb778e-39d9-45bc-bd98-2a38ce814c7d','祖道京淮道中酬唱','彭汝礪','宋','宋诗','song-poetry','','[]','旅中人遠別，河上酒頻行。',48,'全唐诗/poet.song.51000.json','["旅中人遠別，河上酒頻行。", "暖日開花信，高風去雁聲。", "庭闈甘菽水，魏闕望瑶瓊。", "應答詩慚拙，猶能慰別情。"]'),
('351b83d3-4c8b-4774-bd0a-7c7fb5a021a2','和祖道國門外文淵子至東父餞席上贈別','彭汝礪','宋','宋诗','song-poetry','','[]','行李隨長道，飄蓬笑賤官。',48,'全唐诗/poet.song.51000.json','["行李隨長道，飄蓬笑賤官。", "望雲瞻白日，臨水看驚瀾。", "鳥語如知節，花開尚怯寒。", "莫嫌春色淺，留到後園看。"]'),
('937b451b-79ad-432a-bfa5-0126a5505a9e','沈一惠詩次韵謝之','彭汝礪','宋','宋诗','song-poetry','','[]','世途羞困辱，不復顧交情。',48,'全唐诗/poet.song.51000.json','["世途羞困辱，不復顧交情。", "衆稚憐張載，諸公厭禰衡。", "仁心矜廢物，佳句寫真誠。", "喜悅驅車至，思心正若縈。"]'),
('17e22097-5d00-46a8-aca2-5d07848eae49','次靜長老韵','彭汝礪','宋','宋诗','song-poetry','','[]','性火方能熄，心燈不復挑。',48,'全唐诗/poet.song.51000.json','["性火方能熄，心燈不復挑。", "猿聲傳古穴，柏實落枯條。", "闃寂苦無寐，淋零已半宵。", "更深寒愈重，慵解束薪燒。"]'),
('066bdb45-d22a-4577-8735-71fa42ac176f','入桐廬道中','彭汝礪','宋','宋诗','song-poetry','','[]','學問古人重，英豪世所歸。',48,'全唐诗/poet.song.51000.json','["學問古人重，英豪世所歸。", "呼奴整軒駕，拭淚別庭闈。", "久雨路岐澀，荒村草木稀。", "城闉頓相遠，回首一依依。"]'),
('0b98a0dd-1f92-4b86-9089-574bc1d40529','馬上','彭汝礪','宋','宋诗','song-poetry','','[]','馬上值寒食，途中非故鄉。',48,'全唐诗/poet.song.51000.json','["馬上值寒食，途中非故鄉。", "山川勞跋涉，風雨助悲凉。", "碧樹鳥相語，幽林花自芳。", "不辭趨道路，多愧負春光。"]'),
('d2e9b95e-fbd7-4ddf-bec1-9dfc97c3ffe5','風雨','彭汝礪','宋','宋诗','song-poetry','','[]','風雨恣顛蹶，晚潮相繼來。',48,'全唐诗/poet.song.51000.json','["風雨恣顛蹶，晚潮相繼來。", "輕舟一葉轉，巨浪千山頹。", "忠信吾知矣，風波孰病哉。", "寒江幾百里，白雪正皚皚。"]'),
('f8797e97-beab-427f-98d8-5c8000d7e4bc','逢姜二兄','彭汝礪','宋','宋诗','song-poetry','','[]','闃寂桐江地，羈栖遠客魂。',48,'全唐诗/poet.song.51000.json','["闃寂桐江地，羈栖遠客魂。", "別家驚節換，此意與誰言。", "忽爾聲容際，悠然信義存。", "此時皆逆旅，何日共歸軒。"]'),
('cd6de9ec-6e89-435d-be5d-e6a22ce8a0ad','去桐廬學','彭汝礪','宋','宋诗','song-poetry','','[]','中庸方自樂，外慮巧相侵。',48,'全唐诗/poet.song.51000.json','["中庸方自樂，外慮巧相侵。", "興廢盡天意，行藏非我心。", "淚因鶑谷亂，愁爲鶺原深。", "日暮途方遠，誰賡馬上吟。"]'),
('a0fa9dc0-3bfa-41d6-ab9b-a283fb720b9f','與蔣十二','彭汝礪','宋','宋诗','song-poetry','','[]','孑立羈窮際，相逢邂逅間。',48,'全唐诗/poet.song.51000.json','["孑立羈窮際，相逢邂逅間。", "交遊新氣概，塵土舊容顔。", "共指青雲遠，同分白日閑。", "區區交友志，松柏滿南山。"]'),
('3f0813c7-db8d-469a-8b11-f997f43365d9','日暮','彭汝礪','宋','宋诗','song-poetry','','[]','日暮辭前渚，天寒宿遠汀。',48,'全唐诗/poet.song.51000.json','["日暮辭前渚，天寒宿遠汀。", "青燈同寂寞，濁酒慰飄零。", "痛飲無人共，高歌反自聽。", "終宵惟此興，日戰破愁亭。"]'),
('6317837d-e5fa-45d8-8d16-afeb813b9c9a','送元博縣丞還浙忠甫沈翊還鄱陽','彭汝礪','宋','宋诗','song-poetry','','[]','汴水晝夜落，客心朝夕飛。',48,'全唐诗/poet.song.51000.json','["汴水晝夜落，客心朝夕飛。", "君舟雖獨往，吾夢亦同歸。", "山色藏星渚，風清夢釣磯。", "樂遊難並得，人事固多違。"]'),
('aed1569f-023d-406f-9aa8-477cc312ed23','再寄穎叔一首','彭汝礪','宋','宋诗','song-poetry','','[]','山林問舊題，州縣見餘威。',48,'全唐诗/poet.song.51000.json','["山林問舊題，州縣見餘威。", "求友誠相及，思親夢遠歸。", "丁丁聞伐木，密密看縫衣。", "但自心猿伏，如它翼虎飛。"]'),
('65caff66-76da-4f9a-b4b2-7078c0143bd9','同許屯田子仁宿圓通寺','彭汝礪','宋','宋诗','song-poetry','','[]','遠水猿谿古，孤峰石耳懸。',48,'全唐诗/poet.song.51000.json','["遠水猿谿古，孤峰石耳懸。", "慈悲開一徑，智慧出雙泉。", "大士車乘鹿，幽人社結蓮。", "欲知今邂逅，猶是昔因緣。"]'),
('0a8b5628-477e-444f-97c5-2dc23ac1bb1a','再和子仁','彭汝礪','宋','宋诗','song-poetry','','[]','祇見塵埃遠，還疑粉繪懸。',48,'全唐诗/poet.song.51000.json','["祇見塵埃遠，還疑粉繪懸。", "淡雲寒對月，幽石靜聞泉。", "潤澤作甘雨，污泥生白蓮。", "五更催解轡，知未悟塵緣。"]'),
('439f6a7a-9e01-4c32-a174-211c7cdb676b','到慈湖九江有感  其一','彭汝礪','宋','宋诗','song-poetry','','[]','昔赴長沙幙，初經彭蠡湖。',48,'全唐诗/poet.song.51000.json','["昔赴長沙幙，初經彭蠡湖。", "所天正强健，此地稍踟躕。", "杖屨今何在，谿山祇自如。", "白頭雙血淚，一夜落深蒲。"]'),
('6271007f-9760-45e2-8846-dce21bc111f1','到慈湖九江有感  其二','彭汝礪','宋','宋诗','song-poetry','','[]','繫舟此地昔徜徉，楊柳今時更老蒼。',32,'全唐诗/poet.song.51000.json','["繫舟此地昔徜徉，楊柳今時更老蒼。", "却望靈芝西北路，秋風吹泪滿滄浪。"]'),
('c891ab6a-73d2-4f7c-a0ae-925695d753ce','徐亭泛舟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','萬葉烟雲上，千花錦繡中。',24,'全唐诗/poet.song.51000.json','["萬葉烟雲上，千花錦繡中。", "停舟不忍發，爲恐破圓紅。"]'),
('28cab1e0-33fb-4d03-89d5-1c6f4cddf995','徐亭泛舟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','晚雨軒窗潤，秋風池沼香。',24,'全唐诗/poet.song.51000.json','["晚雨軒窗潤，秋風池沼香。", "愛花不忍折，恰似惜甘棠。"]'),
('e96a9c57-c44b-409d-8e63-2b80bf4d50ff','自臨川泛舟還歸因假前韵寄粹老提舉朝議兼簡知府龍圖丈  其一','彭汝礪','宋','宋诗','song-poetry','','[]','村郭孤烟暝，溪山片月斜。',48,'全唐诗/poet.song.51000.json','["村郭孤烟暝，溪山片月斜。", "吾生渾是客，所至即爲家。", "春色生顔面，寒泉遶齒牙。", "歸與須載酒，一笑慰天涯。"]'),
('4aee28c4-5b30-4436-82d9-661bd475eb7d','自臨川泛舟還歸因假前韵寄粹老提舉朝議兼簡知府龍圖丈  其二','彭汝礪','宋','宋诗','song-poetry','','[]','舟行朝市隔，恣意看溪山。',48,'全唐诗/poet.song.51000.json','["舟行朝市隔，恣意看溪山。", "天地青春遠，江湖白日閒。", "偶隨鷗獨往，却與燕俱還。", "時節清明近，應須屢破顔。"]'),
('6c4c39b4-fcf6-41d4-8c62-225bb1aa32f6','自臨川泛舟還歸因假前韵寄粹老提舉朝議兼簡知府龍圖丈  其三','彭汝礪','宋','宋诗','song-poetry','','[]','道路不得已，簡書無奈何。',48,'全唐诗/poet.song.51000.json','["道路不得已，簡書無奈何。", "啼鶑思舊友，流水憶清歌。", "江漢心尤愜，田園興轉多。", "西山春咫尺，游思欲捫蘿。"]'),
('a14f5119-cfe2-4b1b-98ac-0bcb4c79ec97','自臨川泛舟還歸因假前韵寄粹老提舉朝議兼簡知府龍圖丈  其四','彭汝礪','宋','宋诗','song-poetry','','[]','匹馬千山遠，扁舟宇宙寬。',48,'全唐诗/poet.song.51000.json','["匹馬千山遠，扁舟宇宙寬。", "歲華春已仲，時節食初寒。", "稍憶棋爭勝，還須飲盡歡。", "使君如見問，行李已河干。"]'),
('71ac4c7b-1db9-48ad-9627-8d47740a58db','將行季自鄱陽來','彭汝礪','宋','宋诗','song-poetry','','[]','伯也別何遽，叔兮來未央。',48,'全唐诗/poet.song.51000.json','["伯也別何遽，叔兮來未央。", "水流心去遠，月靜夢歸長。", "細雨濕萱草，高風吹雁行。", "幾時生事足，相看老耕桑。"]'),
('5bbb4e54-bc12-415d-afda-03c2333b7cd2','得書并簡仔仲二侄  其一','彭汝礪','宋','宋诗','song-poetry','','[]','近得江東遞，連收十月書。',48,'全唐诗/poet.song.51000.json','["近得江東遞，連收十月書。", "歲時今已晚，安否比何如。", "從事先生老，謀生仲叔疏。", "爲君歸不惜，稍更治田廬。"]'),
('c85c3f25-6872-40b0-9939-6c56f65927f0','得書并簡仔仲二侄  其二','彭汝礪','宋','宋诗','song-poetry','','[]','遠宦非予欲，浮生如此何。',48,'全唐诗/poet.song.51000.json','["遠宦非予欲，浮生如此何。", "幾時俱省定，終日念漸摩。", "流水嗟蓬轉，青雲喜雁過。", "寄書盈萬字，不似淚痕多。"]'),
('3270ffec-a13c-4077-b01e-463b165bbf9f','途中','彭汝礪','宋','宋诗','song-poetry','','[]','小人故懷土，游子更思鄉。',48,'全唐诗/poet.song.51000.json','["小人故懷土，游子更思鄉。", "里堠經雙隻，郵亭宿短長。", "暮棲烏反哺，春去雁隨陽。", "亦有一廛宅，能無十畝桑。"]'),
('1352a672-4a60-473c-b778-0cf77b3155c9','正月初三日送叔宜弟初離襄陽','彭汝礪','宋','宋诗','song-poetry','','[]','月魄纔生夜，春風恰到時。',48,'全唐诗/poet.song.51000.json','["月魄纔生夜，春風恰到時。", "異鄉愁對酒，深院靜論詩。", "道路嗟吾老，雲霄恨汝遲。", "莫言明日別，徒益鬢邊絲。"]'),
('4a2fba27-ee72-481e-893e-e8861a8e5bd5','送叔宜','彭汝礪','宋','宋诗','song-poetry','','[]','地近梅開早，溪深柳放遲。',48,'全唐诗/poet.song.51000.json','["地近梅開早，溪深柳放遲。", "可憐春到處，恰值汝歸時。", "衰晚疲奔走，羈棲恨別離。", "祇因明夜夢，千里亦相隨。"]'),
('bfd8e448-ce2b-4406-86a2-de1ff8c84214','寄庭佐','彭汝礪','宋','宋诗','song-poetry','','[]','久別隨蓬草，相思看雁行。',48,'全唐诗/poet.song.51000.json','["久別隨蓬草，相思看雁行。", "水流心去遠，月靜夢歸長。", "盡力耕南畝，怡顔侍北堂。", "曾參君不及，可以似王祥。"]'),
('454e9919-89c8-4b75-a525-1cf1ee5a97df','病懶','彭汝礪','宋','宋诗','song-poetry','','[]','原憲自多病，長卿仍倦游。',48,'全唐诗/poet.song.51000.json','["原憲自多病，長卿仍倦游。", "經旬或洗面，一月不梳頭。", "身世真羈旅，功名是贅疣。", "百年無可問，吾道合歸休。"]'),
('ef3cb301-28d9-405d-bb9c-7860068b7d00','陳師道教授示黄梅詩次韵呈正夫學士四首  其一','彭汝礪','宋','宋诗','song-poetry','','[]','美色絕殊衆，暗香時著人。',24,'全唐诗/poet.song.51000.json','["美色絕殊衆，暗香時著人。", "齊州終自別，不比嶺頭春。"]'),
('d7907d84-f399-4a2b-b3f7-aba3fdf9bfe1','陳師道教授示黄梅詩次韵呈正夫學士四首  其二','彭汝礪','宋','宋诗','song-poetry','','[]','可但深宜晚，須知巧耐寒。',24,'全唐诗/poet.song.51000.json','["可但深宜晚，須知巧耐寒。", "北人渾未識，祇作棣棠看。"]'),
('37e032f0-217d-4c0c-97e6-0b8f5d988e26','陳師道教授示黄梅詩次韵呈正夫學士四首  其三','彭汝礪','宋','宋诗','song-poetry','','[]','舊作酴醾白，新翻蛺蝶黄。',24,'全唐诗/poet.song.51000.json','["舊作酴醾白，新翻蛺蝶黄。", "不須多變態，固自有真香。"]'),
('ccb68570-180a-4607-868a-3373f64afe70','陳師道教授示黄梅詩次韵呈正夫學士四首  其四','彭汝礪','宋','宋诗','song-poetry','','[]','不獨看花懶，吟詩味亦忘。',24,'全唐诗/poet.song.51000.json','["不獨看花懶，吟詩味亦忘。", "此花誰可賦，顧曲有周郎。"]'),
('dd52c687-7e06-4375-8796-e45447e24db2','大小沙陀  其一','彭汝礪','宋','宋诗','song-poetry','','[]','南障古北口，北控大沙陀。',48,'全唐诗/poet.song.51000.json','["南障古北口，北控大沙陀。", "土地稻粱少，歲時霜雪多。", "古來常用武，今日許通和。", "豈乏驃姚將，君王悟止戈。"]'),
('b694e37c-9246-49e4-a90b-00ea606740e7','大小沙陀  其二','彭汝礪','宋','宋诗','song-poetry','','[]','大小沙陀深沒膝，車不留蹤馬無跡。',88,'全唐诗/poet.song.51000.json','["大小沙陀深沒膝，車不留蹤馬無跡。", "曲折多途胡亦惑，自上高岡認南北。", "大風吹沙成瓦礫，頭面瘡痍手皴坼，下带長烟蔽深驛。", "層冰峨峨霜雪白，狼顧鳥行愁覆溺。", "一日不能行一驛，吾聞治生莫如嗇。"]'),
('29a4c86b-2397-42a1-b736-470047a87da2','送鄭寺丞過洪州  其一','彭汝礪','宋','宋诗','song-poetry','','[]','盛德鴻樞後，才華日久新。',48,'全唐诗/poet.song.51000.json','["盛德鴻樞後，才華日久新。", "聲名飛海岳，步履望星辰。", "棋銳如無敵，詩成似有神。", "當塗難久滯，行楫桂花春。"]'),
('6b8b3a16-4d21-420c-bb49-e9741720f864','送鄭寺丞過洪州  其二','彭汝礪','宋','宋诗','song-poetry','','[]','清風不可近，碎璧綴圓規。',48,'全唐诗/poet.song.51000.json','["清風不可近，碎璧綴圓規。", "翰墨傳家學，風流藴素資。", "龍孫藏舊節，蟾桂毓新枝。", "願聽功名起，青雲慰所思。"]'),
('21d5e7ba-2e83-49c4-868d-ea0a6739168a','送鄭寺丞過洪州  其三','彭汝礪','宋','宋诗','song-poetry','','[]','恨接清規晚，愁看去鷁東。',48,'全唐诗/poet.song.51000.json','["恨接清規晚，愁看去鷁東。", "別情萬里遠，離緒一尊中。", "柳意藏春雪，梅香度曉風。", "餘寒須有作，無惜寄江鴻。"]'),
('db9ad97d-3d74-4130-8c66-705e62f37f1b','送鄭寺丞過洪州  其四','彭汝礪','宋','宋诗','song-poetry','','[]','聞君話行色，今過洞中天。',48,'全唐诗/poet.song.51000.json','["聞君話行色，今過洞中天。", "坐視征帆速，還令別意牽。", "重江鎖雲霧，邃谷隠神仙。", "不得相追逐，詩成一灑然。"]'),
('b55b75dc-160b-4dd3-ae71-8d8d6684a82e','和漢廣席上賦柑','彭汝礪','宋','宋诗','song-poetry','','[]','秀色霜滋重，餘香露洽鮮。',48,'全唐诗/poet.song.51000.json','["秀色霜滋重，餘香露洽鮮。", "鵠巢靈殻媚，海窟夜珠圓。", "丹橘非優貢，蟠桃亦浪仙。", "無嗟後林質，未至太清天。"]'),
('c5afe708-ce3c-4e8c-a689-4baad2cf306c','和蔣孝嚴江行','彭汝礪','宋','宋诗','song-poetry','','[]','江爲雨頻增浩蕩，物因霜重益凄凉。',64,'全唐诗/poet.song.51000.json','["江爲雨頻增浩蕩，物因霜重益凄凉。", "千年老木戰風色，萬里澄波浮日光。", "梅萼半紅渾臘意，麥田微綠已春陽。", "欲留佳賞無樽酒，空引詩魂百尺長。"]'),
('b771143d-7a3b-46b1-bb88-ba435a66890e','諸君江步以病不能從走筆寄之','彭汝礪','宋','宋诗','song-poetry','','[]','煩君仔細數江巒，風物如今總幾般。',64,'全唐诗/poet.song.51000.json','["煩君仔細數江巒，風物如今總幾般。", "永夜水聲應自得，新秋月色好誰看。", "沙禽靜斂雙飛翼，魚艇空餘一釣竿。", "詩力有窮情不盡，更憑收拾向毫端。"]'),
('9c0643c0-33ba-43f2-85ae-7d75b31182f5','登樓','彭汝礪','宋','宋诗','song-poetry','','[]','縹緲飛樓倚太清，危欄一瞬盡滄溟。',64,'全唐诗/poet.song.51000.json','["縹緲飛樓倚太清，危欄一瞬盡滄溟。", "世途忽忽與時異，水色溶溶依舊青。", "夷夏固知歸禹畫，幽燕何事屬戎庭。", "草萊賤策無津致，空想秋風涕泗零。"]'),
('bc32db4e-5ced-4c4e-8ead-e91d5ecd7ed1','到醒心亭','彭汝礪','宋','宋诗','song-poetry','','[]','萬里江湖逐斷萍，紅塵不見北山亭。',64,'全唐诗/poet.song.51000.json','["萬里江湖逐斷萍，紅塵不見北山亭。", "一思好景心魂醉，纔挹餘芳眼目醒。", "寒暑忽移佳木綠，古今長見遠峰青。", "烟蕪路斷無窮盡，空惜琅邪舊記銘。"]'),
('8b8c45c9-b5e2-4a3a-8bc1-6a07db0eb475','日影','彭汝礪','宋','宋诗','song-poetry','','[]','日影昏冥雨力微，扁舟欲往浪沾衣。',64,'全唐诗/poet.song.51000.json','["日影昏冥雨力微，扁舟欲往浪沾衣。", "不甘落葉東歸去，空羨征鴻北向飛。", "俗惡懶經沽酒市，身閑欲臥釣魚磯。", "祇疑風色相欺得，繫滯塵蹤未許歸。"]'),
('dc8a19b8-2294-4d1d-a73e-664806a207e5','呈劉推景仁','彭汝礪','宋','宋诗','song-poetry','','[]','萬里依依欲見君，浪煩車馬走乾坤。',64,'全唐诗/poet.song.51000.json','["萬里依依欲見君，浪煩車馬走乾坤。", "頻經患難心方老，久厭塵埃眼欲昏。", "幾日不歸南郡帳，清宵長夢翟公門。", "側聞丹詔從天下，願借春風起舊根。"]'),
('27d93e35-7a0d-427d-a11c-963f4e92337d','送臧夢符秀才歸','彭汝礪','宋','宋诗','song-poetry','','[]','匹馬騑騑冒曉征，故人惜別涕雙零。',64,'全唐诗/poet.song.51000.json','["匹馬騑騑冒曉征，故人惜別涕雙零。", "青雲器業方千里，窮巷生涯獨一經。", "節目已疏非杞棘，源流不竭即滄溟。", "餘閑且盡詩書學，莫遣塵埃誤性靈。"]'),
('acee48b9-81ac-4f53-81f1-b199e7bc3fbf','溪畔','彭汝礪','宋','宋诗','song-poetry','','[]','塵緒紛紛今少休，更須一去弄溪流。',64,'全唐诗/poet.song.51000.json','["塵緒紛紛今少休，更須一去弄溪流。", "清風滿木春纔半，落日明波雨乍收。", "懶逐山林羣野鹿，欲歸江漢狎沙鷗。", "藻疏菱密吾雖羨，未忍敲針作釣鈎。"]'),
('7ba0ed44-0197-4ea6-ac7d-a0c9a760073f','與梅秀才遊安師池亭賦詩','彭汝礪','宋','宋诗','song-poetry','','[]','炎天自欲沉朱李，詩社初欣見素梅。',64,'全唐诗/poet.song.51000.json','["炎天自欲沉朱李，詩社初欣見素梅。", "綠柳薦風消酷暑，青荷飛雨濯塵埃。", "牆頭竹影紛紛出，水面菱花細細開。", "拍手浩歌情不盡，笑君佳句泥流盃。"]'),
('312f3570-2a79-4c71-bab0-a417b2a54896','重至','彭汝礪','宋','宋诗','song-poetry','','[]','亭臺池沼皆依舊，惟愛清風日日新。',64,'全唐诗/poet.song.51000.json','["亭臺池沼皆依舊，惟愛清風日日新。", "念遠恨無雙羽翼，臨流安得一絲綸。", "好花有意重留客，幽鳥無情亂惹人。", "滿眼澄光清可賦，與君無厭往還頻。"]'),
('c176a612-e569-4da9-8fd2-8e13558f22df','出關寄資道','彭汝礪','宋','宋诗','song-poetry','','[]','草色萋青花色殷，獨乘微雨度重關。',64,'全唐诗/poet.song.51000.json','["草色萋青花色殷，獨乘微雨度重關。", "鵰鷹不死蓬蒿際，騏驥方懷道路間。", "千里未能通咫尺，一毫安敢望丘山。", "韶華欲老功名遠，臥想清風輒厚顔。"]'),
('4349ba6f-c1d8-4ec7-9641-f6b64df91850','平居多憂多病間從詩酒自樂即席爲詩呈諸友且寓一時之懷也','彭汝礪','宋','宋诗','song-poetry','','[]','不惜千金換酒醪，爲君窮力賦離騷。',64,'全唐诗/poet.song.51000.json','["不惜千金換酒醪，爲君窮力賦離騷。", "乾坤盡入雙吟眼，日月都歸一醉毫。", "平昔至誠傾益契，昨宵遊夢得夔皋。", "窮途知負經綸器，爛醉西風首重搔。"]'),
('bee4156e-5fe8-45de-9c46-94bb61457a54','炎暑','彭汝礪','宋','宋诗','song-poetry','','[]','炎暑半歸天早凉，日陰苦短夜初長。',64,'全唐诗/poet.song.51000.json','["炎暑半歸天早凉，日陰苦短夜初長。", "風清月白已秋意，海角天涯非故鄉。", "無頼分爲多病叟，有情還作一詩狂。", "溪聲汩汩東西去，南北遊人欲斷腸。"]'),
('3ac40588-e2e0-41e8-8a61-e575b43519cd','和君時十二弟','彭汝礪','宋','宋诗','song-poetry','','[]','漂泊東南天地間，分明身世似乘船。',64,'全唐诗/poet.song.51000.json','["漂泊東南天地間，分明身世似乘船。", "此生去住總未定，所值險夷皆偶然。", "載酒縱隨紅芰飲，移床深近白雲眠。", "知君獨處多幽趣，詩軸今成第幾編。"]'),
('9225be49-d9ac-4a52-bfcb-d7c9ccb2ed22','次皇甫子仁老杜詩韵','彭汝礪','宋','宋诗','song-poetry','','[]','少陵氣忠勇，毫髮見聲詩。',48,'全唐诗/poet.song.51000.json','["少陵氣忠勇，毫髮見聲詩。", "衛稷心丹破，窮途鬢雪垂。", "兵戈靈武道，風雨耒陽時。", "不及明君用，空餘後學悲。"]'),
('8bf04e07-495b-4982-9afe-f538a870ee0b','冬寒圍爐以題爲韵得寒字','彭汝礪','宋','宋诗','song-poetry','','[]','道路冬無雪，山原臘始寒。',48,'全唐诗/poet.song.51000.json','["道路冬無雪，山原臘始寒。", "平林風力疾，落葉雨聲乾。", "冰玉詩腸瘦，江湖酒思寬。", "庭幃即予樂，不必事盃盤。"]'),
('be1229a6-bd82-4d28-90f8-304a012791b6','和濟叔冬字','彭汝礪','宋','宋诗','song-poetry','','[]','雨聲傳到耳，雪意盡窮冬。',48,'全唐诗/poet.song.51000.json','["雨聲傳到耳，雪意盡窮冬。", "氣味閑相愜，形骸病見攻。", "冷呵詩筆凍，寒啜酒醅醲。", "且劇紅爐飲，行聞古寺鐘。"]'),
('22a1c84b-b8b1-467f-9295-910f0cb396a8','和庭佐弟韵','彭汝礪','宋','宋诗','song-poetry','','[]','鴻雁飛雲際，珪璋照座隅。',48,'全唐诗/poet.song.51000.json','["鴻雁飛雲際，珪璋照座隅。", "喜心看欲雪，佳句續圍爐。", "蕭灑開書帙，清狂泥酒壺。", "雲霄非萬里，行看步夷塗。"]'),
('fe5ec58b-6480-403f-80b0-ee456248b96c','呂睦仲赴詔以病不及送作詩與之','彭汝礪','宋','宋诗','song-poetry','','[]','埃塵留病枕，霜雪聽晨征。',48,'全唐诗/poet.song.51000.json','["埃塵留病枕，霜雪聽晨征。", "出谷鶑聲早，飛雲鶴翅輕。", "寒郊亦常日，物色自離情。", "二月春風信，期君萬里程。"]'),
('37e6fc8e-b6a3-4e08-b2fb-072a5dfad2ff','分題得思字韵寄甯文淵','彭汝礪','宋','宋诗','song-poetry','','[]','風雪今之夕，湖山百爾思。',48,'全唐诗/poet.song.51000.json','["風雪今之夕，湖山百爾思。", "欲歌鶑谷意，不忘鶺原詩。", "臘意生梅萼，春容動柳枝。", "塵埃一千里，歸夢自遲遲。"]'),
('766d6f24-3e5e-4036-8580-19d2a0d4afb7','和濟叔小飲韵','彭汝礪','宋','宋诗','song-poetry','','[]','島嶼風迴北，滄溟月上東。',48,'全唐诗/poet.song.51000.json','["島嶼風迴北，滄溟月上東。", "苦吟詩眼碧，小酌病顔紅。", "城近更籌數，天寒斗柄中。", "且安顔巷陋，無泣阮途窮。"]'),
('31942574-7b17-4584-bd84-401904b2575d','和潤之苦吟韵','彭汝礪','宋','宋诗','song-poetry','','[]','諸公敏酬唱，頃刻聽詩成。',48,'全唐诗/poet.song.51000.json','["諸公敏酬唱，頃刻聽詩成。", "夜月留寒影，春花落細英。", "更須洗塵滓，莫使污晶明。", "君看少陵格，篇章句句新。"]'),
('04580783-2799-4e42-bac6-71057e555316','和庭佐觀射','彭汝礪','宋','宋诗','song-poetry','','[]','勇士環雲幟，將軍臂角弓。',48,'全唐诗/poet.song.51000.json','["勇士環雲幟，將軍臂角弓。", "三狐斃林曲，一雁落雲中。", "百步風爭疾，千夫膽喪雄。", "更須洗稂莠，歸凱上邊功。"]'),
('162fd445-26bb-4fa8-90b7-bc85e0e333fe','夜坐','彭汝礪','宋','宋诗','song-poetry','','[]','日夕孤蟾上，天寒萬象低。',48,'全唐诗/poet.song.51000.json','["日夕孤蟾上，天寒萬象低。", "苦吟聞夜漏，端坐聽晨雞。", "大道非無逕，青雲自有梯。", "更須極幽隠，慎勿嘆羈棲。"]'),
('ff87420e-a780-4bcf-b28e-9a682603bf18','和君玉林字韵','彭汝礪','宋','宋诗','song-poetry','','[]','晚日牛羊舍，清風鳥雀林。',48,'全唐诗/poet.song.51000.json','["晚日牛羊舍，清風鳥雀林。", "山蹊頻下上，天色屢晴陰。", "縣令三鄉念，君王萬里心。", "事功非翰墨，酬唱故相禁。"]'),
('0603df68-8f62-4f39-b992-59341ddde5d5','龍泉','彭汝礪','宋','宋诗','song-poetry','','[]','秋風入野凉，吹散菊花芳。',48,'全唐诗/poet.song.51000.json','["秋風入野凉，吹散菊花芳。", "萬里無人處，千枝祇自香。", "風流憶彭澤，時節念重陽。", "物意雖寥寂，能忘酒一觴。"]'),
('fbd561a5-2dc3-498e-9bb8-dc306ca40f03','得老兒到葉縣書寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','野店雞啼處，平安信息來。',48,'全唐诗/poet.song.51000.json','["野店雞啼處，平安信息來。", "摇旌心未穩，披霧眼先開。", "未敢言曾子，猶能學老萊。", "分陰須愛惜，好爲補南陔。"]'),
('e0a11d96-4c44-4482-bf64-8dfcc7bae8e5','夜坐家人乞詩','彭汝礪','宋','宋诗','song-poetry','','[]','憔悴蓬門學，塵埃布褐身。',48,'全唐诗/poet.song.51000.json','["憔悴蓬門學，塵埃布褐身。", "一官偶今日，相顧守吾貧。", "上國恩波重，高門鬢雪新。", "豈無忠孝論，子細遺良人。"]'),
('f24a8fe7-6d60-4bd9-bcf1-5d3e759ce5ad','白彪馳寄君時','彭汝礪','宋','宋诗','song-poetry','','[]','橫踰紫芝路，徑赴白彪期。',48,'全唐诗/poet.song.51000.json','["橫踰紫芝路，徑赴白彪期。", "翼翼馬爰飭，伾伾車載脂。", "山川道云遠，日月來何遲。", "立語言不盡，不言君自知。"]'),
('eca48e65-f0bf-43f3-b5c9-6700ac53e0f1','和君時予未至君時言有羣鵲集檐','彭汝礪','宋','宋诗','song-poetry','','[]','舊重千金諾，元爲五日期。',48,'全唐诗/poet.song.51000.json','["舊重千金諾，元爲五日期。", "水清冰破玉，岩潤石凝脂。", "命駕不嫌遽，舍車空悔遲。", "多慚無道力，有往鵲先知。"]'),
('266c318a-c9a4-400e-968b-5b287f239722','和君時約誼甫先生游龍泉失期','彭汝礪','宋','宋诗','song-poetry','','[]','昨夜天文靜，重雲宿少微。',48,'全唐诗/poet.song.51000.json','["昨夜天文靜，重雲宿少微。", "客遊還不值，人事故多違。", "照月雙泉落，凌風一雁飛。", "山川雖往復，難值夢魂歸。"]'),
('a73e3122-9767-440e-ab20-b46242597c15','吏部閣子前有千葉菊因酌同僚口占一首','彭汝礪','宋','宋诗','song-poetry','','[]','一花幾千葉，千葉一時開。',48,'全唐诗/poet.song.51000.json','["一花幾千葉，千葉一時開。", "曉露紅雲拂，春風舞雪回。", "薄言酌我酒，亦道賞花來。", "自是蘭臺勝，桃源安在哉。"]'),
('ea1e93ff-a034-4044-b2f3-078b7dacdbb8','漁艇','彭汝礪','宋','宋诗','song-poetry','','[]','物物非吾事，飄飄寄此生。',48,'全唐诗/poet.song.51000.json','["物物非吾事，飄飄寄此生。", "江湖萬古樂，簪紱一毫輕。", "醉舞秋風靜，酣歌夜月明。", "滄浪有餘地，應許濯吾纓。"]'),
('96b694ab-f195-48c4-86fb-cdbbd52c4518','馬上見蜀山','彭汝礪','宋','宋诗','song-poetry','','[]','明日催今日，長亭間短亭。',48,'全唐诗/poet.song.51000.json','["明日催今日，長亭間短亭。", "久流淮水遠，喜見蜀山青。", "天地飛飛雁，江湖泛泛萍。", "欲知後夜樂，罇酒上親庭。"]'),
('cfa4f502-5cd9-4dc3-a7b0-f9b4c9742d96','曉步','彭汝礪','宋','宋诗','song-poetry','','[]','峨冠出林藪，策杖濟泥塗。',48,'全唐诗/poet.song.51000.json','["峨冠出林藪，策杖濟泥塗。", "山迥迷三島，溪長念五湖。", "歸雲靜寒谷，落日憩平蕪。", "獨樂無羈束，低徊愧野夫。"]'),
('7fc3c4ee-42d6-475e-b99e-9a6e59fcbd51','道傍松竹','彭汝礪','宋','宋诗','song-poetry','','[]','細細松千葉，紛紛竹萬枝。',48,'全唐诗/poet.song.51000.json','["細細松千葉，紛紛竹萬枝。", "寒聲落幽徑，碎影出疏籬。", "冷逼風霜勁，清舍雨露滋。", "不須稂莠念，自有歲寒姿。"]'),
('09f73092-97e7-4307-af3a-d965845467c9','欲雨','彭汝礪','宋','宋诗','song-poetry','','[]','雨勢將霶霈，風聲自嘯號。',48,'全唐诗/poet.song.51000.json','["雨勢將霶霈，風聲自嘯號。", "柳眉含綠淚，花臉膩香膏。", "厚澤宜蘇物，微寒怯減袍。", "詩成歡不足，終擬醉春醪。"]'),
('499e51c1-848f-43d3-8982-792e00f2d4a5','新晴','彭汝礪','宋','宋诗','song-poetry','','[]','一雨凄凉夜，羣陽發育春。',48,'全唐诗/poet.song.51000.json','["一雨凄凉夜，羣陽發育春。", "風雷驚舊蟄，泥滓倦行人。", "花秀千家囿，波添數尺津。", "新晴何處好，郊外草如茵。"]'),
('8ded586b-ab7b-4d1c-9d3f-ba58b6909d46','贈潘山人','彭汝礪','宋','宋诗','song-poetry','','[]','病臥滄江側，驚逢長者車。',48,'全唐诗/poet.song.51000.json','["病臥滄江側，驚逢長者車。", "亦如齊扁鵲，能起蜀相如。", "惠飲囊中藥，功窺肘後書。", "微吟贈行色，猶勝百車渠。"]'),
('85894790-3120-4ad5-84bd-3c8f615e3519','過揚瀾','彭汝礪','宋','宋诗','song-poetry','','[]','路入揚瀾險，心魂獨惘然。',48,'全唐诗/poet.song.51000.json','["路入揚瀾險，心魂獨惘然。", "秋風浪飛屋，春雨水彌天。", "一葉漁翁艇，千鈞客子船。", "相爭蝸角利，平地看深淵。"]'),
('75dca092-bd13-4789-901c-c86bbaf7657e','曉起','彭汝礪','宋','宋诗','song-poetry','','[]','清霜羣籟息，淡曉一星留。',48,'全唐诗/poet.song.51000.json','["清霜羣籟息，淡曉一星留。", "野竹寒方翠，溪雲夜不收。", "月明山路逕，霜溼布衣裘。", "羈旅令人瘁，衰羸亦自羞。"]'),
('b0b34ab3-1d4b-4b25-8bfe-cfa7e724667c','春風','彭汝礪','宋','宋诗','song-poetry','','[]','三春含造化，一雨灑空虛。',48,'全唐诗/poet.song.51000.json','["三春含造化，一雨灑空虛。", "寒色宵無定，輕陰晝未舒。", "亭臺花色重，道路馬蹄疏。", "燕雀乘風便，應言莫我如。"]'),
('45e3c805-b451-40aa-8bb3-eeb55a2613b4','駑馬','彭汝礪','宋','宋诗','song-poetry','','[]','我馬固非俗，不時今亦駑。',48,'全唐诗/poet.song.51000.json','["我馬固非俗，不時今亦駑。", "晨征盡迂逕，夜食一乾芻。", "憔悴千金骨，遲迴萬里途。", "無人拂衰朽，矯首獨嗟吁。"]'),
('d2d527bf-9737-460c-b222-578848a9ca7e','途中有感','彭汝礪','宋','宋诗','song-poetry','','[]','維檝闐江海，輪蹄溢道途。',48,'全唐诗/poet.song.51000.json','["維檝闐江海，輪蹄溢道途。", "微晴困炎暑，一雨厭泥途。", "天意自虛淡，物情空嘆吁。", "是非今可卜，吾意獨何虞。"]'),
('14ec5d66-b224-4e10-8c0e-699b2e9369d1','去桐江','彭汝礪','宋','宋诗','song-poetry','','[]','去去不遑息，棲棲何所歸。',48,'全唐诗/poet.song.51000.json','["去去不遑息，棲棲何所歸。", "紅塵傷客鬢，白露點征衣。", "風雨晴時少，山川平地稀。", "夢魂留不得，一夜到庭幃。"]'),
('cee00611-d62a-4be4-b299-23a0f6423fed','病題桐江','彭汝礪','宋','宋诗','song-poetry','','[]','嘆息醫工拙，矜嗟舊疾牢。',48,'全唐诗/poet.song.51000.json','["嘆息醫工拙，矜嗟舊疾牢。", "衰容雖凍雀，烈氣尚驚濤。", "羈旅雙塵鬢，塵埃一布袍。", "遠鄉滋味惡，空益夢魂勞。"]'),
('3a3284e3-c8f7-4f9f-9d18-ee8c164ae882','和游龍泉寺','彭汝礪','宋','宋诗','song-poetry','','[]','林邊竹枝子，問法即心王。',48,'全唐诗/poet.song.51000.json','["林邊竹枝子，問法即心王。", "氣挹千山秀，風吹萬室凉。", "靈泉通潤澤，幽鳥恣徊翔。", "雨雪翻天地，看瞻愛有常。"]'),
('d50f051f-bc46-4ce9-b1ca-82363e1aa77c','先赴東流因寄虞蔣諸君  其一','彭汝礪','宋','宋诗','song-poetry','','[]','相愛不能去，欲行還復留。',48,'全唐诗/poet.song.51000.json','["相愛不能去，欲行還復留。", "山川蕩行色，風雨結離愁。", "紅日千山曉，清霜萬木秋。", "回頭望車馬，目斷白蘋洲。"]'),
('c4ea5b47-8e37-464d-a95a-ddfec2260ef9','先赴東流因寄虞蔣諸君  其二','彭汝礪','宋','宋诗','song-poetry','','[]','我行已南北，君跡尚西東。',48,'全唐诗/poet.song.51000.json','["我行已南北，君跡尚西東。", "車馬到雖晚，道途終不同。", "山川新霽雨，天地正秋風。", "有暇詩應作，無忘草野中。"]'),
('dd27db54-7daa-4f86-9ca9-072dd51618d0','途中作','彭汝礪','宋','宋诗','song-poetry','','[]','窮冬尚羈旅，行色太凄凉。',48,'全唐诗/poet.song.51000.json','["窮冬尚羈旅，行色太凄凉。", "白雪園林好，紅塵道路長。", "暮雲寒不散，斜日淡無光。", "夜宿溪山靜，清風滿肺腸。"]'),
('0e6b5356-16d9-4759-847a-da59e4d4a2cf','次虞遜臣江行韵','彭汝礪','宋','宋诗','song-poetry','','[]','步繞林泉側，襟懷一灑然。',48,'全唐诗/poet.song.51000.json','["步繞林泉側，襟懷一灑然。", "酒酲昏易析，詩癖老難痊。", "鬨息無塵地，寒生欲暝天。", "願期明月到，同枕碧溪眠。"]'),
('0e0c83cd-d054-49c1-b35c-cfcb98e20284','次張瑞甫貪飲韵','彭汝礪','宋','宋诗','song-poetry','','[]','霜濃溪水縮，雨過竹風多。',48,'全唐诗/poet.song.51000.json','["霜濃溪水縮，雨過竹風多。", "久病予無頼，微吟子爲歌。", "遠心傾塞雁，窮緒委江波。", "貪飲祇如此，世人誰復過。"]'),
('e93d6065-bb5d-409a-b019-b07b12fc58b3','寄題晏無黨少府','彭汝礪','宋','宋诗','song-poetry','','[]','身逐塵埃際，心迷道路間。',48,'全唐诗/poet.song.51000.json','["身逐塵埃際，心迷道路間。", "無聊長臥病，未老已衰顔。", "竟日千憂結，何時一息閑。", "空勞中夜夢，繞盡夕陽關。"]'),
('38ae4339-23b1-43e3-8499-9e42fc7ee2c9','倒押前韵','彭汝礪','宋','宋诗','song-poetry','','[]','吾生何獨擾，世事欲相關。',48,'全唐诗/poet.song.51000.json','["吾生何獨擾，世事欲相關。", "願去紅塵穴，同分白日閑。", "詩賡幽意緒，酒裛病容顔。", "尚有松筠意，相期霜雪間。"]'),
('5173ddc7-a5f8-455c-b7dd-e5877428f34b','酬熊君惠詩','彭汝礪','宋','宋诗','song-poetry','','[]','扁舟去江海，邂逅得相親。',48,'全唐诗/poet.song.51000.json','["扁舟去江海，邂逅得相親。", "趨向亦非俗，塵埃知有人。", "我心雙古劍，今日獨飄萍。", "空愧詩中意，相期重濟民。"]'),
('b85b9fe1-db5c-4873-846c-6ce2b10ef73a','寄庭佐弟與潤之同作','彭汝礪','宋','宋诗','song-poetry','','[]','狂風朝不定，急雨暮相連。',48,'全唐诗/poet.song.51000.json','["狂風朝不定，急雨暮相連。", "麗澤已春意，濃寒猶臘天。", "紅爐雙酒艇，清夜一詩篇。", "不見東江客，臨風意惘然。"]'),
('ca4acb60-f2fe-4d90-ad21-7d5aba983b78','至雄州寄諸弟并呈諸友  其一','彭汝礪','宋','宋诗','song-poetry','','[]','馬頭今日過中都，到得雄州更有書。',32,'全唐诗/poet.song.51000.json','["馬頭今日過中都，到得雄州更有書。", "道路莫嗔音問少，天寒沙漠雁全疏。"]'),
('f4b17c1d-f289-4286-9c4f-5e7ec83e0bc7','至雄州寄諸弟并呈諸友  其二','彭汝礪','宋','宋诗','song-poetry','','[]','沙陀行盡見南山，過却中京更少寒。',32,'全唐诗/poet.song.51000.json','["沙陀行盡見南山，過却中京更少寒。", "欲寄梅花無處覓，祇將書去報平安。"]'),
('72712278-a263-4aa6-a45b-66a41dc5dc0a','子育見和前韵因寄君宜弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','滎陽知汝已還都，未得陳橋別後書。',32,'全唐诗/poet.song.51000.json','["滎陽知汝已還都，未得陳橋別後書。", "頭鬢不干霜雪事，冬來一似草彫疏。"]'),
('025a6f73-e8a8-43da-95fb-19abe8acd65b','子育見和前韵因寄君宜弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','東風吹雪滿千山，便似江南料峭寒。',32,'全唐诗/poet.song.51000.json','["東風吹雪滿千山，便似江南料峭寒。", "天意人情終是別，漸知風日近長安。"]'),
('b954ed07-86d2-42f2-9a63-6278ddfed551','和國信子育元韵  其一','彭汝礪','宋','宋诗','song-poetry','','[]','雪餘稅馬立孱顔，望盡南垂北際山。',32,'全唐诗/poet.song.51000.json','["雪餘稅馬立孱顔，望盡南垂北際山。", "一段黄雲凝不散，胡人說是瓦橋關。"]'),
('3f1d36c3-7c3d-4dce-a0fa-e87cff387650','和國信子育元韵  其二','彭汝礪','宋','宋诗','song-poetry','','[]','曉起南山暮北山，夜深歸夢祇山間。',32,'全唐诗/poet.song.51000.json','["曉起南山暮北山，夜深歸夢祇山間。", "山中亦有流泉好，不許行人洗病顔。"]'),
('4aeaa68e-ce46-49bd-8d9a-c68ee2c0e274','和國信子育元韵  其三','彭汝礪','宋','宋诗','song-poetry','','[]','聞道朝正使入關，殷勤試托寄書還。',32,'全唐诗/poet.song.51000.json','["聞道朝正使入關，殷勤試托寄書還。", "逢人若問今何許，已過金鈎第一山。"]'),
('fe6da68f-04d6-435a-a668-61911cff361c','和國信子育元韵  其四','彭汝礪','宋','宋诗','song-poetry','','[]','山谷冥冥風怒號，故吹霜雪上綈袍。',32,'全唐诗/poet.song.51000.json','["山谷冥冥風怒號，故吹霜雪上綈袍。", "風波末路嗟奚拙，露電浮生笑自勞。"]'),
('f347db7a-48a1-4619-843b-e2a1371def1f','和國信子育元韵  其五','彭汝礪','宋','宋诗','song-poetry','','[]','傍火時尋柏子燒，青燈笑語夜寥寥。',32,'全唐诗/poet.song.51000.json','["傍火時尋柏子燒，青燈笑語夜寥寥。", "殊方更喜人情好，長日不知山路遙。"]'),
('b4375c06-786e-48ac-9d0d-e124c3c06faa','再和子育  其一','彭汝礪','宋','宋诗','song-poetry','','[]','易水涿山無苦寒，燕南本是舊家山。',32,'全唐诗/poet.song.51000.json','["易水涿山無苦寒，燕南本是舊家山。", "山頭更覺堯雲近，玄鳥徘徊望漢關。"]'),
('9b463543-a3d0-45f6-8897-87455a8dd779','再和子育  其二','彭汝礪','宋','宋诗','song-poetry','','[]','將軍誓願斬樓蘭，涕淚橫流盃酒間。',32,'全唐诗/poet.song.51000.json','["將軍誓願斬樓蘭，涕淚橫流盃酒間。", "紫氣劍埋終未試，黄金印大亦何顔。"]'),
('2562b2b7-ac0f-4359-b623-ded4242d414b','再和子育  其三','彭汝礪','宋','宋诗','song-poetry','','[]','朔風白晝不勝寒，清曉馬行霜雪間。',32,'全唐诗/poet.song.51000.json','["朔風白晝不勝寒，清曉馬行霜雪間。", "縱目還經望雲嶺，傷心不見採芝山。"]'),
('51214982-7d30-4b9b-b03f-549fc3f0fba1','再和子育  其四','彭汝礪','宋','宋诗','song-poetry','','[]','手拈弓箭膝橫刀，著盡君王賜戰袍。',32,'全唐诗/poet.song.51000.json','["手拈弓箭膝橫刀，著盡君王賜戰袍。", "語及靈州心欲碎，使軺今日敢言勞。"]'),
('cbe99963-33a3-4466-912c-309f12d93379','再和子育  其五','彭汝礪','宋','宋诗','song-poetry','','[]','氣血畏寒身畏勞，養生曾去問參寥。',32,'全唐诗/poet.song.51000.json','["氣血畏寒身畏勞，養生曾去問參寥。", "我今與子俱錯計，霜雪正嚴山正遙。"]'),
('7fd76885-9e8c-49b9-90ad-f5097bc20350','過右北平','彭汝礪','宋','宋诗','song-poetry','','[]','太平天子不言兵，擁節來經右北平。',32,'全唐诗/poet.song.51000.json','["太平天子不言兵，擁節來經右北平。", "論將無人思李廣，笑談樽俎倚儒生。"]'),
('dc6a9add-3208-4ab3-8d97-3f0b1fe75941','望雲嶺','彭汝礪','宋','宋诗','song-poetry','','[]','人臣思國似思親，忠孝從來不可分。',32,'全唐诗/poet.song.51000.json','["人臣思國似思親，忠孝從來不可分。", "更與諸君聊秣馬，儘登高處望堯雲。"]'),
('00c637d2-7cac-428e-903d-e4d06467eedd','過墨斗嶺聞鳥聲似子規而其形非是','彭汝礪','宋','宋诗','song-poetry','','[]','有鳥羽毛非子規，向人如道不如歸。',32,'全唐诗/poet.song.51000.json','["有鳥羽毛非子規，向人如道不如歸。", "使軺不用君多勸，未到歸心已似飛。"]'),
('1b6b8527-7002-4152-8ae2-5ccd40fef488','湖湘路中見梅花寄子開  其一','彭汝礪','宋','宋诗','song-poetry','','[]','追誦寒梅佳句新，東郊平昔與迎春。',32,'全唐诗/poet.song.51000.json','["追誦寒梅佳句新，東郊平昔與迎春。", "今時獨賦雲岩路，目斷蓬萊高閣人。"]'),
('c5996ed1-7bde-411c-b79b-469bf1808afa','湖湘路中見梅花寄子開  其二','彭汝礪','宋','宋诗','song-poetry','','[]','萬木低徊冰雪辰，寄聲憑爾急催春。',32,'全唐诗/poet.song.51000.json','["萬木低徊冰雪辰，寄聲憑爾急催春。", "即看苑囿芳菲遍，還見池臺歌舞人。"]'),
('daa0e612-1ab0-4dc1-957f-029ab1fad5e3','湖湘路中見梅花寄子開  其三','彭汝礪','宋','宋诗','song-poetry','','[]','不問蕭條風雨辰，一花自與物爲春。',32,'全唐诗/poet.song.51000.json','["不問蕭條風雨辰，一花自與物爲春。", "如雲不比東門女，若雪豈非姑射人。"]'),
('1f6ea32b-e4ec-4335-b2cb-98fa96fd3840','湖湘路中見梅花寄子開  其四','彭汝礪','宋','宋诗','song-poetry','','[]','滴葉開花妙入神，酥盤憶看北堂春。',32,'全唐诗/poet.song.51000.json','["滴葉開花妙入神，酥盤憶看北堂春。", "瀟湘此日堪腸斷，隨處幽香著莫人。"]'),
('bac17141-2033-4e12-bbf4-73c2614397ae','湖湘路中見梅花寄子開  其五','彭汝礪','宋','宋诗','song-poetry','','[]','折得寒梅自水濱，恰如去歲在宜春。',32,'全唐诗/poet.song.51000.json','["折得寒梅自水濱，恰如去歲在宜春。", "瀟湘不見江南客，祇有花枝似故人。"]'),
('9214daf1-feb5-4127-ba43-bac2fca0ee42','湖湘路中見梅花寄子開  其六','彭汝礪','宋','宋诗','song-poetry','','[]','眼看梅花愁更新，到頭不似故園春。',32,'全唐诗/poet.song.51000.json','["眼看梅花愁更新，到頭不似故園春。", "風前一片花飛落，節物匆匆更感人。"]'),
('0e976441-5c97-4aa1-8245-0b2794c39657','湖湘路中見梅花寄子開  其七','彭汝礪','宋','宋诗','song-poetry','','[]','沙村飛雪白於雲，野岸寒梅已放春。',32,'全唐诗/poet.song.51000.json','["沙村飛雪白於雲，野岸寒梅已放春。", "詩興鄉愁俱不奈，江邊愁殺杜陵人。"]'),
('ba04c912-a9e5-44d4-8365-33540b74bedf','和正仲提舉  其一','彭汝礪','宋','宋诗','song-poetry','','[]','兀坐形忘入眇微，泊然無事亦無思。',32,'全唐诗/poet.song.51000.json','["兀坐形忘入眇微，泊然無事亦無思。", "箇中若得真消息，先報維摩長者知。"]'),
('003f22ab-4526-4a60-895c-4379bc13edfb','和正仲提舉  其二','彭汝礪','宋','宋诗','song-poetry','','[]','一絲急急一絲遲，觸物蒼茫若有思。',32,'全唐诗/poet.song.51000.json','["一絲急急一絲遲，觸物蒼茫若有思。", "流水高山新作操，十年留待伯牙知。"]'),
('32a247d4-0f30-4bb5-9f06-2ea784686874','和正仲提舉  其三','彭汝礪','宋','宋诗','song-poetry','','[]','萬事縱橫似亂絲，道人莫道便無思。',32,'全唐诗/poet.song.51000.json','["萬事縱橫似亂絲，道人莫道便無思。", "五湖風起浪如屋，祇問鸕鷀知不知。"]'),
('ba33d13b-4bb7-4906-b751-ad7142551f24','和正仲提舉  其四','彭汝礪','宋','宋诗','song-poetry','','[]','峴首人亡無限悲，高陽客散有餘思。',32,'全唐诗/poet.song.51000.json','["峴首人亡無限悲，高陽客散有餘思。", "急來相就一游樂，明日東西渾未知。"]'),
