('1c45cd5e-6a5f-493e-a735-083b7ea9eb2a','雨寄君時弟  其一','彭汝礪','宋','宋诗','song-poetry','','[]','朝霧蒼茫暮雨低，恰如梅子欲黄時。',32,'全唐诗/poet.song.51000.json','["朝霧蒼茫暮雨低，恰如梅子欲黄時。", "三分半是行人泪，莫怪行人鬢已絲。"]'),
('8fd7d516-7d55-4d5d-9165-1f0e21a881cf','雨寄君時弟  其二','彭汝礪','宋','宋诗','song-poetry','','[]','燈前微雨惜黄昏，想費慈闈夜倚門。',32,'全唐诗/poet.song.51000.json','["燈前微雨惜黄昏，想費慈闈夜倚門。", "知汝悅親能有道，不應惟種北堂萱。"]'),
('e80c424e-68c8-4332-a975-1a9276860cb0','李廣','彭汝礪','宋','宋诗','song-poetry','','[]','非薄今人愛古人，今人祇說李將軍。',32,'全唐诗/poet.song.51000.json','["非薄今人愛古人，今人祇說李將軍。", "英雄豈遂無如廣，嘆息寥寥久不聞。"]'),
('a94d50ae-b1a4-417d-bf6d-aa35a71de905','長垣路中','彭汝礪','宋','宋诗','song-poetry','','[]','鳳鳥不鳴今幾時，太平今日合來儀。',32,'全唐诗/poet.song.51000.json','["鳳鳥不鳴今幾時，太平今日合來儀。", "湖塘羽族多如雪，恐是當年養鶴池。"]'),
('d315bf10-8b04-4dff-8a06-6533560a8e6c','歸次雄州','彭汝礪','宋','宋诗','song-poetry','','[]','雁奴到日人初別，燕子來時我亦還。',32,'全唐诗/poet.song.51000.json','["雁奴到日人初別，燕子來時我亦還。", "馳馬直登山絕頂，爭圖先見瓦橋關。"]'),
('d66458f8-2726-4563-bc93-00fc1d36395d','顔子  其一','彭汝礪','宋','宋诗','song-poetry','','[]','孔門弟子數三千，高弟惟稱七十賢。',32,'全唐诗/poet.song.51000.json','["孔門弟子數三千，高弟惟稱七十賢。", "用舍行藏誰與比，當時獨許一顔淵。"]'),
('823356b2-1130-4b15-9ce6-e024be8b9a19','顔子  其二','彭汝礪','宋','宋诗','song-poetry','','[]','高才獨立聖人門，千載巍巍道愈尊。',32,'全唐诗/poet.song.51000.json','["高才獨立聖人門，千載巍巍道愈尊。", "試讀塵編問遺事，終身不及百餘言。"]'),
('a064d2b8-c018-46df-883b-22a8f09eaeac','和履中學士上元有作  其一','彭汝礪','宋','宋诗','song-poetry','','[]','樓頭星斗爛文章，錦繡中焚百和香。',32,'全唐诗/poet.song.51000.json','["樓頭星斗爛文章，錦繡中焚百和香。", "月似中秋燈似晝，總將明德奉吾皇。"]'),
('9ecce27a-9259-4368-85ff-ff0765ba1042','和履中學士上元有作  其二','彭汝礪','宋','宋诗','song-poetry','','[]','燈火能催萬物春，花間蜂蝶已繽紛。',32,'全唐诗/poet.song.51000.json','["燈火能催萬物春，花間蜂蝶已繽紛。", "太平會與民同樂，總道吾君是聖君。"]'),
