('16e67ee3-e811-41ac-8887-0ea27f4b92b8','移舟泊通濟亭','彭汝礪','宋','宋诗','song-poetry','','[]','隔溪楊柳綠毿毿，晚色遲遲認夕嵐。',32,'全唐诗/poet.song.52000.json','["隔溪楊柳綠毿毿，晚色遲遲認夕嵐。", "細細亂山渾不見，漁燈數點照沙南。"]'),
('96bedd04-ab13-4c98-ac8c-53bcd68e9def','張君父歸家有感','彭汝礪','宋','宋诗','song-poetry','','[]','河可以竭山可徙，我翁不歸行不已。',40,'全唐诗/poet.song.52000.json','["河可以竭山可徙，我翁不歸行不已。", "三往三復翁歸止，翁行尚壯今老矣。", "兒昔未生今壯齒。"]'),
('44e83b49-3a6b-4bab-b1d2-2482198f1f1b','簡王大丞','彭汝礪','宋','宋诗','song-poetry','','[]','我看繁劇頻搔首，君賦才名亦異常。',64,'全唐诗/poet.song.52000.json','["我看繁劇頻搔首，君賦才名亦異常。", "尚有閑襟尋水石，更當佳句夢池塘。", "松苗自合分高下，鳬鶴天教有短長。", "徐上青雲猶未晚，可無音問及滄浪。"]'),
('b2df5339-837a-4bcb-b137-aad7945f3491','巢燕初至','彭汝礪','宋','宋诗','song-poetry','','[]','一雙掠水燕來初，萬點飛花社雨餘。',32,'全唐诗/poet.song.52000.json','["一雙掠水燕來初，萬點飛花社雨餘。", "辛苦成來君莫破，從來吾亦愛吾廬。"]'),
('b2c1f4f7-dbe4-4b25-8692-ae155204cb10','予十一月甲申以使來武岡坐茅茨之室逼閭閻之陋無故人往來之樂懷羈旅不足之情于是有游古山之寺在縣西十五里而山水俊拔深秀亦有可愛者因留置酒抵暮還驛而作是詩','彭汝礪','宋','宋诗','song-poetry','','[]','淡日沙村晚，霜晴溪路遙。',288,'全唐诗/poet.song.52000.json','["淡日沙村晚，霜晴溪路遙。", "蠻人瞻虎節，田父看星軺。", "使指勤咨問，君恩費養調。", "畏途諳跋涉，遺策問蒭蕘。", "臘近雲長暝，春遲雪未消。", "遠空低幕帟，疊嶂露瓊瑶。", "板屋誰家舍，茅簷何處橋。", "梅香浮遠水，藤古上重霄。", "細草眠黄犢，巔崖落皁雕。", "兒童晴出牧，婦女晚歸樵。", "樵髻騎吹笛，斑衣行踏謠。", "封疆連五嶺，習俗带三苗。", "狐鼠藏溪老，豺狼脫洞驕。", "今當蒙潤澤，久已靜氛妖。", "歌舞隨鄉地，耕桑托聖朝。", "威儀欣用夏，姓氏恥稱猺。", "僧至不千里，寺名非一朝。", "小亭浮草莽，高閣出苕蕘。", "泉細能沾潤，峰危欲動摇。", "會觀禪味足，還見講花飄。", "茶汎波無跡，香深篆未消。", "遠游貪物象，久客厭塵囂。", "子美詩千首，淵明醉一瓢。", "倘來淹白晝，輕去恨連宵。"]'),
('73e4065d-7dba-46f2-922b-0002dddab7db','人日','彭汝礪','宋','宋诗','song-poetry','','[]','道衡人日獨牽愁，南北胡爲一處囚。',64,'全唐诗/poet.song.52000.json','["道衡人日獨牽愁，南北胡爲一處囚。", "學士詩成應屬和，壽陽梅落殆神謀。", "醉思侍宴登丹殿，寒想開箱睹黑裘。", "佳句繽紛飛白雪，雪天宜飲亟來休。"]'),
('4225498e-61c8-486d-b023-914132cd4e94','江花四首  其一','彭汝礪','宋','宋诗','song-poetry','','[]','江水挼藍綠，江花潑火紅。',24,'全唐诗/poet.song.52000.json','["江水挼藍綠，江花潑火紅。", "夕陽幽鳥下，渾似畫屏中。"]'),
('ca976c98-16aa-4145-ab38-bda256e39e6d','江花四首  其二','彭汝礪','宋','宋诗','song-poetry','','[]','鷗鳥來何事，漁舟到亦迷。',24,'全唐诗/poet.song.52000.json','["鷗鳥來何事，漁舟到亦迷。", "落花流更遠，疑是武陵溪。"]'),
('30995cbb-cefe-4375-8107-7894733a4e8d','江花四首  其三','彭汝礪','宋','宋诗','song-poetry','','[]','水近花逾碧，花臨水更紅。',24,'全唐诗/poet.song.52000.json','["水近花逾碧，花臨水更紅。", "鷗飛錦城外，人立畫屏中。"]'),
('8c6589c8-031e-4802-842f-ece2317c5258','江花四首  其四','彭汝礪','宋','宋诗','song-poetry','','[]','花麗水疑染，水清花欲燃。',24,'全唐诗/poet.song.52000.json','["花麗水疑染，水清花欲燃。", "滄浪無限意，好在釣漁船。"]'),
('6803d9d5-5d2f-4ed6-9e46-3938592968ef','寄君時一章章四句二章章三句二章章五句  其一','彭汝礪','宋','宋诗','song-poetry','','[]','我治斯何，曰治吾身。',20,'全唐诗/poet.song.52000.json','["我治斯何，曰治吾身。", "我事斯何，曰事吾親。"]'),
('288ff2fb-5fe5-400e-bd9b-0a38bb2a5331','寄君時一章章四句二章章三句二章章五句  其二','彭汝礪','宋','宋诗','song-poetry','','[]','我學未信，乃先從仕，孰云乎自治。',16,'全唐诗/poet.song.52000.json','["我學未信，乃先從仕，孰云乎自治。"]'),
('b7d1275f-fa66-4536-b598-85696fd7de05','寄君時一章章四句二章章三句二章章五句  其三','彭汝礪','宋','宋诗','song-poetry','','[]','我親載老，不知乎養志，孰云乎善事。',17,'全唐诗/poet.song.52000.json','["我親載老，不知乎養志，孰云乎善事。"]'),
('16917a42-7bb8-4a24-b694-8d2def73e126','寄君時一章章四句二章章三句二章章五句  其四','彭汝礪','宋','宋诗','song-poetry','','[]','嗟嗟予季，言以訊予。',26,'全唐诗/poet.song.52000.json','["嗟嗟予季，言以訊予。", "有詩有書，是足與居。", "叔兮其歸與。"]'),
('5d6bc03c-256b-4e7f-95a2-783ed3e9b3df','寄君時一章章四句二章章三句二章章五句  其五','彭汝礪','宋','宋诗','song-poetry','','[]','嗟嗟予季，歌以啟予。',26,'全唐诗/poet.song.52000.json','["嗟嗟予季，歌以啟予。", "有田有廬，亦可與娛。", "叔兮其歸與。"]'),
('e1929935-9dd9-45a0-a890-7a198d85499e','戲招史秘校','彭汝礪','宋','宋诗','song-poetry','','[]','畫橈隠隠水中間，紅粉相瞻幾淚潸。',64,'全唐诗/poet.song.52000.json','["畫橈隠隠水中間，紅粉相瞻幾淚潸。", "行客自言歸意樂，故人終惜別情難。", "羞慚俗吏浮生拙，歎息神仙一夢閑。", "漫拾酒杯留客住，春風抵死笑人慳。"]'),
('81e40f4a-0574-4829-8eab-5e1d139bfb9e','和濟叔春日','彭汝礪','宋','宋诗','song-poetry','','[]','青衫日日逐埃塵，風雨今朝重惜春。',64,'全唐诗/poet.song.52000.json','["青衫日日逐埃塵，風雨今朝重惜春。", "幽鳥數聲還近節，落花萬片正愁人。", "十分潤澤生東畝，一丈波濤長舊津。", "欲踏泥塗上城角，紛紛草色細如茵。"]'),
('adb33f50-b717-427c-8845-08f67ce55258','偶與誠之小飲翌日以詩謝之','彭汝礪','宋','宋诗','song-poetry','','[]','相對春風共酒樽，盤蔬取次得清歡。',64,'全唐诗/poet.song.52000.json','["相對春風共酒樽，盤蔬取次得清歡。", "風吹一鶴歸天上，雪壓孤松見歲寒。", "論極不知空肺腑，交成應許綴金蘭。", "明時更聽王陽仕，洗手思彈貢禹冠。"]'),
('fbfe021e-2b04-41c7-9ccd-8dd4937b388c','送致政大夫伯常自洛抵襄歸郢中舊居續賦詩拜送','彭汝礪','宋','宋诗','song-poetry','','[]','投𣀅全家住白雲，地幽雞犬亦無塵。',64,'全唐诗/poet.song.52000.json','["投𣀅全家住白雲，地幽雞犬亦無塵。", "新成元結垂柏翠，舊有淵明漉酒巾。", "漢上更須呼水鏡，郢中疑復繼陽春。", "歸帆見說如雲去，夢斷江湖一釣綸。"]'),
('19c71320-3dcd-44cb-927d-06d071e2ae6d','依韵和毅夫新栽梅花','陸佃','宋','宋诗','song-poetry','','[]','誰賦梅花詩，擬繼三百五。',144,'全唐诗/poet.song.52000.json','["誰賦梅花詩，擬繼三百五。", "昔聞林居士，幽棲賁巖塢。", "瓊章雖在人，玉樹已埋土。", "湖山今寂寥，五雲謾無雨。", "夫君擅文章，頗以詩自許。", "芬芳春草生，光芒夜珠吐。", "人間再生島，名在詩書圃。", "錦囊貯西施，佳麗生百娬。", "翱翔道家山，文采動人主。", "陽春定能和，白華應可補。", "後生誰敢當，柏直口尚乳。", "老夫幸未疲，腰劍猶能舞。"]'),
('03855a10-9b64-488a-8eb6-dc98bdcb6857','贈王君儀','陸佃','宋','宋诗','song-poetry','','[]','嘗思孔子昔在世，門生弟子三千人。',384,'全唐诗/poet.song.52000.json','["嘗思孔子昔在世，門生弟子三千人。", "大哉卷舒聖人道，弦歌講誦鄒魯濱。", "立身非以利欲誘，至誠惟學義與仁。", "雍容德藝愈磨厲，烜赫光輝彌日新。", "追塵力行慕汲汲，忘疲善誘思循循。", "外榮豈就卿相位，內樂惟知探道真。", "所以萬世作師法，望之仰之如北辰。", "吾嘗苦愛孟子語，淵源事業醇乎醇。", "得君達欲善天下，陋巷窮惟周一身。", "當時舉世謂迂闊，進退何妨吾屈伸。", "紛紛流俗何足託，以道優游能自遵。", "瞥然顧彼萬鍾祿，有如聚散空中雲。", "乃知君子所爲學，志將憂道不憂貧。", "君儀建德一儒士，篤學滄溟陶粹純。", "年强有志闢邪說，氣壯力苦鋤荆榛。", "放出森森梓杞材，秀枝爛漫敷青春。", "讀書侵暮即然燭，爲文夜坐常達晨。", "誰憫顔瓢啖藜藿，自憐范甑生埃塵。", "每云外物未嘗恤，披卷動能經累旬。", "有時揮筆瀉霖雨，但聞霹靂飛車輪。", "雲開霧散却晴霽，清風淅淅無纖塵。", "佳花美木競妍秀，高山遠岫皆嶙峋。", "有時高談傾耳聽，又如天馬超崑崙。", "回顧駑駘百千輩，疲筋竭力安可羣。"]'),
('2bef92dd-561e-44d7-829c-aa2027239c74','依韵和孫勉教授','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','汝陰先生學雖興，官職冷靜真如冰。',352,'全唐诗/poet.song.52000.json','["汝陰先生學雖興，官職冷靜真如冰。", "門前鳥雀可羅網，甑中埃墨隨炊蒸。", "收拾人才妙長養，落筆雖誤猶成蠅。", "至于敗羣亦不受，畫脂徒費知難凝。", "從來說詳富學海，發揮春秋破晻曖。", "仲舒玉杯足瑕纇，中散珠船不光彩。", "著書固知非一日，作詩又欲重千載。", "公卿爭迎爲上客，信知淮楚文章伯。", "應許曹參避正堂，未甘賈誼虛前席。", "男兒富貴固有時，如何宦達微愆期。", "衮衣繡裳畢竟在，祇是即今髭鬢改。", "平生耿介性不容，凜凜勁節凌秋風。", "金華中丞最稱賞，惜也未老先龍鍾。", "去人闔棺命云促，浮生瞬息風中燭。", "華萼飄零不得歸，涕淚數行悲手足。", "顧予未放雪滿顛，乞得清潁如升仙。", "喜聞故人在學校，宛若見面初開牋。", "揚州騎鶴未足羨，便欲共醉花中間。", "西湖風景事事好，不似吳越惟無山。", "海棠方恨我來遲，君欲歸去將何之。", "期向聖時同盡瘁，况復交情淡如水。", "他年若和傅說羹，免使鹽梅鼎顛趾。"]'),
('0eb36189-ade9-4814-81fe-f9e6513c453b','依韵和李知剛黄安見示','陸佃','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','蔣山鱗鬣蒼嵯峨，參伐可捫斗可摩。',384,'全唐诗/poet.song.52000.json','["蔣山鱗鬣蒼嵯峨，參伐可捫斗可摩。", "建康開府占形勝，千檣萬舳來江艖。", "憶昨司空駐千騎，與人傾蓋腸無他。", "有時偃蹇枕書臥，忽地起走仍吟哦。", "諸生橫經飽餘論，宛若茂草生陵阿。", "發揮形聲解奇字，豈但晚學池中鵝。", "余初聞風裹糧走，願就秦扁醫沈疴。", "登堂一見便稱許，暴之秋陽濯江沱。", "夜深歸來學舍冷，鼓吹有蛙更聞鼉。", "曾參捉襟肘屢見，回也簞食傾瓢蠡。", "誰云寒儒偶遭遇，馳道馬疾摇鳴珂。", "因緣乞郡得金印，關吏雖識難誰何。", "邇來二紀世已換，仙棋一局真爛柯。", "孔林父子久同葬，謝安墩在空坡陀。", "顧瞻思賢有儀象，挂壁未去聊隨梭。", "中年觸緒易感慨，頼有二子相經過。", "隴西家兒信奇偉，美玉在巖珠在波。", "慚非冰清託之女，亭亭松柏垂蔦蘿。", "黄生初來似蠶蠋，被絲纏裹今成蛾。", "磨礱爪距擅場屋，擬與羣俊爭殊科。", "惟黄與李豈易得，一二自抵三千多。", "回思爭雄六戰國，競致賓客尋干戈。", "黄金築臺禮郭隗，玉盤進手延荆軻。", "雞鳴狗盜何足數，雖欲定霸終蹉跎。"]'),
('037f1d6f-c165-45e4-a27a-c31d3e7caa36','登塔','陸佃','宋','宋诗','song-poetry','','[]','題寫看前輩，躋攀接後塵。',48,'全唐诗/poet.song.52000.json','["題寫看前輩，躋攀接後塵。", "日邊窺兩觀，雲下念雙親。", "宮線徐添晝，林花頓減春。", "夕陽猶獨立，萬慮入經綸。"]'),
('f649f014-00c7-4644-a5ed-104f7678de03','依韵和彭器資直講','陸佃','宋','宋诗','song-poetry','','[]','歲久親談麈，春深集試闈。',48,'全唐诗/poet.song.52000.json','["歲久親談麈，春深集試闈。", "才名非畫餠，科等是傳衣。", "鶑稍遷喬出，鴉應反哺飛。", "羨君親膝近，昨夜夢先歸。"]'),
('1dab9b8b-031b-4568-b6da-8e7aa3be93d8','呈張邃明舍人','陸佃','宋','宋诗','song-poetry','','[]','世掌絲綸美，聲名壯紫微。',48,'全唐诗/poet.song.52000.json','["世掌絲綸美，聲名壯紫微。", "賜茶天上坐，退食日邊歸。", "簡在除書密，時清諫疏稀。", "佇公參鼎席，寰海望餘輝。"]'),
('7a50bbd8-f497-4a80-932c-adc1acf88d2c','思巖老呈彭器資','陸佃','宋','宋诗','song-poetry','','[]','春遠下樓遲，城高背落暉。',48,'全唐诗/poet.song.52000.json','["春遠下樓遲，城高背落暉。", "鶺鴒經歲別，鴻雁幾時歸。", "柳闊行人盡，花殘驛使稀。", "濠州在雲下，深欲伴歸飛。"]');
